-- Poems batch 42
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6bf2a0a2-2758-4a5c-ae0f-90984d986977','讀友人詩','杜荀鶴','唐','唐诗','tang','','[]','君詩通大雅，吟覺古風生。',48,'全唐诗/poet.tang.38000.json','["君詩通大雅，吟覺古風生。", "外却浮華景，中含教化情。", "名應高日月，道可潤公卿。", "莫以孤寒恥，孤寒達更榮。"]'),
('6be081e2-4953-4c5b-9c8e-5bea90695012','登山寺','杜荀鶴','唐','唐诗','tang','','[]','山半一山寺，野人秋日登。',48,'全唐诗/poet.tang.38000.json','["山半一山寺，野人秋日登。", "就中偏愛石，獨上最高層。", "有果猿攀樹，無齋鴿看僧。", "儒門自多事，來此復何能。"]'),
('6a2d317c-6042-4fec-bdcd-7251042925b7','辭九江李郎中入關','杜荀鶴','唐','唐诗','tang','','[]','帝里無相識，何門跡可親。',48,'全唐诗/poet.tang.38000.json','["帝里無相識，何門跡可親。", "願開言重口，薦與分深人。", "卷許新詩出，家憐舊業貧。", "今從九江去，應免更迷津。"]'),
('9d390068-5fc7-45f6-a101-3ad9467b03c5','江南逢李先輩','杜荀鶴','唐','唐诗','tang','','[]','李杜復李杜，彼時逢此時。',48,'全唐诗/poet.tang.38000.json','["李杜復李杜，彼時逢此時。", "干戈侵帝里，流落向天涯。", "歲月消於酒，平生斷在詩。", "懷才不得志，祗恐滿頭絲。"]'),
('84f8b868-9279-4aef-8027-e4359e5622f4','秋日寄吟友','杜荀鶴','唐','唐诗','tang','','[]','閑坐細思量，唯吟不可忘。',48,'全唐诗/poet.tang.38000.json','["閑坐細思量，唯吟不可忘。", "食無三畝地，衣絕一株桑。", "蟬樹生寒色，漁潭落曉光。", "青雲舊知己，未許釣滄浪。"]'),
('125644ed-3dea-42c7-8713-1732c4598734','江上與從弟話別','杜荀鶴','唐','唐诗','tang','','[]','相逢盡說歸，早晚遂歸期。',48,'全唐诗/poet.tang.38000.json','["相逢盡說歸，早晚遂歸期。", "流水多通處，孤舟少住時。", "干人不得已，非我欲爲之。", "及此終無媿，其如道在茲。"]'),
('fa62401e-eca6-464c-b807-cbd7567cabe0','送友人遊南海','杜荀鶴','唐','唐诗','tang','','[]','南海南邊路，君遊祗爲貧。',48,'全唐诗/poet.tang.38000.json','["南海南邊路，君遊祗爲貧。", "山川多少地，郡邑幾何人。", "花鳥名皆別，寒暄氣不均。", "相期早晚見，莫待瘴侵身。"]'),
('9eb94fe9-8c0d-42d1-a4e0-ff86659c3c37','贈聶尊師','杜荀鶴','唐','唐诗','tang','','[]','詩道將仙分，求之不可求。',48,'全唐诗/poet.tang.38000.json','["詩道將仙分，求之不可求。", "非關從小學，應是數生修。", "蟾桂雲梯折，鰲山鶴駕遊。", "他年兩成事，堪喜是鄰州。"]'),
('acaf168a-cf37-45d7-a44d-b76893a3182f','旅感','杜荀鶴','唐','唐诗','tang','','[]','白髮根叢出，鑷頻愁不開。',48,'全唐诗/poet.tang.38000.json','["白髮根叢出，鑷頻愁不開。", "自憐空老去，誰信苦吟來。", "客路東西闊，家山早晚回。", "翻思釣魚處，一雨一層苔。"]'),
('b8a4ac3e-246d-4405-a3da-700bd8d75912','寄益陽武灌明府','杜荀鶴','唐','唐诗','tang','','[]','縣稱詩人理，無嫌日寂寥。',48,'全唐诗/poet.tang.38000.json','["縣稱詩人理，無嫌日寂寥。", "溪山入城郭，戶口半漁樵。", "月滿彈琴夜，花香漉酒朝。", "相思不相見，煙水路迢迢。"]'),
('0d9d95bf-fdcc-49ae-9332-ec0aa00d18ef','湘中秋日呈所知','杜荀鶴','唐','唐诗','tang','','[]','四海無寸土，一生惟苦吟。',48,'全唐诗/poet.tang.38000.json','["四海無寸土，一生惟苦吟。", "虛垂異鄉淚，不滴別人心。", "雨色凋湘樹，灘聲下塞禽。", "求歸歸未得，不是擲光陰。"]'),
('f66da26c-2005-4b50-9046-f47bd0f19254','苦吟','杜荀鶴','唐','唐诗','tang','','[]','世間何事好，最好莫過詩。',48,'全唐诗/poet.tang.38000.json','["世間何事好，最好莫過詩。", "一句我自得，四方人已知。", "生應無輟日，死是不吟時。", "始擬歸山去，林泉道在茲。"]'),
('e0035baa-de78-49c8-87c9-536d079d3b14','閩中別所知','杜荀鶴','唐','唐诗','tang','','[]','觸目生歸思，那堪路七千。',48,'全唐诗/poet.tang.38000.json','["觸目生歸思，那堪路七千。", "臘中離此地，馬上見明年。", "郡邑溪山巧，寒暄日月偏。", "自疑雙鬢雪，不似到南天。"]'),
('8bed77bb-252a-4347-8551-ff8325807709','塞上傷戰士','杜荀鶴','唐','唐诗','tang','','[]','戰士說辛勤，書生不忍聞。',48,'全唐诗/poet.tang.38000.json','["戰士說辛勤，書生不忍聞。", "三邊遠天子，一命信將軍。", "野火燒人骨，陰風捲陣雲。", "其如禁城裏，何以重要勳。"]'),
('f7c68962-9649-433b-9d64-01d78e024a07','春日訪獨孤處士','杜荀鶴','唐','唐诗','tang','','[]','地僻春來靜，深宜長者居。',48,'全唐诗/poet.tang.38000.json','["地僻春來靜，深宜長者居。", "好花都待晚，修竹不妨疎。", "鴈入湘江食，人侵曉色鋤。", "似君無學處，頭白道如初。"]'),
('cebe6dbc-5e11-4c51-9b32-1f6d6171eed2','哭友人','杜荀鶴','唐','唐诗','tang','','[]','病向名場得，終爲善誤身。',48,'全唐诗/poet.tang.38000.json','["病向名場得，終爲善誤身。", "無兒承後嗣，有女托何人。", "葬禮難求備，交情好者貧。", "惟餘舊文集，一覽一沾巾。"]'),
('7bea0575-51aa-4266-a425-90732518949a','新栽竹','杜荀鶴','唐','唐诗','tang','','[]','斸破蒼苔色，因栽十數莖。',48,'全唐诗/poet.tang.38000.json','["斸破蒼苔色，因栽十數莖。", "窗風從此冷，詩思當時清。", "酒入杯中影，棊添局上聲。", "不同桃與李，瀟灑伴書生。"]'),
('bf0e4552-5b53-44ae-bbf9-0afdd38a8a54','送吳蛻下第入蜀','杜荀鶴','唐','唐诗','tang','','[]','下第言之蜀，那愁舉別杯。',48,'全唐诗/poet.tang.38000.json','["下第言之蜀，那愁舉別杯。", "難兄方在幕，上相復憐才。", "鳥徑盤春靄，龍湫發夜雷。", "臨邛無久戀，高桂待君回。"]'),
('471c6fe2-3962-4407-8e2d-46f89ca7982c','亂後歸山','杜荀鶴','唐','唐诗','tang','','[]','亂世歸山谷，征鼙喜不聞。',48,'全唐诗/poet.tang.38000.json','["亂世歸山谷，征鼙喜不聞。", "詩書猶滿架，弟姪未爲軍。", "山犬眠紅葉，樵童唱白雲。", "此心非此志，終擬致明君。"]'),
('c9142cf3-9f9d-4332-9c85-15a1ca7fc706','題著禪師','杜荀鶴','唐','唐诗','tang','','[]','大道本無幻，常情自有魔。',48,'全唐诗/poet.tang.38000.json','["大道本無幻，常情自有魔。", "人皆迷著此，師獨悟如何。", "爲岳開窗闊，因蟲長草多。", "說空空說得，空得到維摩。"]'),
('91eb65fd-05d4-4228-8d8d-f5c7c7b97acc','春日閑居即事','杜荀鶴','唐','唐诗','tang','','[]','未得青雲志，春同秋日情。',48,'全唐诗/poet.tang.38000.json','["未得青雲志，春同秋日情。", "花開如葉落，鶯語似蟬鳴。", "道合和貧守，詩堪與命爭。", "飢寒是吾事，斷定不歸耕。"]'),
('b8bd2b40-4e81-480e-a726-c5ba3a68e3c2','秋宿棲賢寺懷友人','杜荀鶴','唐','唐诗','tang','','[]','一宿三秋寺，閑忙與曉分。',48,'全唐诗/poet.tang.38000.json','["一宿三秋寺，閑忙與曉分。", "細泉山半落，孤客夜深聞。", "鶴去巢盛月，龍潛穴擁雲。", "苦吟方見景，多恨不同君。"]'),
('e7554ed9-f336-4379-8a8a-481107bf3af1','亂後再逢汪處士','杜荀鶴','唐','唐诗','tang','','[]','如君真道者，亂世有閑情。',48,'全唐诗/poet.tang.38000.json','["如君真道者，亂世有閑情。", "每別不知處，見來長後生。", "藥非因病服，酒不爲愁傾。", "笑我於身苦，吟髭白數莖。"]'),
('c529dac2-c230-43ed-8c6f-aa36e922e842','山中喜與故交宿話','杜荀鶴','唐','唐诗','tang','','[]','遠地能相訪，何慙事力微。',48,'全唐诗/poet.tang.38000.json','["遠地能相訪，何慙事力微。", "山中深夜坐，海內故交稀。", "村酒沽來濁，溪魚釣得肥。", "貧家只如此，未可便言歸。"]'),
('2d38a6f3-05ed-41a6-a59b-08b4f60bcf54','觀碁','杜荀鶴','唐','唐诗','tang','','[]','對面不相見，用心同用兵。',48,'全唐诗/poet.tang.38000.json','["對面不相見，用心同用兵。", "算人常欲殺，顧己自貪生。", "得勢侵吞遠，乘危打劫贏。", "有時逢敵手，當局到深更。"]'),
('852d4a66-247b-4804-9182-ef4c09c01396','送人宰德清','杜荀鶴','唐','唐诗','tang','','[]','亂世人多事，耕桑或失時。',48,'全唐诗/poet.tang.38000.json','["亂世人多事，耕桑或失時。", "不聞寬賦斂，因此轉流離。", "天意未如是，君心無自欺。", "能依四十字，可立德清碑。"]'),
('fba50569-b399-4132-b3a0-7ed030819799','寄竇處士','杜荀鶴','唐','唐诗','tang','','[]','漳水醉中別，今來猶未醒。',48,'全唐诗/poet.tang.38000.json','["漳水醉中別，今來猶未醒。", "半生因酒廢，大國幾時寧。", "海畔將軍柳，天邊處士星。", "遊人不可見，春入亂山青。"]'),
('31295832-4533-4197-a1eb-56f3100b77bb','題歷山舜祠','杜荀鶴','唐','唐诗','tang','','[]','昔舜曾耕地，遺風日寂寥。',48,'全唐诗/poet.tang.38000.json','["昔舜曾耕地，遺風日寂寥。", "世人那肯祭，大聖不興妖。", "殿宇秋霖壞，杉松野火燒。", "時訛競淫祀，絲竹醉山魈。"]'),
('21b2008e-4601-4595-ada2-fc353e4d20bd','贈李蒙叟','杜荀鶴','唐','唐诗','tang','','[]','在我成何事，逢君更勸吟。',48,'全唐诗/poet.tang.38000.json','["在我成何事，逢君更勸吟。", "縱饒不得力，猶勝別勞心。", "凡事有興廢，詩名無古今。", "百年能幾日，忍不惜光陰。"]'),
('ddea20a3-2860-4bfb-84b3-7e82005f250a','維揚冬末寄幕中二從事','杜荀鶴','唐','唐诗','tang','','[]','聞道長溪尉，相留一館閑。',48,'全唐诗/poet.tang.38000.json','["聞道長溪尉，相留一館閑。", "□□□□□，尚隔幾重山。", "爲旅春風外，懷人夜雨間。", "年來疎覽鏡，怕見減朱顏。"]'),
('b319e46c-66eb-41a4-a006-25b7df145bde','和吳太守罷郡山村偶題二首 一','杜荀鶴','唐','唐诗','tang','','[]','罷郡饒山興，村家不惜過。',48,'全唐诗/poet.tang.38000.json','["罷郡饒山興，村家不惜過。", "官情隨日薄，詩思入秋多。", "野獸眠低草，池禽浴動荷。", "眼前餘政在，不似有干戈。"]'),
('3f6ac250-3980-4bd1-baac-9bd8b69312e5','和吳太守罷郡山村偶題二首 二','杜荀鶴','唐','唐诗','tang','','[]','快活田翁輩，常言化育時。',48,'全唐诗/poet.tang.38000.json','["快活田翁輩，常言化育時。", "縱饒稽歲月，猶說向孫兒。", "茅屋梁和節，茶盤果帶枝。", "相傳終不忘，何必立生祠。"]'),
('3897d27c-48a4-4be7-af91-84a5e74333b3','亂後送友人歸湘中','杜荀鶴','唐','唐诗','tang','','[]','家枕三湘岸，門前即釣磯。',48,'全唐诗/poet.tang.38000.json','["家枕三湘岸，門前即釣磯。", "漁竿壯歲別，鶴髮亂時歸。", "岳暖無猿叫，江春有燕飛。", "平生書劒在，莫便學忘機。"]'),
('d50d7fa4-9a51-49a8-bdbb-b2f306957976','送紫陽僧歸廬岳舊寺','杜荀鶴','唐','唐诗','tang','','[]','紫衣明主贈，歸寺感先師。',48,'全唐诗/poet.tang.38000.json','["紫衣明主贈，歸寺感先師。", "受業恩難報，開堂影不知。", "松風欹枕夜，山雪下樓時。", "此際無人會，微吟復歛眉。"]'),
('e64b010c-8cc4-4ff1-b8c6-eaedb42376ee','和劉評事送海禪和歸山','杜荀鶴','唐','唐诗','tang','','[]','衲外元無象，言尋那路尋。',72,'全唐诗/poet.tang.38000.json','["衲外元無象，言尋那路尋。", "問禪將底說，傳印得何心。", "未了羣山淺，難休一室深。", "伏魔寧是獸，巢頂亦非禽。", "觀色風驅霧，聽聲雪灑林。", "凡歸是歸處，不必指高岑。"]'),
('5b00a57f-55ca-4e88-91e8-5e4e6e8a2b29','御溝柳','杜荀鶴','唐','唐诗','tang','','[]','律到御溝春，溝邊柳色新。',72,'全唐诗/poet.tang.38000.json','["律到御溝春，溝邊柳色新。", "細籠穿禁水，輕拂入朝人。", "日近韶光早，天低聖澤勻。", "谷鶯棲未穩，宮女畫難真。", "楚國空搖浪，隋堤暗惹塵。", "如何帝城裏，先得覆龍津。"]'),
('a9de8077-8661-4700-be78-a33b1338d7a7','冬末同友人泛瀟湘','杜荀鶴','唐','唐诗','tang','','["\u6292\u60c5", "\u6de1\u6cca", "\u5199\u666f"]','殘臘泛舟何處好，最多吟興是瀟湘。',64,'全唐诗/poet.tang.38000.json','["殘臘泛舟何處好，最多吟興是瀟湘。", "就船買得魚偏美，踏雪沽來酒倍香。", "猿到夜深啼嶽麓，鴈知春近別衡陽。", "與君剩採江山景，裁取新詩入帝鄉。"]'),
('e27b8c42-7060-46aa-a48d-adcda16cc561','贈李鐔','杜荀鶴','唐','唐诗','tang','','[]','君行君文天合知，見君如此我興悲。',64,'全唐诗/poet.tang.38000.json','["君行君文天合知，見君如此我興悲。", "秪殘三口兵戈後，纔到孤村雨雪時。", "著臥衣裳難辦洗，旋求糧食莫供炊。", "地鑪不暖柴枝濕，猶把蒙求授小兒。"]'),
('4b534ee6-5767-4853-9f66-f1927c36da70','旅中臥病','杜荀鶴','唐','唐诗','tang','','[]','秋來誰料病相縈，枕上心猶算去程。',64,'全唐诗/poet.tang.38000.json','["秋來誰料病相縈，枕上心猶算去程。", "風射破窗燈易滅，月穿疎屋夢難成。", "故園何啻三千里，新鴈纔聞一兩聲。", "我自與人無舊分，非干人與我無情。"]'),
('bb61bcc7-a89e-4301-ad2d-e9134a6b03ec','旅泊遇郡中叛亂示同志','杜荀鶴','唐','唐诗','tang','','[]','握手相看誰敢言，軍家刀劒在腰邊。',64,'全唐诗/poet.tang.38000.json','["握手相看誰敢言，軍家刀劒在腰邊。", "遍搜寶貨無藏處，亂殺平人不怕天。", "古寺拆爲修寨木，荒墳開作甃城塼。", "郡侯逐出渾閑事，正是鑾輿幸蜀年。"]'),
('2cf56c99-0beb-42a8-806b-1609e28180a7','贈秋浦張明府','杜荀鶴','唐','唐诗','tang','','[]','君爲秋浦三年宰，萬慮關心兩鬢知。',64,'全唐诗/poet.tang.38000.json','["君爲秋浦三年宰，萬慮關心兩鬢知。", "人事旋生當路縣，吏才難展用兵時。", "農夫背上題軍號，賈客船頭插戰旗。", "他日親知問官況，但教吟取杜家詩。"]'),
('7fccf441-09ef-4974-b6d8-8615bbe567b7','雪','杜荀鶴','唐','唐诗','tang','','[]','風攪長空寒骨生，光於曉色報窗明。',64,'全唐诗/poet.tang.38000.json','["風攪長空寒骨生，光於曉色報窗明。", "江湖不見飛禽影，巖谷時聞折竹聲。", "巢穴幾多相似處，路岐兼得一般平。", "擁袍公子休言冷，中有樵夫跣足行。"]'),
('093dd01f-1a80-48a7-ae02-e27eb2a113e7','題廬嶽劉處士草堂','杜荀鶴','唐','唐诗','tang','','[]','仙境閑尋採藥翁，草堂留話一宵同。',64,'全唐诗/poet.tang.38000.json','["仙境閑尋採藥翁，草堂留話一宵同。", "若看山下雲深處，直是人間路不通。", "泉領藕花來洞口，月將松影過溪東。", "求名心在閑難遂，明日馬蹄塵土中。"]'),
('dbda0ac7-3684-4d28-a82f-54f7d992625e','山中寄詩友','杜荀鶴','唐','唐诗','tang','','[]','山深長恨少同人，覽景無時不憶君。',64,'全唐诗/poet.tang.38000.json','["山深長恨少同人，覽景無時不憶君。", "庭果自從霜後熟，野猿頻向屋邊聞。", "琴臨秋水彈明月，酒就東山酌白雲。", "仙桂算攀攀合得，平生心力盡於文。"]'),
('a404f717-91a7-45d8-8d02-964f3ba588ce','秋宿臨江驛','杜荀鶴','唐','唐诗','tang','','[]','南來北去二三年，年去年來兩鬢斑。',64,'全唐诗/poet.tang.38000.json','["南來北去二三年，年去年來兩鬢斑。", "舉世盡從愁裏老，誰人肯向死前閑。", "漁舟火影寒歸浦，驛路鈴聲夜過山。", "身事未成歸未得，聽猿鞭馬入長關。"]'),
('68ecd3fc-511a-4b49-9137-34b1e1a7786f','題瓦棺寺真上人院矮檜','杜荀鶴','唐','唐诗','tang','','[]','天生仙檜是長材，栽檜希逢此最低。',64,'全唐诗/poet.tang.38000.json','["天生仙檜是長材，栽檜希逢此最低。", "一自舊山來砌畔，幾番凡木與雲齊。", "迴無斜影教僧踏，免有閑枝引鶴棲。", "今日偶題題似着，不知題後更誰題。"]'),
('d5255d88-2dd1-45ad-806c-f8fda1bd2d43','江下初秋寓泊','杜荀鶴','唐','唐诗','tang','','[]','濛濛煙雨蔽江村，江館愁人好斷魂。',64,'全唐诗/poet.tang.38000.json','["濛濛煙雨蔽江村，江館愁人好斷魂。", "自別家來生白髮，爲侵星起謁朱門。", "也知柳欲開春眼，爭奈萍無入土根。", "兄弟無書鴈歸北，一聲聲覺苦於猿。"]'),
('541e8bfe-cadd-41e9-8f35-dea5a065d888','投從叔補闕','杜荀鶴','唐','唐诗','tang','','[]','吾宗不謁謁詩宗，常仰門風繼國風。',64,'全唐诗/poet.tang.38000.json','["吾宗不謁謁詩宗，常仰門風繼國風。", "空有篇章傳海內，更無親族在朝中。", "其來雖媿源流淺，所得須憐雅頌同。", "三十年吟到今日，不妨私薦亦成公。"]'),
('d884c2e5-8cda-4bc4-991b-6225c2072424','贈張員外兒','杜荀鶴','唐','唐诗','tang','','[]','張公一子才三歲，聞客吟聲便出來。',64,'全唐诗/poet.tang.38000.json','["張公一子才三歲，聞客吟聲便出來。", "喚物舌頭猶未穩，誦詩心孔迥然開。", "天生便是成家慶，年長終爲間世才。", "月裏桂枝知有分，不勞諸丈作梯媒。"]'),
('ee446c46-8054-4928-854c-228b46d9e16a','重陽日有作','杜荀鶴','唐','唐诗','tang','','[]','一爲重陽上古臺，亂時誰見菊花開。',64,'全唐诗/poet.tang.38000.json','["一爲重陽上古臺，亂時誰見菊花開。", "偷𢸧白髮真堪笑，牢鏁黃金實可哀。", "是箇少年皆老去，爭知荒塚不榮來。", "大家拍手高聲唱，日未沈山且莫迴。"]'),
('0b76a0f4-ff08-4038-b195-e253b44efaeb','入關寄九華友人','杜荀鶴','唐','唐诗','tang','','[]','坐牀難穩露蟬新，便作東西馬上身。',64,'全唐诗/poet.tang.38000.json','["坐牀難穩露蟬新，便作東西馬上身。", "醲酒却輸耽睡客，好山翻對不吟人。", "無多志氣禁離別，強半年光屬苦辛。", "篋裏篇章頭上雪，未知誰戀杏園春。"]'),
('9feef88b-7433-477b-856b-3e8b8d2491cb','送李鐔遊新安','杜荀鶴','唐','唐诗','tang','','[]','邯鄲李鐔才崢嶸，酒狂詩逸難干名。',64,'全唐诗/poet.tang.38000.json','["邯鄲李鐔才崢嶸，酒狂詩逸難干名。", "氣直不與兒輩洽，醉來擬共天公爭。", "孤店夜燒枯葉坐，亂時秋踏早霜行。", "一間茅屋住不穩，剛出爲人平不平。"]'),
('45c3b6bd-bcd2-4eca-a5cd-ed31b6c12034','冬末自長沙遊桂嶺留獻所知','杜荀鶴','唐','唐诗','tang','','[]','家隔重湖歸未期，更堪南去別深知。',64,'全唐诗/poet.tang.38000.json','["家隔重湖歸未期，更堪南去別深知。", "前程笑到山多處，上馬愁逢歲盡時。", "四海內無容足地，一生中有苦心詩。", "朱門秪見朱門事，獨把孤寒問阿誰。"]'),
('af9a3730-053c-4b11-881c-b3b760b67470','送福昌周繇少府歸寧兼謀隱','杜荀鶴','唐','唐诗','tang','','[]','少見古人無遠慮，如君真得古人情。',64,'全唐诗/poet.tang.38000.json','["少見古人無遠慮，如君真得古人情。", "登科作尉官雖小，避世安親祿已榮。", "一路水雲生隱思，幾山猿鳥認吟聲。", "知君未作終焉計，要著文章待太平。"]'),
('4fdfa53c-8575-4c68-aec2-9a67274c4ac4','賀顧雲侍御府主與子弟奏官','杜荀鶴','唐','唐诗','tang','','[]','青桂朱袍不賀兄，賀兄榮是見兒榮。',64,'全唐诗/poet.tang.38000.json','["青桂朱袍不賀兄，賀兄榮是見兒榮。", "孝經始向堂前徹，官誥當從幕下迎。", "戲把藍袍包果子，嬌將竹笏惱先生。", "自慙亂世無知己，弟姪鞭牛傍隴耕。"]'),
('9258cfae-35aa-40a6-81a2-1feeeeb7403e','舟行即事','杜荀鶴','唐','唐诗','tang','','[]','年少髭鬚雪欲侵，別家三日幾般心。',64,'全唐诗/poet.tang.38000.json','["年少髭鬚雪欲侵，別家三日幾般心。", "朝隨賈客憂風色，夜逐漁翁宿葦林。", "秋水鷺飛紅蓼晚，暮山猿叫白雲深。", "重陽酒熟茱萸紫，却向江頭倚棹吟。"]'),
('1962eeeb-5152-4ff1-84c4-91e9ebf347ab','亂後山居','杜荀鶴','唐','唐诗','tang','','[]','從亂移家擬傍山，今來方辦買山錢。',64,'全唐诗/poet.tang.38000.json','["從亂移家擬傍山，今來方辦買山錢。", "九州有路休爲客，百歲無愁即是仙。", "野叟竝田鋤暮雨，溪禽同石立寒煙。", "他人似我還應少，如此安貧亦荷天。"]'),
('cca2f682-f5ca-400c-8bdb-2913ea9713d0','山居寄同志','杜荀鶴','唐','唐诗','tang','','[]','茅齋深僻絕輪蹄，門徑緣莎細接溪。',64,'全唐诗/poet.tang.38000.json','["茅齋深僻絕輪蹄，門徑緣莎細接溪。", "垂釣石臺依竹壘，待賓茶竈就巖泥。", "風生谷口猿相叫，月照松頭鶴竝棲。", "不是無端過時日，擬從窗下躡雲梯。"]'),
('17613c91-f1ba-41ba-b718-c295bd27d900','將入關安陸遇兵寇','杜荀鶴','唐','唐诗','tang','','[]','家貧無計早離家，離得家來蹇滯多。',64,'全唐诗/poet.tang.38000.json','["家貧無計早離家，離得家來蹇滯多。", "已是數程行雨雪，更堪中路阻兵戈。", "幾州戶口看成血，一旦天心却許和。", "四面煙塵少無處，不知吾土自如何。"]'),
('9cf12da0-6e86-42bb-82c4-22b9f14f1b2d','夏日登友人書齋林亭','杜荀鶴','唐','唐诗','tang','','[]','暑天長似秋天冷，帶郭林亭畫不如。',64,'全唐诗/poet.tang.38000.json','["暑天長似秋天冷，帶郭林亭畫不如。", "蟬噪檻前遮日竹，鷺窺池面弄萍魚。", "拋山野客橫琴醉，種藥家僮踏雪鋤。", "衆惜君才堪上第，莫因居此與名疎。"]'),
('e51fa3c9-90ca-4234-b688-531140b9f5ad','寄臨海姚中丞','杜荀鶴','唐','唐诗','tang','','[]','夏辭旌斾已秋深，永夕思量淚滿襟。',64,'全唐诗/poet.tang.38000.json','["夏辭旌斾已秋深，永夕思量淚滿襟。", "風月易斑搜句鬢，星霜難改感恩心。", "尋花洞裏連春醉，望海樓中徹曉吟。", "雖有夢魂知處所，去來多被角聲侵。"]'),
('bbdbaeba-abe5-4309-9d92-6c0e74026981','秋日閑居寄先達','杜荀鶴','唐','唐诗','tang','','[]','到頭身事欲何爲，窗下工夫鬢上知。',64,'全唐诗/poet.tang.38000.json','["到頭身事欲何爲，窗下工夫鬢上知。", "乍可百年無稱意，難教一日不吟詩。", "風驅早鴈衝湖色，雨挫殘蟬點柳枝。", "自古書生也如此，獨堪惆悵是明時。"]'),
('2803d624-a72d-4560-9aad-f8feec6329c3','題覺禪和','杜荀鶴','唐','唐诗','tang','','[]','少見修行得似師，茅堂佛像亦隨時。',64,'全唐诗/poet.tang.38000.json','["少見修行得似師，茅堂佛像亦隨時。", "禪衣衲後雲藏線，夏臘高來雪印眉。", "耕地誡侵連塚土，伐薪教護帶巢枝。", "有時問着經中事，却道山僧總不知。"]'),
('8f992df1-2c49-4b4e-861b-4ce2e217608f','感秋','杜荀鶴','唐','唐诗','tang','','[]','年年名路謾辛勤，襟袖空多馬上塵。',64,'全唐诗/poet.tang.38000.json','["年年名路謾辛勤，襟袖空多馬上塵。", "畫戟門前難作客，釣魚船上易安身。", "冷煙黏柳蟬聲老，寒渚澄星雁叫新。", "自是儂家無住處，不關天地窄於人。"]'),
('1e556de9-4f5d-4c89-b62b-3706ca72b464','題德玄上人院','杜荀鶴','唐','唐诗','tang','','[]','刳得心來忙處閑，閑中方寸闊於天。',64,'全唐诗/poet.tang.38000.json','["刳得心來忙處閑，閑中方寸闊於天。", "浮生自是無空性，長壽何曾有百年。", "罷定磬敲松罅月，解眠茶煮石根泉。", "我雖未似師披衲，此理同師悟了然。"]'),
('81170ea7-4553-4bce-813d-f8bbd8265e1b','春日山居寄友人','杜荀鶴','唐','唐诗','tang','','[]','野吟何處最相宜，春景暄和好入詩。',64,'全唐诗/poet.tang.38000.json','["野吟何處最相宜，春景暄和好入詩。", "高下麥苗新雨後，淺深山色晚晴時。", "半巖雲脚風牽斷，平野花枝鳥踏垂。", "倒載干戈是何日，近來麋鹿欲相隨。"]'),
('930dd667-3b03-4929-b072-162f39835bc5','懷廬嶽舊隱','杜荀鶴','唐','唐诗','tang','','[]','一別三年長在夢，夢中時躡石稜層。',64,'全唐诗/poet.tang.38000.json','["一別三年長在夢，夢中時躡石稜層。", "泉聲入夜方堪聽，山色逢秋始好登。", "巖鹿慣隨鋤藥叟，溪鷗不怕洗苔僧。", "人間有許多般事，求要身閑直未能。"]'),
('6665c96d-592e-43fe-9982-e2e5b0d69578','投長沙裴侍郎','杜荀鶴','唐','唐诗','tang','','[]','此身雖賤道長存，非謁朱門謁孔門。',64,'全唐诗/poet.tang.38000.json','["此身雖賤道長存，非謁朱門謁孔門。", "秪望至公將卷讀，不求朝士致書論。", "垂綸雨結漁鄉思，吹木風傳鴈夜魂。", "男子受恩須有地，平生不受等閑恩。"]'),
('19f32680-eea2-48d2-b17c-65cdd4fc5e4c','和友人見題山居','杜荀鶴','唐','唐诗','tang','','[]','避時多喜葺居成，七字君題萬象清。',64,'全唐诗/poet.tang.38000.json','["避時多喜葺居成，七字君題萬象清。", "開戶曉雲連地白，訪人秋月滿山明。", "庭前樹瘦霜來影，洞口泉噴雨後聲。", "有景供吟且如此，算來何必躁於名。"]'),
('2993bfb9-fde3-4802-8dd4-25a1261fa22f','獻長沙王侍郎','杜荀鶴','唐','唐诗','tang','','[]','文星漸見射台星，皆仰爲霖沃衆情。',64,'全唐诗/poet.tang.38000.json','["文星漸見射台星，皆仰爲霖沃衆情。", "天澤逼來逢聖主，辭林盛去得書生。", "雲粧嶽色供吟景，月浩湘流遞政聲。", "美化事多難諷誦，未如耕釣口分明。"]'),
('147519d6-fcd8-4f85-b24c-a439aded4190','春日登樓遇雨','杜荀鶴','唐','唐诗','tang','','[]','忽地晴天作雨天，全無暑氣似秋間。',64,'全唐诗/poet.tang.38000.json','["忽地晴天作雨天，全無暑氣似秋間。", "看看水沒來時路，漸漸雲藏望處山。", "風趁鷺鷥雙出葦，浪催漁父盡歸灣。", "一心準擬閑登眺，却被詩情使不閑。"]'),
('ae6e4fe6-1b49-4c2c-b0ae-1692a59b9072','春日行次錢塘却寄台州姚中丞','杜荀鶴','唐','唐诗','tang','','[]','豈爲無心求上第，難安帝里爲家貧。',64,'全唐诗/poet.tang.38000.json','["豈爲無心求上第，難安帝里爲家貧。", "江南江北閑爲客，潮去潮來老却人。", "兩岸雨收鶯語柳，一樓風滿角吹春。", "花前不獨垂鄉淚，曾是朱門寄食身。"]'),
('84c89c8f-c977-4348-a5cd-daee299ce601','投江上崔尚書','杜荀鶴','唐','唐诗','tang','','[]','此生何路出塵埃，猶把中才謁上才。',64,'全唐诗/poet.tang.38000.json','["此生何路出塵埃，猶把中才謁上才。", "閉戶十年專筆硯，仰天無處認梯媒。", "馬前霜葉催歸去，枕上邊鴻喚覺來。", "若許登門換鬐鬣，必應辛苦事風雷。"]'),
('2aa3fb25-59cc-4143-acaf-7ebae6b32afb','書事投所知','杜荀鶴','唐','唐诗','tang','','[]','古陌寒風來去吹，馬蹄塵旋上麻衣。',64,'全唐诗/poet.tang.38000.json','["古陌寒風來去吹，馬蹄塵旋上麻衣。", "雖然干祿無休意，爭奈趨時不見機。", "詩思趁雲從嶽涌，鄉心隨鴈遶湖飛。", "肯將骨肉輕離別，未遇人知未得歸。"]'),
('58fe6dd6-acb1-4032-99fb-6c72c94d2f23','秋日湖外書事','杜荀鶴','唐','唐诗','tang','','[]','十五年來筆硯功，秪今猶在苦貧中。',64,'全唐诗/poet.tang.38000.json','["十五年來筆硯功，秪今猶在苦貧中。", "三秋客路湖光外，萬里鄉關楚邑東。", "鳥逕杖藜山翳雨，猿林欹枕樹搖風。", "朱門處處若相似，此命到頭通不通。"]'),
('a1c67ddb-23e0-494b-9399-8329061c0713','題宗上人舊院','杜荀鶴','唐','唐诗','tang','','[]','此院重來事事乖，半欹茅屋草侵堦。',64,'全唐诗/poet.tang.38000.json','["此院重來事事乖，半欹茅屋草侵堦。", "啄生鴉憶啼松枿，接果猿思嘯石崖。", "壁上塵黏蒲葉扇，牀前苔爛筍皮鞋。", "分明記得談空日，不向秋風更愴懷。"]'),
('acf78547-a9c5-414d-be78-4d25a84e17e8','亂後出山逢高員外','杜荀鶴','唐','唐诗','tang','','[]','自從亂後別京關，一入煙蘿十五年。',64,'全唐诗/poet.tang.38000.json','["自從亂後別京關，一入煙蘿十五年。", "重出故山生白髮，却裝新卷謁清賢。", "窗迴旅夢城頭角，柳結鄉愁雨後蟬。", "名姓暗投心暗祝，永期收拾向門前。"]'),
('052ba7a8-54b8-4ee6-947e-70f6644fba0b','贈友人罷舉赴交趾辟命','杜荀鶴','唐','唐诗','tang','','[]','罷却名場擬入秦，南行無罪似流人。',64,'全唐诗/poet.tang.38000.json','["罷却名場擬入秦，南行無罪似流人。", "縱經商嶺非馳驛，須過長沙弔逐臣。", "舶載海奴鐶硾耳，象駝蠻女綵纏身。", "如何待取丹霄桂，別赴嘉招作上賓。"]'),
('293466f5-27ef-4a4c-8c90-75eefb445669','山中寡婦','杜荀鶴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5987\u5973", "\u751f\u6d3b"]','夫因兵死守蓬茅，麻苧衣衫鬢髮焦。',64,'全唐诗/poet.tang.38000.json','["夫因兵死守蓬茅，麻苧衣衫鬢髮焦。", "桑柘廢來猶納稅，田園荒後尚徵苗。", "時挑野菜和根煮，旋斫生柴帶葉燒。", "任是深山更深處，也應無計避征徭。"]'),
('7e8386a3-3292-4ca2-b50f-f61207641dba','訪蔡融因題','杜荀鶴','唐','唐诗','tang','','[]','杖藜時復過荒郊，來到君家不忍拋。',64,'全唐诗/poet.tang.38000.json','["杖藜時復過荒郊，來到君家不忍拋。", "每見苦心修好事，未嘗開口怨平交。", "一溪寒色漁收網，半樹斜陽鳥傍巢。", "必若天工主人事，肯交吾子委衡茅。"]'),
('93c6ab71-b30d-4a95-ae38-99024518c486','閑居書事','杜荀鶴','唐','唐诗','tang','','[]','竹門茅屋帶村居，數畝生涯自有餘。',64,'全唐诗/poet.tang.38000.json','["竹門茅屋帶村居，數畝生涯自有餘。", "鬢白祗應秋鍊句，眼昏多爲夜抄書。", "鴈驚風浦漁燈動，猿叫霜林橡實疎。", "待得功成即西去，時清不問命何如。"]'),
('5de5f40d-33bc-44e3-96be-4b89ea5c4676','友人贈舍弟依韻戲和','杜荀鶴','唐','唐诗','tang','','[]','吾家此弟有何知，多媿君開道業基。',64,'全唐诗/poet.tang.38000.json','["吾家此弟有何知，多媿君開道業基。", "不覺裹頭成大漢，昨來竹馬作童兒。", "還緣世遇兵戈鬧，祗恐身修禮樂遲。", "及見和詩詩自好，碢公不到更何時。"]'),
('96e68215-27c3-42b5-9055-308a852fdcdb','亂後逢村叟','杜荀鶴','唐','唐诗','tang','','[]','經亂衰翁居破村，村中何事不傷魂。',64,'全唐诗/poet.tang.38000.json','["經亂衰翁居破村，村中何事不傷魂。", "因供寨木無桑柘，爲著鄉兵絕子孫。", "還似平寧徵賦稅，未嘗州縣畧安存。", "至於雞犬皆星散，日落前山獨倚門。"]'),
('dac1baa2-4987-4aa6-af91-fb9b536a9cb9','贈元上人','杜荀鶴','唐','唐诗','tang','','[]','多少僧中僧行高，偈成流落遍僧抄。',64,'全唐诗/poet.tang.38000.json','["多少僧中僧行高，偈成流落遍僧抄。", "經窗月靜灘聲到，石逕人稀蘚色交。", "垂露竹黏蟬落殼，窣雲松載鶴棲巢。", "煮茶童子閑勝我，猶得依時把磬敲。"]'),
('fb87380a-59c2-4109-9151-c8a5228328ca','下第東歸道中作','杜荀鶴','唐','唐诗','tang','','[]','一迴落第一寧親，多是途中過却春。',64,'全唐诗/poet.tang.38000.json','["一迴落第一寧親，多是途中過却春。", "心火不銷雙鬢雪，眼泉難濯滿衣塵。", "苦吟風月唯添病，遍識公卿未免貧。", "馬壯金多有官者，榮歸却笑讀書人。"]'),
('0950174c-6529-49b6-b5dd-9965784d246a','夏日留題張山人林亭','杜荀鶴','唐','唐诗','tang','','[]','此中偏稱夏中遊，時有風來暑氣收。',64,'全唐诗/poet.tang.38000.json','["此中偏稱夏中遊，時有風來暑氣收。", "澗底松搖千尺雨，庭中竹撼一窗秋。", "求猿句寄山深寺，乞鶴書傳海畔洲。", "閑與先生話身事，浮名薄宦總悠悠。"]'),
('8e356125-1079-41a1-abf1-b32d8e7c7db9','傷病馬','杜荀鶴','唐','唐诗','tang','','[]','此馬堪憐力壯時，細勻行步恐塵知。',64,'全唐诗/poet.tang.38000.json','["此馬堪憐力壯時，細勻行步恐塵知。", "騎來未省將鞭觸，病後長教覓藥醫。", "顧主強擡和淚眼，就人輕刷帶瘡皮。", "祗今筋骨渾全在，春暖莎青放未遲。"]'),
('2e93f84e-9fa3-4fad-b21a-6a5768771072','館舍秋夕','杜荀鶴','唐','唐诗','tang','','[]','寒雨蕭蕭燈焰青，燈前孤客難爲情。',64,'全唐诗/poet.tang.38000.json','["寒雨蕭蕭燈焰青，燈前孤客難爲情。", "兵戈鬧日別鄉國，鴻鴈過時思弟兄。", "冷極睡無離枕夢，苦多吟有徹雲聲。", "出門便作還家計，直至如今計未成。"]'),
('2e9c1f46-dd0f-4913-b7e2-22dc9a6047c5','送僧赴黃山沐湯泉兼參禪宗長老','杜荀鶴','唐','唐诗','tang','','["\u9ec4\u5c71"]','聞有湯泉獨去尋，一缾一鉢一無金。',64,'全唐诗/poet.tang.38000.json','["聞有湯泉獨去尋，一缾一鉢一無金。", "不愁亂世兵相害，却喜寒山路入深。", "野老禱神鴉噪廟，獵人衝雪鹿驚林。", "患身是幻逢禪主，水洗皮膚語洗心。"]'),
('a40e035d-c6f5-4ec1-90f9-7093e6839754','哭山友','杜荀鶴','唐','唐诗','tang','','[]','十載同棲廬嶽雲，寒燒枯葉夜論文。',64,'全唐诗/poet.tang.38000.json','["十載同棲廬嶽雲，寒燒枯葉夜論文。", "在生未識公卿面，至死不離麋鹿羣。", "從見蓬蒿叢壞屋，長憂雨雪透荒墳。", "把君詩句高聲讀，想得天高也合聞。"]'),
('ce31f5b8-c783-4414-8a42-38a80b22e85c','獻池州牧','杜荀鶴','唐','唐诗','tang','','[]','池陽今日似漁陽，大變凶年作小康。',64,'全唐诗/poet.tang.38000.json','["池陽今日似漁陽，大變凶年作小康。", "江路靜來通客貨，郡城安後絕戎裝。", "分開野色收新麥，驚斷鶯聲摘嫩桑。", "縱有逋民歸未得，遠聞仁政旋還鄉。"]'),
('901264bd-279f-4dca-9746-60ef0ed6201c','送韋書記歸京','杜荀鶴','唐','唐诗','tang','','[]','韋杜相逢眼自明，事連恩地倍牽情。',64,'全唐诗/poet.tang.38000.json','["韋杜相逢眼自明，事連恩地倍牽情。", "聞歸帝里愁攀送，知到師門話姓名。", "朝客半修前輩禮，古人多重晚年榮。", "從來有淚非無淚，未似今朝淚滿纓。"]'),
('755476e7-25ff-4b69-97f9-d23e47933b2d','獻鄭給事','杜荀鶴','唐','唐诗','tang','','[]','化行邦域二年春，樵唱漁歌日日新。',64,'全唐诗/poet.tang.38000.json','["化行邦域二年春，樵唱漁歌日日新。", "未降詔書酬善政，不知天澤答何人。", "秋登嶽寺雲隨步，夜宴江樓月滿身。", "他日朱門恐難掃，沙堤新築必無塵。"]'),
('8c93aef2-f707-4710-9602-c4c706941159','贈休禪和','杜荀鶴','唐','唐诗','tang','','[]','爲僧難得不爲僧，僧戒僧儀未是能。',64,'全唐诗/poet.tang.38000.json','["爲僧難得不爲僧，僧戒僧儀未是能。", "弟子自知心了了，吾師應爲醉騰騰。", "多生覺悟非關衲，一點分明不在燈。", "祗道詩人無佛性，長將二雅入三乘。"]'),
('bbf0b3ff-a5d9-4006-bca5-9c862f0a8132','送李先輩從知塞上','杜荀鶴','唐','唐诗','tang','','[]','去草軍書出帝鄉，便從城外學戎裝。',64,'全唐诗/poet.tang.38000.json','["去草軍書出帝鄉，便從城外學戎裝。", "好隨漢將收胡土，莫遣胡兵近漢疆。", "灑磧雪黏旗力重，凍河風揭角聲長。", "此行也是男兒事，莫向征人恃桂香。"]'),
('219c32a2-a69b-4a10-b669-1dfbee8179e9','和友人送弟','杜荀鶴','唐','唐诗','tang','','[]','君說無家祗弟兄，此中言別若爲情。',64,'全唐诗/poet.tang.38000.json','["君說無家祗弟兄，此中言別若爲情。", "干戈鬧日分頭去，山水寒時信路行。", "月下斷猿空有影，雪中孤鴈却無聲。", "我今骨肉雖飢凍，幸喜團圓過亂兵。"]'),
('f0c76639-6c4e-4268-8e14-993b3c1f9e39','酬張員外見寄','杜荀鶴','唐','唐诗','tang','','[]','分應天與吟詩老，如此兵戈不廢詩。',64,'全唐诗/poet.tang.38000.json','["分應天與吟詩老，如此兵戈不廢詩。", "生在世間人不識，死於泉下鬼應知。", "啼花蜀鳥春同苦，叫雪巴猿晝共飢。", "今日逢君惜分手，一枝何校一年遲。"]'),
('b3c4d3a9-a464-4180-9e88-a3528dc138f2','獻新安于尚書','杜荀鶴','唐','唐诗','tang','','[]','九土雄師竟若何，未如良牧與天和。',64,'全唐诗/poet.tang.38000.json','["九土雄師竟若何，未如良牧與天和。", "月留清俸資家少，歲計陰功及物多。", "四野綠雲籠稼穡，千山明月靜干戈。", "行人耳滿新安事，盡是無愁父老歌。"]'),
('464dc5bf-95c9-48a4-8777-86b1cb387a1a','亂後書事寄同志','杜荀鶴','唐','唐诗','tang','','[]','九土如今盡用兵，短戈長戟困書生。',64,'全唐诗/poet.tang.38000.json','["九土如今盡用兵，短戈長戟困書生。", "思量在世頭堪白，畫度歸山計未成。", "皇澤正霑新將士，侯門不是舊公卿。", "到頭詩卷須藏却，各向漁樵混姓名。"]'),
('560f281d-f1a9-4d9c-acd9-3064bd77ca13','中山臨上人院觀牡丹寄諸從事','杜荀鶴','唐','唐诗','tang','','[]','閑來吟遶牡丹叢，花豔人生事畧同。',64,'全唐诗/poet.tang.38000.json','["閑來吟遶牡丹叢，花豔人生事畧同。", "半雨半風三月內，多愁多病百年中。", "開當韶景何妨好，落向僧家即是空。", "一境別無唯此有，忍教醒坐對支公。"]'),
('2e4ce87e-08a8-4403-959c-a32cf569ef96','投宣諭張侍郎亂後遇毘陵','杜荀鶴','唐','唐诗','tang','','[]','此生今日似前生，重著麻衣特地行。',64,'全唐诗/poet.tang.38000.json','["此生今日似前生，重著麻衣特地行。", "經亂後囊新卷軸，出山來見舊公卿。", "雨籠蛬壁吟燈影，風觸蟬枝噪浪聲。", "聞道中興重人物，不妨西去馬蹄輕。"]'),
('a43832b9-03a7-4462-bd2d-5520298165e0','下第投所知','杜荀鶴','唐','唐诗','tang','','[]','落第愁生曉鼓初，地寒才薄欲何如。',64,'全唐诗/poet.tang.38000.json','["落第愁生曉鼓初，地寒才薄欲何如。", "不辭更寫公卿卷，却是難修骨肉書。", "御苑早鶯啼暖樹，釣鄉春水浸貧居。", "擬離門館東歸去，又恐重來事轉疎。"]'),
('50d3711d-a019-4b13-b894-52e2389c349a','哭方干','杜荀鶴','唐','唐诗','tang','','[]','何言寸祿不沾身，身沒詩名萬古存。',64,'全唐诗/poet.tang.38000.json','["何言寸祿不沾身，身沒詩名萬古存。", "況有數篇關教化，得無餘慶及兒孫。", "漁樵共壘墳三尺，猿鶴同棲月一村。", "天下未寧吾道喪，更誰將酒酹吟魂。"]'),
('eb416a62-a7ed-48fd-86b1-ffea7d83e28f','秋日泊浦江','杜荀鶴','唐','唐诗','tang','','[]','一帆程歇九秋時，漠漠蘆花拂浪飛。',64,'全唐诗/poet.tang.38000.json','["一帆程歇九秋時，漠漠蘆花拂浪飛。", "寒浦更無船竝宿，暮山時見鳥雙歸。", "照雲烽火驚離抱，剪葉風霜逼暑衣。", "江月漸明汀露濕，靜驅吟魄入玄微。"]'),
('9d6bdf1c-f81b-4ca8-9cf4-cefdd597adea','白髮吟','杜荀鶴','唐','唐诗','tang','','[]','一莖兩莖初似絲，不妨驚度少年時。',64,'全唐诗/poet.tang.38000.json','["一莖兩莖初似絲，不妨驚度少年時。", "幾人亂世得及此，今我滿頭何足悲。", "九轉靈丹那勝酒，五音清樂未如詩。", "家山蒼翠萬餘尺，藜杖楮冠輸老兒。"]'),
('bb7cf8d0-aa05-415b-9dd1-03e13a81fae6','下第寄池州鄭員外','杜荀鶴','唐','唐诗','tang','','[]','省出蓬蒿修謁初，蒙知曾不見生疎。',64,'全唐诗/poet.tang.38000.json','["省出蓬蒿修謁初，蒙知曾不見生疎。", "侯門數處將書薦，帝里經年借宅居。", "未必有詩堪諷誦，祗憐無援過吹噓。", "如今足得成持取，莫使江湖却釣魚。"]'),
('dd01992e-ed6f-47cf-a444-a05a4526e190','塞上','杜荀鶴','唐','唐诗','tang','','[]','旌旗鬣鬣漢將軍，閑出巡邊帝命新。',64,'全唐诗/poet.tang.38000.json','["旌旗鬣鬣漢將軍，閑出巡邊帝命新。", "沙塞旋收饒帳幕，犬戎時殺少煙塵。", "冰河夜渡偷來馬，雪嶺朝飛獵去人。", "獨作書生疑不穩，軟弓輕劒也隨身。"]'),
('31e3c174-4ac9-408d-a5cc-bc10a1a368b4','贈題兜率寺閑上人院','杜荀鶴','唐','唐诗','tang','','[]','人間寺應諸天號，真行僧禪此寺中。',64,'全唐诗/poet.tang.38000.json','["人間寺應諸天號，真行僧禪此寺中。", "百歲有涯頭上雪，萬般無染耳邊風。", "挂帆波浪驚心白，上馬塵埃翳眼紅。", "畢竟浮生謾勞役，算來何事不成空。"]'),
('86cfbffc-313b-458a-ab3f-7facae93741c','別四明鍾尚書','杜荀鶴','唐','唐诗','tang','','[]','九華天際碧嵯峨，無奈春來入夢何。',64,'全唐诗/poet.tang.38000.json','["九華天際碧嵯峨，無奈春來入夢何。", "難與英雄論教化，却思猿鳥共煙蘿。", "風前柳態閑時少，雨後花容淡處多。", "都大人生有離別，且將詩句代離歌。"]'),
('fd17ef3d-98fd-4cb7-9463-6d85bea90f6e','題護國大師塔','杜荀鶴','唐','唐诗','tang','','[]','莫認雙林是佛林，禪棲無地亦無金。',64,'全唐诗/poet.tang.38000.json','["莫認雙林是佛林，禪棲無地亦無金。", "塔前盡禮灰來相，衲下誰宗印了心。", "笠象胤明雙不見，線源分派寸難尋。", "吾師覺路余知處，大藏經門一夜吟。"]'),
('123a1f14-745c-4268-bb16-b2090684c3b3','春日山中對雪有作','杜荀鶴','唐','唐诗','tang','','["\u5199\u96ea", "\u6625\u5929", "\u96ea", "\u559c\u60a6"]','竹樹無聲或有聲，霏霏漠漠散還凝。',64,'全唐诗/poet.tang.38000.json','["竹樹無聲或有聲，霏霏漠漠散還凝。", "嶺梅謝後重粧蘂，巖水鋪來却結冰。", "牢繫鹿兒防獵客，滿添茶鼎候吟僧。", "好將膏雨同功力，松徑莓苔又一層。"]'),
('9c84da30-f186-4766-ace6-1203bd33da0c','山中對雪有作','杜荀鶴','唐','唐诗','tang','','[]','一渾乾坤萬象收，唯應不壅大江流。',64,'全唐诗/poet.tang.38000.json','["一渾乾坤萬象收，唯應不壅大江流。", "虎狼遇獵難藏跡，松柏因風易舉頭。", "玉帳英雄攜妓賞，山村鳥雀共民愁。", "豈堪久蔽蒼蒼色，須放三光照九州。"]'),
('da558545-641b-4dab-aff7-2cac070994d9','戲題王處士書齋','杜荀鶴','唐','唐诗','tang','','[]','先生高興似樵漁，水鳥山猿一處居。',64,'全唐诗/poet.tang.38000.json','["先生高興似樵漁，水鳥山猿一處居。", "石徑可行苔色厚，釣竿時斫竹叢疎。", "欺春祗愛和醅酒，諱老猶看夾注書。", "莫道無金空有壽，有金無壽欲何如。"]'),
('7196cf75-49ee-465c-b4a2-7f3e0c656b6c','早發','杜荀鶴','唐','唐诗','tang','','[]','東窗未明塵夢蘇，呼童結束登征途。',64,'全唐诗/poet.tang.38000.json','["東窗未明塵夢蘇，呼童結束登征途。", "落葉鋪霜馬蹄滑，寒猿嘯月人心孤。", "時逆帽簷風刮頂，旋呵鞭手凍粘鬚。", "青雲快活一未見，爭得安閑釣五湖。"]'),
('d72d6db9-c7b5-4323-a028-0290b74f2ca6','題仇處士郊居','杜荀鶴','唐','唐诗','tang','','[]','江南景簇此林亭，手板藍裾自可輕。',64,'全唐诗/poet.tang.38000.json','["江南景簇此林亭，手板藍裾自可輕。", "洞裏客來無俗話，郭中人到有公情。", "閑敲巖果呼猿接，時釣溪魚引鶴爭。", "笑我有詩三百首，馬蹄紅日急於名。"]'),
('522c8e7e-bc9d-4973-a336-2b0f3e032202','依韻次同年張曙先輩見寄之什','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','天上詩名天下傳，引來齊列玉皇前。',64,'全唐诗/poet.tang.38000.json','["天上詩名天下傳，引來齊列玉皇前。", "大仙錄後頭無雪，至藥成來竈絕煙。", "笑躡紫雲金作闕，夢拋塵世鐵爲船。", "九華山叟驚凡骨，同到蓬萊豈偶然。"]'),
('adffd7e8-42b9-4016-9fd0-9a78011989d3','亂後逢李昭象敘別','杜荀鶴','唐','唐诗','tang','','[]','李生李生何所之，家山窣雲胡不歸。',64,'全唐诗/poet.tang.38000.json','["李生李生何所之，家山窣雲胡不歸。", "兵戈到處弄性命，禮樂向人生是非。", "却與野猿同橡塢，還將溪鳥共漁磯。", "也知不是男兒事，爭奈時情賤布衣。"]'),
('3405ba46-baf3-455c-8227-b959638d1794','晚春寄同年張曙先輩','杜荀鶴','唐','唐诗','tang','','[]','莫將時態破天真，祗合高歌醉過春。',64,'全唐诗/poet.tang.38000.json','["莫將時態破天真，祗合高歌醉過春。", "易落好花三箇月，難留浮世百年身。", "無金潤屋渾閑事，有酒扶頭是了人。", "恩地未酬閑未得，一迴醒話一沾巾。"]'),
('e585d3a7-dfca-488a-9ca5-5254c3ec9aab','長安春感','杜荀鶴','唐','唐诗','tang','','[]','出京無計住京難，深入東風轉索然。',64,'全唐诗/poet.tang.38000.json','["出京無計住京難，深入東風轉索然。", "滿眼有花寒食下，一家無信楚江邊。", "此時晴景愁於雨，是處鶯聲苦却蟬。", "公道算來終達去，更從今日望明年。"]'),
('cc24a36e-ffe7-4e95-b4ee-08f1bb7bae85','登靈山水閣貽釣者','杜荀鶴','唐','唐诗','tang','','[]','江上見僧誰是了，修齋補衲日勞身。',64,'全唐诗/poet.tang.38000.json','["江上見僧誰是了，修齋補衲日勞身。", "未勝漁父閑垂釣，獨背斜陽不采人。", "縱有風波猶得睡，總無蓑笠始爲貧。", "瓦瓶盛酒瓷甌酌，荻浦蘆灣是要津。"]'),
('50276b0b-69f4-4ff9-9eb2-1326ce4e7e07','贈溧水崔少府','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','庭戶蕭條燕雀喧，日高窗下枕書眠。',64,'全唐诗/poet.tang.38000.json','["庭戶蕭條燕雀喧，日高窗下枕書眠。", "祗聞留客教沽酒，未省逢人說料錢。", "洞口禮星披鶴氅，溪頭吟月上漁船。", "九華山叟心相許，不計官卑贈一篇。"]'),
('5675af1d-37a1-4dd0-8e7c-17cca3e32a38','讀張僕射詩','杜荀鶴','唐','唐诗','tang','','[]','秋吟一軸見心胷，萬象搜羅詠欲空。',64,'全唐诗/poet.tang.38000.json','["秋吟一軸見心胷，萬象搜羅詠欲空。", "才大却嫌天上桂，世危翻立陣前功。", "廉頗解武文無說，謝朓能文武不通。", "雙美總輸張太守，二南章句六鈞弓。"]'),
('3f2074a4-b3cb-491e-b491-3104db399ae8','題所居村舍','杜荀鶴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u793e\u4f1a", "\u63ed\u9732"]','家隨兵盡屋空存，稅額寧容減一分。',64,'全唐诗/poet.tang.38000.json','["家隨兵盡屋空存，稅額寧容減一分。", "衣食旋營猶可過，賦輸長急不堪聞。", "蠶無夏織桑充寨，田廢春耕犢勞軍。", "如此數州誰會得，殺民將盡更邀勳。"]'),
('5a3dc41c-9ddf-4592-a6e2-68467a791243','獻錢塘縣羅著作判官','杜荀鶴','唐','唐诗','tang','','[]','還鄉夫子遇賢侯，撫字情知不自由。',64,'全唐诗/poet.tang.38000.json','["還鄉夫子遇賢侯，撫字情知不自由。", "莫把一名專懊惱，放教雙眼絕冤讐。", "猩袍懶著辭公宴，鶴氅閑披訪道流。", "猶有九華知己在，羨君高臥早回頭。"]'),
('effa4b36-9b79-4e81-9c28-a7e9eca64252','遣懷','杜荀鶴','唐','唐诗','tang','','[]','驅馳岐路共營營，祗爲人間利與名。',64,'全唐诗/poet.tang.38000.json','["驅馳岐路共營營，祗爲人間利與名。", "紅杏園中終擬醉，白雲山下懶歸耕。", "題橋每念相如志，佩印當期季子榮。", "謾道彊親堪倚賴，到頭須是有前程。"]'),
('9fd994b0-b5d0-41b9-9259-03f292e81ebf','長安道中有作','杜荀鶴','唐','唐诗','tang','','[]','回頭不忍看羸僮，一路行人我最窮。',64,'全唐诗/poet.tang.38000.json','["回頭不忍看羸僮，一路行人我最窮。", "馬跡蹇於槐影裏，釣船拋在月明中。", "帽簷曉滴淋蟬露，衫袖時飄卷鴈風。", "子細尋思底模樣，騰騰又過玉關東。"]'),
('f23933d8-63a9-4ea4-8333-b72aecaf8c10','題開元寺門閤','杜荀鶴','唐','唐诗','tang','','[]','一登高閣眺清秋，滿目風光盡勝遊。',64,'全唐诗/poet.tang.38000.json','["一登高閣眺清秋，滿目風光盡勝遊。", "何處畫橈尋綠水，幾家鳴笛咽紅樓。", "雲山已老應長在，歲月如波祗暗流。", "唯有禪居離塵俗，了無榮辱挂心頭。"]'),
('695b68f0-cd07-4a67-aba0-bc8e9ac293cc','出關投孫侍御','杜荀鶴','唐','唐诗','tang','','[]','東歸還著舊麻衣，爭免花前有淚垂。',64,'全唐诗/poet.tang.38000.json','["東歸還著舊麻衣，爭免花前有淚垂。", "每歲春光九十日，一生年少幾多時。", "青雲寸祿心耕早，明月仙枝分種遲。", "不爲感恩酬未得，五湖閑作釣魚師。"]'),
('2e2a021b-82ff-4c1f-8189-cc89e1be27fd','送項山人歸天台','杜荀鶴','唐','唐诗','tang','','[]','因話天台歸思生，布囊藤杖笑離城。',64,'全唐诗/poet.tang.38000.json','["因話天台歸思生，布囊藤杖笑離城。", "不教日月拘身事，自與煙蘿結野情。", "龍鎮古潭雲色黑，露淋秋檜鶴聲清。", "此中是處堪終隱，何要世人知姓名。"]'),
('77500e84-6495-4f98-8f4f-ee135285ff4e','題衡陽隱士山居','杜荀鶴','唐','唐诗','tang','','[]','閑居不問世如何，雲起山門日已斜。',64,'全唐诗/poet.tang.38000.json','["閑居不問世如何，雲起山門日已斜。", "放鶴去尋三島客，任人來看四時花。", "松醪臘醞安神酒，布水宵煎覓句茶。", "畢竟金多也頭白，算來爭得似君家。"]'),
('0c068344-02d0-47d2-94e3-ad4176161a06','題江寺禪和','杜荀鶴','唐','唐诗','tang','','[]','江寺禪僧似悟禪，壞衣芒履住茅軒。',64,'全唐诗/poet.tang.38000.json','["江寺禪僧似悟禪，壞衣芒履住茅軒。", "懶求施主修真像，翻說經文是妄言。", "出浦釣船驚宿鴈，伐巖樵斧迸寒猿。", "行人莫問師宗旨，眼不浮華耳不喧。"]'),
('4ba532f9-953e-4d49-8d9b-7885ac626693','題弟姪書堂','杜荀鶴','唐','唐诗','tang','','["\u60dc\u65f6", "\u52c9\u52b1", "\u54f2\u7406"]','何事居窮道不窮，亂時還與靜時同。',64,'全唐诗/poet.tang.38000.json','["何事居窮道不窮，亂時還與靜時同。", "家山雖在干戈地，弟姪常修禮樂風。", "窗竹影搖書案上，野泉聲入硯池中。", "少年辛苦終身事，莫向光陰惰寸功。"]'),
('a8e5d970-11e1-430f-b6f3-00f0d375ab0c','和友人寄長林孟明府','杜荀鶴','唐','唐诗','tang','','[]','爲政爲人漸見心，長才聊屈宰長林。',64,'全唐诗/poet.tang.38000.json','["爲政爲人漸見心，長才聊屈宰長林。", "莫嫌月入無多俸，須喜秋來不廢吟。", "寒雨旋疎叢菊豔，晚風時動小松陰。", "訟庭閑寂公書少，留客看山索酒斟。"]'),
('36f96f38-d204-42b6-a4fc-d61f1564ec05','戲贈漁家','杜荀鶴','唐','唐诗','tang','','[]','見君生計羨君閑，求食求衣有底難。',64,'全唐诗/poet.tang.38000.json','["見君生計羨君閑，求食求衣有底難。", "養一箔蠶供釣線，種千莖竹作漁竿。", "葫蘆杓酌春濃酒，舴艋舟流夜漲灘。", "却笑農家最辛苦，聽蟬鞭馬入長安。"]'),
('6811f546-6a2f-486f-bdff-48f5985dbbdd','登城有作','杜荀鶴','唐','唐诗','tang','','[]','上得孤城向晚春，眼前何事不傷神。',64,'全唐诗/poet.tang.38000.json','["上得孤城向晚春，眼前何事不傷神。", "遍看原上纍纍塚，曾是城中汲汲人。", "盡謂黃金堪潤屋，誰思荒骨旋成塵。", "一名一宦平生事，不放愁侵易過身。"]'),
('1f8bdd1e-d25d-4336-bad8-8be2ae39d460','秋日山中寄池州李常侍','杜荀鶴','唐','唐诗','tang','','[]','近來參謁陡生疎，因向雲山僻處居。',64,'全唐诗/poet.tang.38000.json','["近來參謁陡生疎，因向雲山僻處居。", "出爲羈孤營糲食，歸同弟姪讀生書。", "風凋古木秋陰薄，月滿寒山夜景虛。", "但得中興知己在，算應身未老樵漁。"]'),
('1a727745-8f9b-45aa-ae55-ac55b702bd7e','辭楊侍郎','杜荀鶴','唐','唐诗','tang','','[]','春在門闌秋未離，不因人薦只因詩。',64,'全唐诗/poet.tang.38000.json','["春在門闌秋未離，不因人薦只因詩。", "半年賓館成前事，一日侯門失舊知。", "霜島樹凋猿叫夜，湖田穀熟鴈來時。", "西風萬里東歸去，更把愁心說向誰。"]'),
('659e3169-ef7d-44e6-8a80-64d8e0ea967b','題汪氏茅亭','杜荀鶴','唐','唐诗','tang','','[]','茅亭客到多稱奇，茅亭之上難題詩。',64,'全唐诗/poet.tang.38000.json','["茅亭客到多稱奇，茅亭之上難題詩。", "出塵景物不可狀，小手篇章徒爾爲。", "牛畔稻苗新雨後，鶴邊松韻晚風時。", "君今酷愛人間事，爭得安閑老在茲。"]'),
('f1a6adb6-78e9-4fc5-9178-f617f0ec4d03','喜從弟雪中遠至有作','杜荀鶴','唐','唐诗','tang','','[]','深山大雪懶開門，門逕行蹤自爾新。',64,'全唐诗/poet.tang.38000.json','["深山大雪懶開門，門逕行蹤自爾新。", "無酒禦寒雖寡況，有書供讀且資身。", "便均情愛同諸弟，莫更生疎似外人。", "晝短夜長須強學，學成貧亦勝他貧。"]'),
('50734116-bb9a-497a-aee8-b2e336452cfa','送僧歸國清寺','杜荀鶴','唐','唐诗','tang','','[]','吟送越僧歸海涯，僧行渾不覺程賒。',64,'全唐诗/poet.tang.38000.json','["吟送越僧歸海涯，僧行渾不覺程賒。", "路沿山脚潮痕出，睡倚松根日色斜。", "撼錫度岡猿抱樹，挈瓶盛浪鷺翹沙。", "到參禪後知無事，看引秋泉灌藕花。"]'),
('e7f7b63f-127d-450b-8a6f-60983091994a','題汪明府山居','杜荀鶴','唐','唐诗','tang','','[]','不似當官祗似閑，野情終日不離山。',64,'全唐诗/poet.tang.38000.json','["不似當官祗似閑，野情終日不離山。", "方知薄宦難拘束，多與高人作往還。", "牛笛漫吹煙雨裏，稻苗平入水雲間。", "羨君公退歸欹枕，免向他門厚客顏。"]'),
('245cf83d-1e26-4c1f-be2c-3468bea22734','下第東歸將及故園有作','杜荀鶴','唐','唐诗','tang','','[]','平生操立有天知，何事謀身與志違。',64,'全唐诗/poet.tang.38000.json','["平生操立有天知，何事謀身與志違。", "上國獻詩還不遇，故園經亂又空歸。", "山城欲暮人煙歛，江月初寒釣艇歸。", "且把風寒作閑事，懶能和淚拜庭闈。"]'),
('49cbcec7-9263-4b13-aba6-5e02a3d30f67','宿東林寺題願公院','杜荀鶴','唐','唐诗','tang','','[]','古寺沈沈僧未眠，搘頤將客說閑緣。',64,'全唐诗/poet.tang.38000.json','["古寺沈沈僧未眠，搘頤將客說閑緣。", "一溪月色非塵世，滿洞松聲似雨天。", "簷底水涵抄律燭，窗間風引煮茶煙。", "無由住得吟相伴，心繫青雲十五年。"]'),
('f0f45cf5-fdf4-4e41-a2cb-84b0c39502db','山居自遣','杜荀鶴','唐','唐诗','tang','','[]','茅屋周回松竹陰，山翁時挈酒相尋。',64,'全唐诗/poet.tang.38000.json','["茅屋周回松竹陰，山翁時挈酒相尋。", "無人開口不言利，只我白頭空愛吟。", "月在釣潭秋睡重，雲橫樵逕野情深。", "此中一日過一日，有底閑愁得到心。"]'),
('bae4f365-d38f-4e7d-bcf5-6bf716bbdab9','贈友人罷舉赴辟命','杜荀鶴','唐','唐诗','tang','','[]','連天一水浸吳東，十幅帆飛二月風。',64,'全唐诗/poet.tang.38000.json','["連天一水浸吳東，十幅帆飛二月風。", "好景採拋詩句裏，別愁驅入酒杯中。", "漁依岸柳眠圓影，鳥傍嵒花戲暖紅。", "不是桂枝終不得，自緣年少好從戎。"]'),
('02e873a1-5052-4011-9e9b-f59e24b5de39','亂後旅中遇友人','杜荀鶴','唐','唐诗','tang','','[]','念子爲儒道未亨，依依心向十年兄。',64,'全唐诗/poet.tang.38000.json','["念子爲儒道未亨，依依心向十年兄。", "莫依亂世輕依託，須學前賢隱姓名。", "大國未知何日靜，舊山猶可入雲耕。", "不如自此同歸去，帆挂秋風一信程。"]'),
('0dc69395-9fd5-4a46-9e2a-7fb865596625','贈休糧僧','杜荀鶴','唐','唐诗','tang','','[]','自言因病學休糧，本意非求不死方。',64,'全唐诗/poet.tang.38000.json','["自言因病學休糧，本意非求不死方。", "徒有至人傳道術，更無齋客到禪房。", "雨中林鳥歸巢晚，霜後嵒猨拾橡忙。", "爭似吾師無一事，穩披雲衲坐藤牀。"]'),
('092610c9-e27a-42db-8778-63c81c699876','維揚春日再遇孫侍御','杜荀鶴','唐','唐诗','tang','','[]','本爲榮家不爲身，讀書誰料轉家貧。',64,'全唐诗/poet.tang.38000.json','["本爲榮家不爲身，讀書誰料轉家貧。", "三年行却千山路，兩地思歸一主人。", "絡岸柳絲懸細雨，繡田花朵弄殘春。", "多情御史應嗟見，未上青雲白髮新。"]'),
('572fd0d1-9717-4015-9710-cdeb7c4e673d','亂後宿南陵廢寺寄沈明府','杜荀鶴','唐','唐诗','tang','','[]','祗共寒燈坐到明，塞鴻衝雪一聲聲。',64,'全唐诗/poet.tang.38000.json','["祗共寒燈坐到明，塞鴻衝雪一聲聲。", "亂時爲客無人識，廢寺吟詩有鬼驚。", "且把酒杯添志氣，已將身事託公卿。", "男兒仗劒酬恩在，未肯徒然過一生。"]'),
('26df26fc-92f0-41e8-9b67-eb36fe04afa2','投鄭先輩','杜荀鶴','唐','唐诗','tang','','[]','匣中長劒未酬恩，不遇男兒不合論。',64,'全唐诗/poet.tang.38000.json','["匣中長劒未酬恩，不遇男兒不合論。", "悶向酒杯吞日月，閑將詩句問乾坤。", "寧辭馬足勞關路，肯爲漁竿憶水村。", "兩鬢欲斑三百首，更教裝寫傍誰門。"]'),
('10d6075d-503e-4883-91b5-966156361446','途中有作','杜荀鶴','唐','唐诗','tang','','[]','無論南北與西東，名利牽人處處同。',64,'全唐诗/poet.tang.38000.json','["無論南北與西東，名利牽人處處同。", "枕上事仍多馬上，山中心更甚關中。", "川原晚結陰沈氣，草樹秋生索漠風。", "百歲此身如且健，大家閑作臥雲翁。"]'),
('483caed2-d0d4-4052-a452-5f19058ede17','和舍弟題書堂','杜荀鶴','唐','唐诗','tang','','[]','兄弟將知大自強，亂時同葺讀書堂。',64,'全唐诗/poet.tang.38000.json','["兄弟將知大自強，亂時同葺讀書堂。", "嵒泉遇雨多還鬧，溪竹唯風少即涼。", "藉草醉吟花片落，傍山閑步藥苗香。", "團圓便是家肥事，何必盈倉與滿箱。"]'),
('581313cd-a67a-4e42-8405-24bad3c1b56f','送蜀客遊維揚','杜荀鶴','唐','唐诗','tang','','[]','見說西川景物繁，維揚景物勝西川。',64,'全唐诗/poet.tang.38000.json','["見說西川景物繁，維揚景物勝西川。", "青春花柳樹臨水，白日綺羅人上船。", "夾岸畫樓難惜醉，數橋明月不教眠。", "送君嬾問君回日，才子風流正少年。"]'),
('1e334c10-1d22-47cc-bd8c-3a8f7b528e4c','旅寓','杜荀鶴','唐','唐诗','tang','','[]','暗筭鄉程隔數州，欲歸無計淚空流。',64,'全唐诗/poet.tang.38000.json','["暗筭鄉程隔數州，欲歸無計淚空流。", "已違骨肉來時約，更束琴書何處遊。", "畫角引風吹斷夢，垂楊和雨結成愁。", "去年今日還如此，似與青春有舊讐。"]'),
('41c55f68-d3ad-495b-966a-8dc8f5aed343','途中春','杜荀鶴','唐','唐诗','tang','','[]','年光身事旋成空，畢竟何門遇至公。',64,'全唐诗/poet.tang.38000.json','["年光身事旋成空，畢竟何門遇至公。", "人世鶴歸雙鬢上，客程蛇遶亂山中。", "牧童向日眠春草，漁父隈巖避晚風。", "一醉未醒花又落，故鄉回首楚關東。"]'),
('ad847d61-66cb-4901-8dab-6dfb798048a6','維揚冬末寄幕中二從事','杜荀鶴','唐','唐诗','tang','','["\u601d\u4e61", "\u51ac\u5929"]','江上數株桑棗樹，自從離亂更荒涼。',64,'全唐诗/poet.tang.38000.json','["江上數株桑棗樹，自從離亂更荒涼。", "那堪旅館經殘臘，祗把空書寄故鄉。", "典盡客衣三尺雪，鍊精詩句一頭霜。", "故人多在芙蓉幕，應笑孜孜道未光。"]'),
('d55597f5-fad7-459e-9b0a-a12e1fff6e88','辭鄭員外入關','杜荀鶴','唐','唐诗','tang','','[]','男兒三十尚蹉跎，未遂青雲一桂科。',64,'全唐诗/poet.tang.38000.json','["男兒三十尚蹉跎，未遂青雲一桂科。", "在客易爲銷歲月，到家難住似經過。", "帆飛楚國風濤潤，馬度藍關雨雪多。", "長把行藏信天道，不知天道竟如何。"]'),
('bed76586-a845-455c-aa6b-6d96d3a6c489','書齋即事','杜荀鶴','唐','唐诗','tang','','[]','時清祗合力爲儒，不可家貧與善疎。',64,'全唐诗/poet.tang.38000.json','["時清祗合力爲儒，不可家貧與善疎。", "賣却屋邊三畝地，添成窗下一牀書。", "沿溪摘果霜晴後，出竹吟詩月上初。", "鄉里老農多見笑，不知稽古勝耕鋤。"]'),
('57a01fbb-f85a-415a-824e-b2210c455f3f','雋陽道中','杜荀鶴','唐','唐诗','tang','','[]','客路客路何悠悠，蟬聲向背槐花愁。',64,'全唐诗/poet.tang.38000.json','["客路客路何悠悠，蟬聲向背槐花愁。", "爭知百歲不百歲，未合白頭今白頭。", "四五朵山妝雨色，兩三行鴈帖雲秋。", "輸他江上垂綸者，祗在船中老便休。"]'),
('8fcf54f6-1a27-4e76-a58e-a50d59055c4c','入關因別舍弟','杜荀鶴','唐','唐诗','tang','','[]','吾今別汝汝聽言，去住人情足可安。',64,'全唐诗/poet.tang.38000.json','["吾今別汝汝聽言，去住人情足可安。", "百口度荒均食易，數年經亂保家難。", "莫愁寒族無人薦，但願春官把卷看。", "天道不欺心意是，帝鄉吾土一般般。"]'),
('a7ec905b-272d-4c09-a5ab-1fadb2ea9d19','贈彭蠡釣者','杜荀鶴','唐','唐诗','tang','','[]','偏坐漁舟出葦林，葦花零落向秋深。',64,'全唐诗/poet.tang.38000.json','["偏坐漁舟出葦林，葦花零落向秋深。", "祗將波上鷗爲侶，不把人間事繫心。", "傍岸歌來風欲起，卷絲眠去月初沈。", "若教我似君閑放，贏得湖山到老吟。"]'),
('6a61ac93-4a2e-462f-953b-0ae293cb2ab7','送友人入關','杜荀鶴','唐','唐诗','tang','','[]','此去青雲莫更疑，出人才行足人知。',64,'全唐诗/poet.tang.38000.json','["此去青雲莫更疑，出人才行足人知。", "況當朝野搜賢日，正是孤寒取士時。", "仙島煙霞通鶴信，早春雷雨與龍期。", "我今不得同君去，兩鬢霜欺桂一枝。"]'),
('1a2675f1-be4d-4de3-9442-86dbc8a8b2a2','送友人宰潯陽','杜荀鶴','唐','唐诗','tang','','[]','高興那言去路長，非君不解愛潯陽。',64,'全唐诗/poet.tang.38000.json','["高興那言去路長，非君不解愛潯陽。", "有時猨鳥來公署，到處煙霞是道鄉。", "釣艇滿江魚賤菜，紙窯連嶽楮多桑。", "陶潛舊隱依稀在，好繼高蹤結草堂。"]'),
('48242f24-a894-4c18-bb15-f150aab6dcbd','秋日臥病','杜荀鶴','唐','唐诗','tang','','[]','浮世浮名能幾何，致身流落向天涯。',64,'全唐诗/poet.tang.38000.json','["浮世浮名能幾何，致身流落向天涯。", "少年心壯輕爲客，一日病來思在家。", "山頂老猨啼古木，渡頭新鴈下平沙。", "不堪吟罷西風起，黃葉滿庭寒日斜。"]'),
('515e884a-6fe0-4919-81a9-ac1725a8b490','敘吟','杜荀鶴','唐','唐诗','tang','','[]','多慙到處有詩名，轉覺吟詩僻性成。',64,'全唐诗/poet.tang.38000.json','["多慙到處有詩名，轉覺吟詩僻性成。", "度水却嫌船著岸，過山翻恨馬貪程。", "如讐雪月年年景，似夢笙歌處處聲。", "未合白頭今已白，自知非爲別愁生。"]'),
('59b6a8a9-11bf-4970-80a6-908d0a1c5220','行次滎陽却寄諸弟','杜荀鶴','唐','唐诗','tang','','[]','難把歸書說遠情，奉親多闕拙爲兄。',64,'全唐诗/poet.tang.38000.json','["難把歸書說遠情，奉親多闕拙爲兄。", "早知寸祿榮家晚，悔不深山共汝耕。", "枕上算程關月落，帽前搜景嶽雲生。", "如今已作長安計，祗得辛勤取一名。"]'),
('4692469a-f711-4707-ab80-f315da4a1280','登石壁禪師水閣有作','杜荀鶴','唐','唐诗','tang','','[]','石壁早聞僧說好，今來偏與我相宜。',64,'全唐诗/poet.tang.38000.json','["石壁早聞僧說好，今來偏與我相宜。", "有山有水堪吟處，無雨無風見景時。", "漁父晚船分浦釣，牧童寒笛倚牛吹。", "畫人畫得從他畫，六幅應輸八句詩。"]'),
('a1a8ed98-3334-4145-aa6e-405db50b38bc','贈袒肩和尚','杜荀鶴','唐','唐诗','tang','','[]','山衣草屐染莓苔，雙眼猶慵向俗開。',64,'全唐诗/poet.tang.38000.json','["山衣草屐染莓苔，雙眼猶慵向俗開。", "若比吾師居世上，何如野客臥嵒隈。", "才聞錫杖離三楚，又說隨緣向五臺。", "乘醉吟詩問禪理，爲誰須去爲誰來。"]'),
('08346b38-91b9-4807-980d-3695f7b636eb','閑居即事','杜荀鶴','唐','唐诗','tang','','[]','形覺清羸道覺肥，竹門前徑靜相宜。',64,'全唐诗/poet.tang.38000.json','["形覺清羸道覺肥，竹門前徑靜相宜。", "一壺村酒無求處，數朵庭花見落時。", "章句偶爲前輩許，話言多被俗人疑。", "一枝仙桂如攀得，祗此山前是老期。"]'),
('7469d1af-167b-41af-abc3-eddb8596bf16','自敘','杜荀鶴','唐','唐诗','tang','','[]','酒甕琴書伴病身，熟諳時事樂於貧。',64,'全唐诗/poet.tang.38000.json','["酒甕琴書伴病身，熟諳時事樂於貧。", "寧爲宇宙閑吟客，怕作乾坤竊祿人。", "詩旨未能忘救物，世情奈值不容真。", "平生肺腑無言處，白髮吾唐一逸人。"]'),
('8f98526e-d0e0-41c1-a42b-13cac9ed79e0','空閑二公遞以禪律相鄙因而解之','杜荀鶴','唐','唐诗','tang','','[]','一教誰云闢二途，律禪禪律智歸愚。',64,'全唐诗/poet.tang.38000.json','["一教誰云闢二途，律禪禪律智歸愚。", "念珠在手隳禪衲，禪衲披肩壞念珠。", "象外空分空外象，無中有作有中無。", "有無無有師窮取，山到平來海亦枯。"]'),
('d5cac4e1-2599-4ee6-8409-43026970d22b','寄溫州朱尚書幷呈軍倅崔太傅','杜荀鶴','唐','唐诗','tang','','[]','永嘉名郡昔推名，連屬荀家弟與兄。',64,'全唐诗/poet.tang.38000.json','["永嘉名郡昔推名，連屬荀家弟與兄。", "教化靜師龔渤海，篇章高體謝宣城。", "山從海岸妝吟景，水自城根演政聲。", "今日老輸崔博士，不妨疎逸伴雙旌。"]'),
('c4d9db46-0b2d-4ae8-928a-5ce636298763','恩門致書遠及山居因獻之','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','時難轉覺保身難，難向師門欲繼顏。',64,'全唐诗/poet.tang.38000.json','["時難轉覺保身難，難向師門欲繼顏。", "若把白衣輕易脫，却成青桂偶然攀。", "身居劒戟爭雄地，道在乾坤未喪間。", "必許酬恩酬未晚，且須容到九華山。"]'),
('e136415d-62b4-4912-a5b0-b858bb91f8ab','寄溫州崔博士','杜荀鶴','唐','唐诗','tang','','[]','懷君勞我寫詩情，窣窣陰風有鬼聽。',64,'全唐诗/poet.tang.38000.json','["懷君勞我寫詩情，窣窣陰風有鬼聽。", "縣宰不仁工部餓，酒家無識翰林醒。", "眼昏經史天何在，心盡英雄國未寧。", "好向賢侯話吟侶，莫教辜負少微星。"]'),
('4dc66959-5056-440f-9810-a15c3f4448cc','李昭象云與二三同人見訪有寄','杜荀鶴','唐','唐诗','tang','','[]','得君書後病顏開，云拉同人訪我來。',64,'全唐诗/poet.tang.38000.json','["得君書後病顏開，云拉同人訪我來。", "在路不妨衝雨雪，到山還免踏塵埃。", "吟沈水閣何宵月，坐破松巖幾處苔。", "貧舍款賓無別物，止於空戰大尊罍。"]'),
('9a5a4c58-11f3-4cbd-af80-5dbebf7a9016','自江西歸九華','杜荀鶴','唐','唐诗','tang','','[]','他鄉終日憶吾鄉，及到吾鄉值亂荒。',64,'全唐诗/poet.tang.38000.json','["他鄉終日憶吾鄉，及到吾鄉值亂荒。", "雲外好山看不見，馬頭歧路去何忙。", "無衣織女桑猶小，闕食農夫麥未黃。", "許大乾坤吟未了，揮鞭回首出陵陽。"]'),
('5e984b06-dfc7-4d20-8afe-e91ae02ab932','和友人見題山居水閣八韻','杜荀鶴','唐','唐诗','tang','','[]','池閣初成眼豁開，眼前霽景屬微才。',128,'全唐诗/poet.tang.38000.json','["池閣初成眼豁開，眼前霽景屬微才。", "試攀簷果猨先見，纔把漁竿鶴即來。", "修竹已多猶可種，豔花雖少不勞栽。", "南昌一榻延徐孺，楚國千鍾逼老萊。", "未稱執鞭奔紫陌，惟宜策杖步蒼苔。", "籠禽豈是摩霄翼，潤木元非澗下材。", "鑒己每將天作鏡，陶情常以海爲杯。", "和君詩句吟聲大，蟲豸聞之謂蟄雷。"]'),
('69cb80d3-e99c-4cbe-9247-127a06766fef','感寓','杜荀鶴','唐','唐诗','tang','','[]','大海波濤淺，小人方寸深。',24,'全唐诗/poet.tang.38000.json','["大海波濤淺，小人方寸深。", "海枯終見底，人死不知心。"]'),
('66dba053-99b0-4bbe-b793-96e76e53bea9','春閨怨','杜荀鶴','唐','唐诗','tang','','[]','朝喜花豔春，暮悲花委塵。',24,'全唐诗/poet.tang.38000.json','["朝喜花豔春，暮悲花委塵。", "不悲花落早，悲妾似花身。"]'),
('e626ff19-7f8a-4613-947e-2b327faba257','馬上行','杜荀鶴','唐','唐诗','tang','','[]','五里復五里，去時無住時。',24,'全唐诗/poet.tang.38000.json','["五里復五里，去時無住時。", "日將家漸遠，猶恨馬行遲。"]'),
('f01a63c0-533e-4060-b10f-1c0e5b40b465','釣叟','杜荀鶴','唐','唐诗','tang','','[]','茅屋深灣裏，釣船橫竹門。',24,'全唐诗/poet.tang.38000.json','["茅屋深灣裏，釣船橫竹門。", "經營衣食外，猶得弄兒孫。"]'),
('90909ca8-cc8f-46ed-a957-e3f46a038640','再經胡城縣','杜荀鶴','唐','唐诗','tang','','[]','去歲曾經此縣城，縣民無口不冤聲。',32,'全唐诗/poet.tang.38000.json','["去歲曾經此縣城，縣民無口不冤聲。", "今來縣宰加朱紱，便是生靈血染成。"]'),
('28ad4845-cccc-46d5-98f1-f8f3d931bc1c','讀諸家詩','杜荀鶴','唐','唐诗','tang','','[]','辭賦文章能者稀，難中難者莫過詩。',32,'全唐诗/poet.tang.38000.json','["辭賦文章能者稀，難中難者莫過詩。", "直應吟骨無生死，祗我前身是阿誰。"]'),
('741b4d85-9368-45f5-aef3-c4443e822ec2','春來燕','杜荀鶴','唐','唐诗','tang','','[]','我屋汝嫌低不住，雕梁畫閣也知寬。',32,'全唐诗/poet.tang.38000.json','["我屋汝嫌低不住，雕梁畫閣也知寬。", "大須穩擇安巢處，莫道巢成却不安。"]'),
('17d9c123-e0c6-4d1d-8271-27b233f84f8f','清溪來明府出二子請詩因遺一絕','杜荀鶴','唐','唐诗','tang','','[]','珠明玉潤盡驚人，不稱寒門不稱貧。',32,'全唐诗/poet.tang.38000.json','["珠明玉潤盡驚人，不稱寒門不稱貧。", "若向吾唐作雙瑞，便同祥鳳與祥麟。"]'),
('ac39de3d-058c-41bb-8198-8e3d71cdb5f3','哭陳陶','杜荀鶴','唐','唐诗','tang','','[]','耒陽山下傷工部，采石江邊弔翰林。',32,'全唐诗/poet.tang.38000.json','["耒陽山下傷工部，采石江邊弔翰林。", "兩地荒墳各三尺，却成開解哭君心。"]'),
('5ceb248e-be94-4408-891d-0cebb51f1994','哭貝韜','杜荀鶴','唐','唐诗','tang','','[]','交朋來哭我來歌，喜傍山家葬荔蘿。',32,'全唐诗/poet.tang.38000.json','["交朋來哭我來歌，喜傍山家葬荔蘿。", "四海十年人殺盡，似君埋少不埋多。"]'),
('8a42a500-d24a-4e44-9504-dda41d890b42','蠶婦','杜荀鶴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5987\u5973", "\u8bbd\u523a"]','粉色全無飢色加，豈知人世有榮華。',32,'全唐诗/poet.tang.38000.json','["粉色全無飢色加，豈知人世有榮華。", "年年道我蠶辛苦，底事渾身着苧麻。"]'),
('4380c071-6a60-4097-bb05-4740593e57b9','山寺老僧','杜荀鶴','唐','唐诗','tang','','[]','草靸無塵心地閑，靜隨猿鳥過寒暄。',32,'全唐诗/poet.tang.38000.json','["草靸無塵心地閑，靜隨猿鳥過寒暄。", "眼昏齒落看經遍，却向僧中總不言。"]'),
('cde7e297-13d9-4606-b002-18035d482cac','閩中秋思','杜荀鶴','唐','唐诗','tang','','["\u601d\u4e61"]','雨勻紫菊叢叢色，風弄紅蕉葉葉聲。',32,'全唐诗/poet.tang.38000.json','["雨勻紫菊叢叢色，風弄紅蕉葉葉聲。", "北畔是山南畔海，祗堪圖畫不堪行。"]'),
('d40d1b44-ef68-4070-8cc4-a7a7c08c8ef7','八駿圖','杜荀鶴','唐','唐诗','tang','','[]','丹雘傳真未得真，那知筋骨與精神。',32,'全唐诗/poet.tang.38000.json','["丹雘傳真未得真，那知筋骨與精神。", "祗今恃駿憑毛色，綠耳驊騮賺殺人。"]'),
('abd386e7-8775-4570-bf2b-980d94c3754d','贈僧','杜荀鶴','唐','唐诗','tang','','[]','利門名路兩何憑，百歲風前短焰燈。',32,'全唐诗/poet.tang.38000.json','["利門名路兩何憑，百歲風前短焰燈。", "祗恐爲僧僧不了，爲僧得了總輸僧。"]'),
('7398c0a8-32e9-4e88-8f9f-a04d7691a889','秋夕','杜荀鶴','唐','唐诗','tang','','[]','世間多少能詩客，誰是無愁得睡人。',32,'全唐诗/poet.tang.38000.json','["世間多少能詩客，誰是無愁得睡人。", "自我夜來霜月下，到頭吟魄始終身。"]'),
('030c5b3a-c6c1-4aa9-83e3-134d1afb40f4','溪興','杜荀鶴','唐','唐诗','tang','','["\u6292\u60c5", "\u95f2\u9002", "\u9690\u5c45"]','山雨溪風卷釣絲，瓦甌篷底獨斟時。',32,'全唐诗/poet.tang.38000.json','["山雨溪風卷釣絲，瓦甌篷底獨斟時。", "醉來睡着無人喚，流下前溪也不知。"]'),
('f3507c4e-c1f1-4236-afb7-5b2b3e035003','過巢湖','杜荀鶴','唐','唐诗','tang','','[]','世人貪利復貪榮，來向湖邊始至誠。',32,'全唐诗/poet.tang.38000.json','["世人貪利復貪榮，來向湖邊始至誠。", "男子登舟與登陸，把心何不一般行。"]'),
('89fce731-7332-4d99-b3fa-e217173fb677','傷硤石縣病叟','杜荀鶴','唐','唐诗','tang','','[]','無子無孫一病翁，將何筋力事耕農。',32,'全唐诗/poet.tang.38000.json','["無子無孫一病翁，將何筋力事耕農。", "官家不管蓬蒿地，須勒王租出此中。"]'),
('3e2072af-1025-484a-85f7-3113c035928c','贈老僧','杜荀鶴','唐','唐诗','tang','','[]','童子爲僧今白首，暗鋤心地種閑情。',32,'全唐诗/poet.tang.38000.json','["童子爲僧今白首，暗鋤心地種閑情。", "時將舊衲添新線，披坐披行過一生。"]'),
('a9075579-94ee-4a22-9e90-c5191e89ef9b','釣叟','杜荀鶴','唐','唐诗','tang','','[]','田不曾耕地不鋤，誰人閑散得如渠。',32,'全唐诗/poet.tang.38000.json','["田不曾耕地不鋤，誰人閑散得如渠。", "渠將底物爲香餌，一度擡竿一箇魚。"]'),
('228ca668-391c-40a4-9919-d6d6df8243e0','溪岸秋思','杜荀鶴','唐','唐诗','tang','','[]','桑柘窮頭三四家，挂罾垂釣是生涯。',32,'全唐诗/poet.tang.38000.json','["桑柘窮頭三四家，挂罾垂釣是生涯。", "秋風忽起溪灘白，零落岸邊蘆荻花。"]'),
('1f2929f2-66cb-495a-9fad-be3e6d71bea0','春日旅寓','杜荀鶴','唐','唐诗','tang','','[]','滿城羅綺拖春色，幾處笙歌揭畫樓。',32,'全唐诗/poet.tang.38000.json','["滿城羅綺拖春色，幾處笙歌揭畫樓。", "江上有家歸未得，眼前花是眼前愁。"]'),
('f4a2847c-eb33-459f-bf49-99298c6bfbd1','田翁','杜荀鶴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bbd\u523a"]','白髮星星筋力衰，種田猶自伴孫兒。',32,'全唐诗/poet.tang.38000.json','["白髮星星筋力衰，種田猶自伴孫兒。", "官苗若不平平納，任是豐年也受飢。"]'),
('2f34f94b-db63-41bf-9671-0fbf98a2515c','秋江雨夜逢詩友','杜荀鶴','唐','唐诗','tang','','[]','故友別來三四載，新詩吟得百餘篇。',32,'全唐诗/poet.tang.38000.json','["故友別來三四載，新詩吟得百餘篇。", "夜來江上秋無月，恨不相逢在雪天。"]'),
('037ea122-96cd-42ac-bd71-0126010990d7','感春','杜荀鶴','唐','唐诗','tang','','[]','無況青雲有恨身，眼前花似夢中春。',32,'全唐诗/poet.tang.38000.json','["無況青雲有恨身，眼前花似夢中春。", "浮生七十今三十，已是人間半世人。"]'),
('bad8dc85-f0d8-4e36-8d2c-83e672f6628c','題花木障','杜荀鶴','唐','唐诗','tang','','[]','不假東風次第吹，筆勻春色一枝枝。',32,'全唐诗/poet.tang.38000.json','["不假東風次第吹，筆勻春色一枝枝。", "由來畫看勝栽看，免見朝開暮落時。"]'),
('a1271361-814a-4e11-bbec-f09c98c6dce5','顧雲侍御出二子請詩因遺一絕','杜荀鶴','唐','唐诗','tang','','[]','二雛毛骨秀仍奇，小小能吟大大詩。',32,'全唐诗/poet.tang.38000.json','["二雛毛骨秀仍奇，小小能吟大大詩。", "想得月中仙桂樹，各從生日長新枝。"]'),
('b9c00499-fd83-4d4f-8441-f0fc0fcefae7','秋夕病中','杜荀鶴','唐','唐诗','tang','','[]','壞屋不眠風雨夜，故園無信水雲秋。',32,'全唐诗/poet.tang.38000.json','["壞屋不眠風雨夜，故園無信水雲秋。", "病中枕上誰相問，一一蟬聲槐樹頭。"]'),
('bc6f3625-97b5-47d2-8ba8-69b278ae6dfd','宿欒城驛却寄常山張書記','杜荀鶴','唐','唐诗','tang','','[]','一更更盡到三更，吟破離心句不成。',32,'全唐诗/poet.tang.38000.json','["一更更盡到三更，吟破離心句不成。", "數樹秋風滿庭月，憶君時復下堦行。"]'),
('ddf6a309-913c-4b82-b919-652f7967622a','湘江秋夕','杜荀鶴','唐','唐诗','tang','','[]','三湘月色三湘水，浸骨寒光似練鋪。',32,'全唐诗/poet.tang.38000.json','["三湘月色三湘水，浸骨寒光似練鋪。", "一夜寒鴻來不住，故鄉書信半年無。"]'),
('f6c169fd-4227-4b07-9a09-45452e063aa6','旅懷','杜荀鶴','唐','唐诗','tang','','[]','蒹葭月冷時聞鴈，楊柳風和日聽鶯。',32,'全唐诗/poet.tang.38000.json','["蒹葭月冷時聞鴈，楊柳風和日聽鶯。", "水涉山行二年客，就中偏怕雨船聲。"]'),
('e2b57898-e523-401c-b48d-5461e7b6efb8','贈崔道士','杜荀鶴','唐','唐诗','tang','','[]','四海兵戈無靜處，人家廢業望烽煙。',32,'全唐诗/poet.tang.38000.json','["四海兵戈無靜處，人家廢業望烽煙。", "九華道士渾如夢，猶向尊前笑揭天。"]'),
('c4c1cb09-c9a8-402a-b9e4-043b163c0907','題道林寺','杜荀鶴','唐','唐诗','tang','','[]','身未立間終日苦，身當立後幾年榮。',32,'全唐诗/poet.tang.38000.json','["身未立間終日苦，身當立後幾年榮。", "萬般不及僧無事，共水將山過一生。"]'),
('770e1f7b-75a1-43ee-ba52-e9ba5e205058','贈質上人','杜荀鶴','唐','唐诗','tang','','["\u8d60\u8a00", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','枿坐雲遊出世塵，兼無缾鉢可隨身。',32,'全唐诗/poet.tang.38000.json','["枿坐雲遊出世塵，兼無缾鉢可隨身。", "逢人不說人間事，便是人間無事人。"]'),
('5f4c9bbd-6eb6-4331-a09e-1ae4a1320861','涇溪','杜荀鶴','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u54f2\u7406", "\u5199\u6c34"]','涇溪石險人兢慎，終歲不聞傾覆人。',32,'全唐诗/poet.tang.38000.json','["涇溪石險人兢慎，終歲不聞傾覆人。", "却是平流無石處，時時聞說有沈淪。"]'),
('ae11534e-cbe1-49b2-b0b6-a0e6c01959ee','夏日題悟空上人院','杜荀鶴','唐','唐诗','tang','','[]','三伏閉門披一衲，兼無松竹蔭房廊。',32,'全唐诗/poet.tang.38000.json','["三伏閉門披一衲，兼無松竹蔭房廊。", "安禪不必須山水，滅得心中火自涼。"]'),
('e8a0731b-afba-45d0-8c31-29c8c8d053a3','經嚴陵釣臺','杜荀鶴','唐','唐诗','tang','','[]','蒼翠雲峰開俗眼，泓澄煙水浸塵心。',32,'全唐诗/poet.tang.38000.json','["蒼翠雲峰開俗眼，泓澄煙水浸塵心。", "唯將道業爲芳餌，釣得高名直至今。"]'),
('f8737efb-017c-480d-bf8e-577bb0bf346b','關試後筵上別同人','杜荀鶴','唐','唐诗','tang','','[]','日午離筵到夕陽，明朝秦地與吳鄉。',32,'全唐诗/poet.tang.39000.json','["日午離筵到夕陽，明朝秦地與吳鄉。", "同年多是長安客，不信行人欲斷腸。"]'),
('a03ae25b-86b5-4db5-af26-1e8d90eaf9bb','鸕鷀','杜荀鶴','唐','唐诗','tang','','[]','一般毛羽結羣飛，雨岸煙汀好景時。',32,'全唐诗/poet.tang.39000.json','["一般毛羽結羣飛，雨岸煙汀好景時。", "深水有魚銜得出，看來却是鷺鶿飢。"]'),
('46f2a563-fff3-4887-972b-242f290f90cb','宿村舍','杜荀鶴','唐','唐诗','tang','','[]','野人於我有何情，半掩柴門向月明。',32,'全唐诗/poet.tang.39000.json','["野人於我有何情，半掩柴門向月明。", "深夜欲眠眠未著，一叢寒木一猿聲。"]'),
('cd6efb88-60d1-4e01-9162-edf752da85b2','題新鴈','杜荀鶴','唐','唐诗','tang','','[]','暮天新鴈起汀洲，紅蓼花疎水國秋。',32,'全唐诗/poet.tang.39000.json','["暮天新鴈起汀洲，紅蓼花疎水國秋。", "想得故園今夜月，幾人相憶在江樓。"]'),
('12d26073-60b4-44e7-8d1f-22d156334d2b','離家','杜荀鶴','唐','唐诗','tang','','[]','丈夫三十身如此，疲馬離鄉懶著鞭。',32,'全唐诗/poet.tang.39000.json','["丈夫三十身如此，疲馬離鄉懶著鞭。", "槐柳路長愁殺我，一枝蟬到一枝蟬。"]'),
('d9f777e7-e16e-4459-9ede-42b8ae1d82e4','旅舍遇雨','杜荀鶴','唐','唐诗','tang','','[]','月華星彩坐來收，嶽色江聲暗結愁。',32,'全唐诗/poet.tang.39000.json','["月華星彩坐來收，嶽色江聲暗結愁。", "半夜燈前十年事，一時和雨到心頭。"]'),
('3563aa31-ab93-42b9-a430-d762a9d40423','送人歸淝上','杜荀鶴','唐','唐诗','tang','','[]','巢湖春漲喻溪深，纔過東關見故林。',32,'全唐诗/poet.tang.39000.json','["巢湖春漲喻溪深，纔過東關見故林。", "莫道南來總無利，水亭山寺二年吟。"]'),
('03b96410-b1e6-4863-be0e-4cebb2e2a8e6','自遣','杜荀鶴','唐','唐诗','tang','','[]','糲食麤衣隨分過，堆金積帛欲如何。',32,'全唐诗/poet.tang.39000.json','["糲食麤衣隨分過，堆金積帛欲如何。", "百年身後一丘土，貧富高低爭幾多。"]'),
('55157217-07e9-464e-9bb9-f940998cf5cd','聞子規','杜荀鶴','唐','唐诗','tang','','[]','楚天空闊月成輪，蜀魄聲聲似告人。',32,'全唐诗/poet.tang.39000.json','["楚天空闊月成輪，蜀魄聲聲似告人。", "啼得血流無用處，不如緘口過殘春。"]'),
('10220ed5-bb62-4755-b379-5daf6a1a16a7','秋夜苦吟','杜荀鶴','唐','唐诗','tang','','[]','吟盡三更未著題，竹風松雨共淒淒。',32,'全唐诗/poet.tang.39000.json','["吟盡三更未著題，竹風松雨共淒淒。", "此時若有人來聽，始覺巴猿不解啼。"]'),
('294c43b3-61e0-4c83-adf0-af85ca690bbc','秋夜聞砧','杜荀鶴','唐','唐诗','tang','','[]','荒涼客舍眠秋色，砧杵家家弄月明。',32,'全唐诗/poet.tang.39000.json','["荒涼客舍眠秋色，砧杵家家弄月明。", "不及巴山聽猿夜，三聲中有不愁聲。"]'),
('64c879a7-b7d2-48ed-a466-4f99196c15b0','將過湖南經馬當山廟因書三絕 一','杜荀鶴','唐','唐诗','tang','','[]','人說馬當波浪險，我經波浪似通衢。',32,'全唐诗/poet.tang.39000.json','["人說馬當波浪險，我經波浪似通衢。", "大凡君子行藏是，自有龍神衛過湖。"]'),
('c3860cd0-89e6-4720-afca-759b22203445','將過湖南經馬當山廟因書三絕 二','杜荀鶴','唐','唐诗','tang','','[]','貪殘官吏虔誠謁，毒害商人瀝膽過。',32,'全唐诗/poet.tang.39000.json','["貪殘官吏虔誠謁，毒害商人瀝膽過。", "祗怕馬當山下水，不知平地有風波。"]'),
('c0b27b2a-1f64-49d0-ad53-25aaa2266295','將過湖南經馬當山廟因書三絕 三','杜荀鶴','唐','唐诗','tang','','[]','九江連海一般深，未必船經廟下沈。',32,'全唐诗/poet.tang.39000.json','["九江連海一般深，未必船經廟下沈。", "頭上蒼蒼沒瞞處，不如平取一生心。"]'),
('423c9943-3a32-416f-8027-284cdcc1698d','梁王坐上賦無雲雨','杜荀鶴','唐','唐诗','tang','','[]','同是乾坤事不同，雨絲飛灑日輪中。',32,'全唐诗/poet.tang.39000.json','["同是乾坤事不同，雨絲飛灑日輪中。", "若教陰郎長相似，爭表梁王造化功。"]'),
('8ffbf2c6-272d-46bd-9fd8-f797d936beaf','小松','杜荀鶴','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u54f2\u7406", "\u548f\u7269", "\u8bbd\u55bb", "\u52b1\u5fd7"]','自小刺頭深草裏，而今漸覺出蓬蒿。',32,'全唐诗/poet.tang.39000.json','["自小刺頭深草裏，而今漸覺出蓬蒿。", "時人不識凌雲木，直待凌雲始道高。"]'),
('87eb220e-34d5-4ec0-b6e7-9b591f0ee622','醉書僧壁','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','九華山色真堪愛，留得高僧爾許年。',32,'全唐诗/poet.tang.39000.json','["九華山色真堪愛，留得高僧爾許年。", "聽我吟詩供我酒，不曾穿得判齋錢。"]'),
('a7a8f62c-1ad1-455a-93a7-4d484ca722c8','寄李隱居','杜荀鶴','唐','唐诗','tang','','[]','自小棲玄到老閑，如雲如鶴住應難。',32,'全唐诗/poet.tang.39000.json','["自小棲玄到老閑，如雲如鶴住應難。", "溪山不必將錢買，贏得來來去去看。"]'),
('facc9ed3-d579-4a3d-892f-31f4447dcbc7','句','杜荀鶴','唐','唐诗','tang','','[]','舊衣灰絮絮，新酒竹篘篘。',28,'全唐诗/poet.tang.39000.json','["舊衣灰絮絮，新酒竹篘篘。", "只知斷送豪家酒，不解安排旅客情。"]'),
('affc4c69-a82e-4c1f-927a-84e07d4547d3','上蜀王','張道古','唐','唐诗','tang','','[]','封章才達冕旒前，黜詔俄離玉座端。',64,'全唐诗/poet.tang.39000.json','["封章才達冕旒前，黜詔俄離玉座端。", "二亂豈由明主用，五危終被佞臣彈。", "西巡鳳府非爲固，東播鑾輿卒未安。", "諫疏至今如可在，誰能更與讀來看。"]'),
('a4c31d1c-9ee0-4cee-991f-6cdc145a7ffd','詠雨','張道古','唐','唐诗','tang','','[]','亢陽今已久，嘉雨自雲傾。',24,'全唐诗/poet.tang.39000.json','["亢陽今已久，嘉雨自雲傾。", "一點不斜去，極多時下成。"]'),
('e2f602a5-8685-4fa8-9cc1-3643119d43ca','楊岐山','唐廩','唐','唐诗','tang','','[]','逗竹穿花越幾村，還從舊路入雲門。',64,'全唐诗/poet.tang.39000.json','["逗竹穿花越幾村，還從舊路入雲門。", "翠微不閉樓臺出，清吹頻回水石喧。", "天外鶴歸松自老，巖間僧逝塔空存。", "重來白首良堪喜，朝露浮生不足言。"]'),
('3253e0e0-0ff5-4d27-87d4-0d9734eb0a73','吹笙引','王轂','唐','唐诗','tang','','[]','媧皇遺音寄玉笙，雙成傳得何淒清。',80,'全唐诗/poet.tang.39000.json','["媧皇遺音寄玉笙，雙成傳得何淒清。", "丹穴嬌雛七十隻，一時飛上秋天鳴。", "水泉迸瀉急相續，一束宮商裂寒玉。", "旖旎香風繞指生，千聲妙盡神仙曲。", "曲終滿席悄無語，巫山冷碧愁雲雨。"]'),
('13f924e9-4740-482d-b7b0-48bb7f3e3713','鴻門讌','王轂','唐','唐诗','tang','','[]','寰海沸兮爭戰苦，風雲愁兮會龍虎。',63,'全唐诗/poet.tang.39000.json','["寰海沸兮爭戰苦，風雲愁兮會龍虎。", "四百年漢欲開基，項莊一劍何虛舞。", "殊不知人心去暴秦，天意歸明主。", "項王足底踏漢土，席上相看渾未悟。"]'),
('f0f62044-8fb8-4e65-99f3-539929c4cf2d','玉樹曲','王轂','唐','唐诗','tang','','[]','陳宮內宴明朝日，玉樹新妝逞嬌逸。',160,'全唐诗/poet.tang.39000.json','["陳宮內宴明朝日，玉樹新妝逞嬌逸。", "三閣霞明天上開，靈鼉振攂神仙出。", "天花數朵風吹綻，對舞輕盈瑞香散。", "金管紅弦旖旎隨，霓旌玉佩參差轉。", "璧月夜滿樓風輕，蓮舌泠泠詞調新。", "當行狎客盡持祿，直諫犯顏無一人。", "歌舞未終樂未闋，晉王劍上黏腥血。", "君臣猶在醉鄉中，一面已無陳日月。", "聖唐御宇三百祀，濮上桑間宜禁止。", "請停此曲歸正聲，願將雅樂調元氣。"]'),
('e83519e3-9286-4b07-a53e-e0e688ddae8b','苦熱行','王轂','唐','唐诗','tang','','[]','祝融南來鞭火龍，火旗焰焰燒天紅。',64,'全唐诗/poet.tang.39000.json','["祝融南來鞭火龍，火旗焰焰燒天紅。", "日輪當午凝不去，萬國如在洪爐中。", "五嶽翠乾雲彩滅，陽侯海底愁波竭。", "何當一夕金風發，爲我掃却天下熱。"]'),
('4a65068f-7e17-437b-ab45-a584f1ec63d9','暑日題道邊樹','王轂','唐','唐诗','tang','','[]','火輪迸焰燒長空，浮埃撲面愁朦朦。',64,'全唐诗/poet.tang.39000.json','["火輪迸焰燒長空，浮埃撲面愁朦朦。", "羸童走馬喘不進，忽逢碧樹含清風。", "清風留我移時住，滿地濃陰嬾前去。", "却歎人無及物功，不似團團道邊樹。"]'),
('cb96023d-8cc9-42f0-8c67-dafa7fa71c28','紅薔薇歌','王轂','唐','唐诗','tang','','[]','紅霞爛潑猩猩血，阿母瑤池曬仙纈。',64,'全唐诗/poet.tang.39000.json','["紅霞爛潑猩猩血，阿母瑤池曬仙纈。", "晚日春風奪眼明，蜀機錦彩渾疑黦。", "公子亭臺香觸人，百花懡㦬無精神。", "苧羅西子見應妬，風光占斷年年新。"]'),
('7b2a0bd1-0834-4096-8765-37d16644a398','刺桐花','王轂','唐','唐诗','tang','','[]','南國清和煙雨辰，刺桐夾道花開新。',64,'全唐诗/poet.tang.39000.json','["南國清和煙雨辰，刺桐夾道花開新。", "林梢簇簇紅霞爛，暑天別覺生精神。", "穠英鬬火欺朱槿，棲鶴驚飛翅憂燼。", "直疑青帝去怱怱，收拾春風渾不盡。"]'),
('d43d99e8-ec8c-4f4d-a9a6-e760bd688721','贈蒼溪王明府有文在手曰長生','王轂','唐','唐诗','tang','','[]','執手長生在，人皆號地仙。',48,'全唐诗/poet.tang.39000.json','["執手長生在，人皆號地仙。", "水雲真遂性，龜鶴足齊年。", "但以酒養氣，何言命在天。", "況無婚嫁累，應拍尚平肩。"]'),
('112125d8-08fd-471b-8111-a7c632a5dfd4','逢道者神和子','王轂','唐','唐诗','tang','','[]','珍重神和子，聞名五十年。',48,'全唐诗/poet.tang.39000.json','["珍重神和子，聞名五十年。", "童顏終不改，綠髮尚依然。", "酒裏消閑日，人間作散仙。", "長生如可慕，相逐隱林泉。"]'),
('12d929b9-8ee3-4755-97b3-3ca1f54177c8','送友人歸閩','王轂','唐','唐诗','tang','','[]','東南歸思切，把酒且留連。',48,'全唐诗/poet.tang.39000.json','["東南歸思切，把酒且留連。", "再會知何處，相看共黯然。", "猨啼棃嶺路，月白建溪船。", "莫戀家鄉住，酬身在少年。"]'),
('b75c51e0-292a-477b-ba6c-6bd7c92c11b5','春草碧色','王轂','唐','唐诗','tang','','[]','習習東風扇，萋萋草色新。',72,'全唐诗/poet.tang.39000.json','["習習東風扇，萋萋草色新。", "淺深千里碧，高下一時春。", "嫩葉舒煙際，微香動水濱。", "金塘明夕照，輦路惹芳塵。", "造化功何廣，陽和力自均。", "今當發生日，瀝懇祝良辰。"]'),
('eea023f0-0a44-4315-ab2c-ba917c449a01','夢仙謠三首 一','王轂','唐','唐诗','tang','','[]','前程漸覺風光好，琪花片片粘瑤草。',32,'全唐诗/poet.tang.39000.json','["前程漸覺風光好，琪花片片粘瑤草。", "有人遺我五色丹，一粒吞之後天老。"]'),
('e639605f-af52-43d1-8a50-76f31a762a0a','夢仙謠三首 二','王轂','唐','唐诗','tang','','[]','青童遞酒金觴疾，列坐紅霞神氣逸。',32,'全唐诗/poet.tang.39000.json','["青童遞酒金觴疾，列坐紅霞神氣逸。", "笑說留連數日間，已是人間一千日。"]'),
('06fd3f80-6f1c-4348-8046-205d81d5dfb5','夢仙謠三首 三','王轂','唐','唐诗','tang','','[]','瑤臺絳節遊皆遍，異果奇花香撲面。',32,'全唐诗/poet.tang.39000.json','["瑤臺絳節遊皆遍，異果奇花香撲面。", "松窗夢覺却神清，殘月林前三兩片。"]'),
('c7efff66-3635-4900-a067-fda3f2671fbc','後魏行','王轂','唐','唐诗','tang','','[]','力微皇帝謗天嗣，太武凶殘人所畏。',32,'全唐诗/poet.tang.39000.json','["力微皇帝謗天嗣，太武凶殘人所畏。", "一朝𦍩䍽飛上天，子孫盡作河魚餌。"]'),
('d85584d8-24ed-4a25-af94-fc26bf0f4f37','秋','王轂','唐','唐诗','tang','','[]','蟬噪古槐疏葉下，樹銜斜日映孤城。',32,'全唐诗/poet.tang.39000.json','["蟬噪古槐疏葉下，樹銜斜日映孤城。", "欲知潘鬢愁多少，一夜新添白數莖。"]'),
('e46c553e-4ba2-4e7f-9d42-3a27b3e99b3b','燕','王轂','唐','唐诗','tang','','[]','海燕雙飛意若何，曲梁嘔嘎語聲多。',32,'全唐诗/poet.tang.39000.json','["海燕雙飛意若何，曲梁嘔嘎語聲多。", "茅檐不必嫌卑陋，猶勝吳宮爇爾窠。"]'),
('54539b02-23db-415b-a521-890b6a28436c','牡丹','王轂','唐','唐诗','tang','','[]','牡丹妖豔亂人心，一國如狂不惜金。',32,'全唐诗/poet.tang.39000.json','["牡丹妖豔亂人心，一國如狂不惜金。", "曷若東園桃與李，果成無語自垂陰。"]'),
('52ba0fee-9b9b-4acf-8921-8d03e546d530','古意二首 一','孫郃','唐','唐诗','tang','','[]','屈子生楚國，七雄知其材。',48,'全唐诗/poet.tang.39000.json','["屈子生楚國，七雄知其材。", "介潔世不容，跡合藏蒿萊。", "道廢固命也，瓢飲亦賢哉。", "何事葬江水，空使後人哀。"]'),
('368fd800-6c1b-466f-84c6-7dcbdc45ed05','古意二首 二','孫郃','唐','唐诗','tang','','[]','魏禮段干木，秦王乃止戈。',48,'全唐诗/poet.tang.39000.json','["魏禮段干木，秦王乃止戈。", "小國有其人，大國奈之何。", "賢哲信爲美，兵甲豈云多。", "君子戰必勝，斯言聞孟軻。"]'),
('5f4f32d1-d4c0-46c7-8efc-929a35d61913','哭方玄英先生','孫郃','唐','唐诗','tang','','[]','牛斗文星落，知是先生死。',72,'全唐诗/poet.tang.39000.json','["牛斗文星落，知是先生死。", "湖上聞哭聲，門前見彈指。", "官無一寸祿，名傳千萬里。", "死著弊衣裳，生誰顧朱紫。", "我心痛其語，淚落不能已。", "猶喜韋補闕，揚名薦天子。"]'),
('d2399184-a4c5-4184-bc95-920088394852','句','孫郃','唐','唐诗','tang','','[]','仕宦類商賈，終日常東西。',12,'全唐诗/poet.tang.39000.json','["仕宦類商賈，終日常東西。"]'),
('e6d91294-726a-4174-a11a-90bac85303ee','投節度邢公','褚載','唐','唐诗','tang','','[]','西風昨夜墜紅蘭，一宿郵亭事萬般。',64,'全唐诗/poet.tang.39000.json','["西風昨夜墜紅蘭，一宿郵亭事萬般。", "無地可耕歸不得，有恩堪報死何難。", "流年怕老看將老，百計求安未得安。", "一卷新書滿懷淚，頻來門館訴飢寒。"]'),
('a3ebc78c-ca91-4a5f-8935-0a45e8d242ea','賀趙觀文重試及第','褚載','唐','唐诗','tang','','[]','一枝仙桂兩回春，始覺文章可致身。',64,'全唐诗/poet.tang.39000.json','["一枝仙桂兩回春，始覺文章可致身。", "已把色絲要上第，又將彩筆冠羣倫。", "龍泉再淬方知利，火浣重燒轉更新。", "今日街頭看御牓，大能榮耀苦心人。"]'),
('fb7faa2d-b7de-4511-961f-a42aa215bfcf','贈道士','褚載','唐','唐诗','tang','','[]','簪星曳月下蓬壺，曾見東臯種白榆。',64,'全唐诗/poet.tang.39000.json','["簪星曳月下蓬壺，曾見東臯種白榆。", "六甲威靈藏瑞檢，五龍雷電遶霜都。", "惟教鶴探丹丘信，不使人窺太乙爐。", "聞說葛陂風浪惡，許騎青鹿從行無。"]'),
('a46dc2f4-3eec-4255-8ada-ae14950325b3','曉發','褚載','唐','唐诗','tang','','[]','貪路貪名須早發，枕前無計暫裴回。',64,'全唐诗/poet.tang.39000.json','["貪路貪名須早發，枕前無計暫裴回。", "纔聞雞唱呼童起，已有鈴聲過驛來。", "衣溼乍驚霑霧露，馬行仍未見塵埃。", "朝朝陌上侵星去，待得酬身了便回。"]'),
('ea744ab7-9131-4dfa-8b20-fcf5e72569b5','曉感','褚載','唐','唐诗','tang','','[]','曉鼓鼕鼕星漢微，佩金鳴玉鬬光輝。',64,'全唐诗/poet.tang.39000.json','["曉鼓鼕鼕星漢微，佩金鳴玉鬬光輝。", "出門各自爭岐路，至老何人免是非。", "大道不應由曲取，浮生還要畧知機。", "故園華表高高在，可得不如丁令威。"]'),
('24930022-531a-4f49-807d-541aa570ee39','南徐晚望','褚載','唐','唐诗','tang','','[]','芳草鋪香晚岸晴，岸頭含醉去來行。',64,'全唐诗/poet.tang.39000.json','["芳草鋪香晚岸晴，岸頭含醉去來行。", "僧歸岳外殘鐘寺，日下江邊調角城。", "入浙孤帆知楚信，過淮疎雨帶潮聲。", "如今未免風塵役，寧敢怱怱便濯纓。"]'),
('2fcf0ee1-54c1-42d5-b431-a859180f42c9','移石','褚載','唐','唐诗','tang','','[]','磷𥒘一片溪中石，恰稱幽人彈素琴。',64,'全唐诗/poet.tang.39000.json','["磷𥒘一片溪中石，恰稱幽人彈素琴。", "浪侵多年苔色在，洗來今日碏痕深。", "磨看粹色何殊玉，敲有奇聲直異金。", "不是不堪爲器用，都緣良匠未留心。"]'),
('6061de32-6811-442a-acfc-c8105b3d35a7','瀑布','褚載','唐','唐诗','tang','','[]','瀉霧傾煙撼撼雷，滿山風雨助喧豗。',32,'全唐诗/poet.tang.39000.json','["瀉霧傾煙撼撼雷，滿山風雨助喧豗。", "爭知不是青天闕，撲下銀河一半來。"]'),
('b262bd58-6dff-4a23-96a2-fd88d264edf4','定鼎門','褚載','唐','唐诗','tang','','[]','郟鄏城高門倚天，九重蹤跡尚依然。',32,'全唐诗/poet.tang.39000.json','["郟鄏城高門倚天，九重蹤跡尚依然。", "須知道德無關鎖，一閉乾坤一萬年。"]'),
('dc8d043a-d3f6-483f-b712-fc60887c3395','陳倉驛','褚載','唐','唐诗','tang','','[]','錦翼花冠安在哉，雄飛雌伏盡塵埃。',32,'全唐诗/poet.tang.39000.json','["錦翼花冠安在哉，雄飛雌伏盡塵埃。", "一雙童子應惆悵，不見真人更獵來。"]'),
('979c60d9-9fd6-4db5-8b32-dd3788f983e1','長城','褚載','唐','唐诗','tang','','["\u6292\u60c5", "\u548f\u7269", "\u548f\u7269\u8bd7"]','秦築長城比鐵牢，蕃戎不敢過臨洮。',32,'全唐诗/poet.tang.39000.json','["秦築長城比鐵牢，蕃戎不敢過臨洮。", "焉知萬里連雲色，不及堯階三尺高。"]'),
('d04fdbb7-ad17-4130-87f0-e813962bbc9d','弔秦叟','褚載','唐','唐诗','tang','','[]','市西樓店金千秤，渭北田園粟萬鍾。',32,'全唐诗/poet.tang.39000.json','["市西樓店金千秤，渭北田園粟萬鍾。", "兒被殺傷妻被虜，一身隨駕到三峰。"]'),
('39872409-84a1-4b01-b2e7-a711652dbf21','雲','褚載','唐','唐诗','tang','','[]','盡日看雲首不回，無心都大似無才。',32,'全唐诗/poet.tang.39000.json','["盡日看雲首不回，無心都大似無才。", "可憐光彩一片玉，萬里晴天何處來。"]'),
('2bdd95a6-98cd-45e8-8557-d3bd0458c20d','鶴','褚載','唐','唐诗','tang','','[]','欲洗霜翎下澗邊，却嫌菱刺汚香泉。',32,'全唐诗/poet.tang.39000.json','["欲洗霜翎下澗邊，却嫌菱刺汚香泉。", "沙鷗浦鴈應驚訝，一舉扶搖直上天。"]'),
('e81299b3-371e-4708-832e-86e37d490ca6','句','褚載','唐','唐诗','tang','','[]','相逢多是醉醺然，應有囊中子母錢。',160,'全唐诗/poet.tang.39000.json','["相逢多是醉醺然，應有囊中子母錢。", "有興欲沽紅麴酒，無人同上翠旌樓。", "星斗離披煙靄收，玉蟾蜍耀海東頭。", "鹿胎冠子水晶簪，長嘯欹眠紫桂陰。", "躞蹀馬搖金絡腦，嬋娟人墜玉搔頭。", "狂歌放飲渾成性，知道逍遙出俗籠。", "除却洛陽才子後，更誰封恨弔懷沙。", "蓮浦浪澄堪倚釣，柳堤風煖好垂鞭。", "上馬等閑銷白日，出門輕薄倚黃金。", "淨名方丈雖然病，曼倩年涯未有多。"]'),
('de3cc60e-ea13-44f0-b7c0-725b667f622d','代寄邊人','鄭準','唐','唐诗','tang','','[]','君去不來久，悠悠昏又明。',48,'全唐诗/poet.tang.39000.json','["君去不來久，悠悠昏又明。", "片心因卜解，殘夢過橋驚。", "聖澤如垂餌，沙場會息兵。", "涼風當爲我，一一送砧聲。"]'),
('15a1dcdf-2408-4b8c-8d2b-a49292322825','江南清明','鄭準','唐','唐诗','tang','','[]','吳山楚驛四年中，一見清明一改容。',64,'全唐诗/poet.tang.39000.json','["吳山楚驛四年中，一見清明一改容。", "旅恨共風連夜起，韶光隨酒著人濃。", "延興門外攀花別，采石江頭帶雨逢。", "無限歸心何計是，路邊戈甲正重重。"]'),
('5c91dcfa-8204-473d-8e36-e5b717c19618','題宛陵北樓','鄭準','唐','唐诗','tang','','[]','雨來風靜綠蕪蘚，凭著朱闌思浩然。',64,'全唐诗/poet.tang.39000.json','["雨來風靜綠蕪蘚，凭著朱闌思浩然。", "人語獨耕燒後嶺，鳥飛斜沒望中煙。", "松梢半露藏雲寺，灘勢橫流出浦船。", "若遣謝宣城不死，必應吟盡夕陽川。"]'),
('68a5b50d-5f64-4d9a-a87e-dc0e196b637f','寄進士崔魯範','鄭準','唐','唐诗','tang','','[]','洛陽才子舊交知，別後干戈積詠思。',64,'全唐诗/poet.tang.39000.json','["洛陽才子舊交知，別後干戈積詠思。", "百戰市朝千里夢，三年風月幾篇詩。", "山高鴈斷音書絕，谷背鶯寒變化遲。", "會待路寧歸得去，酒樓漁浦重相期。"]'),
('e9d8a198-a249-4b1a-9b64-6351c6cf60c9','雲','鄭準','唐','唐诗','tang','','[]','片片飛來靜又閑，樓頭江上復山前。',32,'全唐诗/poet.tang.39000.json','["片片飛來靜又閑，樓頭江上復山前。", "飄零盡日不歸去，點破清光萬里天。"]'),
('daea56eb-6552-41c0-a81d-0d4caef1290d','句','鄭準','唐','唐诗','tang','','[]','護犢橫身立，逢人揭尾跳。',12,'全唐诗/poet.tang.39000.json','["護犢橫身立，逢人揭尾跳。"]'),
('0f810a9a-ddc4-4771-a288-d3d35fac18fa','游九鯉湖','陳乘','唐','唐诗','tang','','[]','汗漫乘春至，林巒霧雨生。',48,'全唐诗/poet.tang.39000.json','["汗漫乘春至，林巒霧雨生。", "洞莓黏屐重，巖雪濺衣輕。", "窟宅分三島，煙霞接五城。", "却憐饒藥物，欲辨不知名。"]'),
('19796737-ec7b-4c33-8df4-a81a7ca2cc10','章臺夜思','韋莊','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6000\u4eba", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','清瑟怨遙夜，遶弦風雨哀。',48,'全唐诗/poet.tang.39000.json','["清瑟怨遙夜，遶弦風雨哀。", "孤燈聞楚角，殘月下章臺。", "芳草已云暮，故人殊未來。", "鄉書不可寄，秋雁又南迴。"]'),
('b1fcfa0d-04ce-41fa-8148-1a78c8620b33','延興門外作','韋莊','唐','唐诗','tang','','[]','芳草五陵道，美人金犢車。',48,'全唐诗/poet.tang.39000.json','["芳草五陵道，美人金犢車。", "綠奔穿內水，紅落過牆花。", "馬足倦遊客，鳥聲歡酒家。", "王孫歸去晚，宮樹欲棲鴉。"]'),
('0578ce96-e47d-42ed-87b7-e121be9c2c80','劉得仁墓','韋莊','唐','唐诗','tang','','[]','至公遺至藝，終抱至冤沈。',48,'全唐诗/poet.tang.39000.json','["至公遺至藝，終抱至冤沈。", "名有詩家業，身無戚里心。", "桂和秋露滴，松帶夜風吟。", "冥寞知春否，墳蒿日已深。"]'),
('8ebacbee-c8ec-4fce-ab49-b116472ece92','下第題青龍寺僧房','韋莊','唐','唐诗','tang','','[]','千蹄萬轂一枝芳，要路無媒果自傷。',64,'全唐诗/poet.tang.39000.json','["千蹄萬轂一枝芳，要路無媒果自傷。", "題柱未期歸蜀國，曳裾何處謁吳王。", "馬嘶春陌金羈鬧，鳥睡花林繡羽香。", "酒薄恨濃消不得，却將惆悵問支郎。"]'),
('dbb27644-13d7-4dc8-b7ea-1662c3ec8d7a','虢州澗東村居作','韋莊','唐','唐诗','tang','','[]','東南騎馬出郊坰，迴首寒煙隔郡城。',64,'全唐诗/poet.tang.39000.json','["東南騎馬出郊坰，迴首寒煙隔郡城。", "清澗漲時翹鷺喜，綠桑疎處哺牛鳴。", "兒童見少生於客，奴僕驕多倨似兄。", "試望家田還自適，滿畦秋水稻苗平。"]'),
('c695ad47-3bc4-47d0-9d5b-e0fc683cf99a','送日本國僧敬龍歸','韋莊','唐','唐诗','tang','','["\u9001\u522b", "\u795d\u798f", "\u53cb\u60c5"]','扶桑已在渺茫中，家在扶桑東更東。',32,'全唐诗/poet.tang.39000.json','["扶桑已在渺茫中，家在扶桑東更東。", "此去與師誰共到，一船明月一帆風。"]'),
('f16577e3-e581-4a34-9105-68bc6c616f8b','對酒','韋莊','唐','唐诗','tang','','[]','何用巖棲隱姓名，一壺春酎可忘形。',32,'全唐诗/poet.tang.39000.json','["何用巖棲隱姓名，一壺春酎可忘形。", "伯倫若有長生術，直到如今醉未醒。"]'),
('f41e46d5-144e-435b-bbfc-b159a972d3f0','尹喜宅','韋莊','唐','唐诗','tang','','[]','荒原秋殿柏蕭蕭，何代風煙占寂寥。',64,'全唐诗/poet.tang.39000.json','["荒原秋殿柏蕭蕭，何代風煙占寂寥。", "紫氣已隨僊仗去，白雲空向帝鄉消。", "濛濛暮雨春雞唱，漠漠寒蕪雪兔跳。", "欲問靈蹤無處所，十洲空闊閬山遙。"]'),
('c78efd18-5597-4f1e-973e-718be02dbf85','途中望雨懷歸','韋莊','唐','唐诗','tang','','[]','滿空寒雨漫霏霏，去路雲深鎖翠微。',64,'全唐诗/poet.tang.39000.json','["滿空寒雨漫霏霏，去路雲深鎖翠微。", "牧豎遠當煙草立，飢禽閑傍渚田飛。", "誰家樹壓紅榴折，幾處籬懸白菌肥。", "對此不堪鄉外思，荷蓑遙羨釣人歸。"]'),
('aacef7e5-0597-435e-9477-d5d1b5ed52ea','古離別','韋莊','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u666f"]','晴煙漠漠柳毿毿，不那離情酒半酣。',32,'全唐诗/poet.tang.39000.json','["晴煙漠漠柳毿毿，不那離情酒半酣。", "更把玉鞭雲外指，斷腸春色在江南。"]'),
('88e88209-9ec7-4c53-a45d-bc1c71c41ad9','柳谷道中作却寄','韋莊','唐','唐诗','tang','','[]','馬前紅葉正紛紛，馬上離情斷殺魂。',64,'全唐诗/poet.tang.39000.json','["馬前紅葉正紛紛，馬上離情斷殺魂。", "曉發獨辭殘月店，暮程遙宿隔雲村。", "心如岳色留秦地，夢逐河聲出禹門。", "莫怪苦吟鞭拂地，有誰傾蓋待王孫。"]'),
('97dc6198-117c-4477-bfc2-cbd459beea85','灞陵道中作','韋莊','唐','唐诗','tang','','[]','春橋南望水溶溶，一桁晴山倒碧峰。',64,'全唐诗/poet.tang.39000.json','["春橋南望水溶溶，一桁晴山倒碧峰。", "秦苑落花零露濕，灞陵新酒撥醅濃。", "青龍夭矯盤雙闕，丹鳳䙰褷隔九重。", "萬古行人離別地，不堪吟罷夕陽鐘。"]'),
('ee87bdd8-28b3-4493-9bc3-01fe63bba60a','秋日早行','韋莊','唐','唐诗','tang','','[]','上馬蕭蕭襟袖涼，路穿禾黍繞宮牆。',64,'全唐诗/poet.tang.39000.json','["上馬蕭蕭襟袖涼，路穿禾黍繞宮牆。", "半山殘月露華冷，一岸野風蓮萼香。", "煙外驛樓紅隱隱，渚邊雲樹暗蒼蒼。", "行人自是心如火，兔走烏飛不覺長。"]'),
('5c4b5ce2-82b8-4acc-954d-6d1ed661a01d','歎落花','韋莊','唐','唐诗','tang','','[]','一夜霏微露濕煙，曉來和淚喪嬋娟。',64,'全唐诗/poet.tang.39000.json','["一夜霏微露濕煙，曉來和淚喪嬋娟。", "不隨殘雪埋芳草，盡逐香風上舞筵。", "西子去時遺笑靨，謝娥行處落金鈿。", "飄紅墮白堪惆悵，少別穠華又隔年。"]'),
('4571e043-116b-49c1-afd2-a5c6dd75bc8e','宮怨','韋莊','唐','唐诗','tang','','[]','一辭同輦閉昭陽，耿耿寒宵禁漏長。',64,'全唐诗/poet.tang.39000.json','["一辭同輦閉昭陽，耿耿寒宵禁漏長。", "釵上翠禽應不返，鏡中紅豔豈重芳。", "螢低夜色棲瑤草，水咽秋聲傍粉牆。", "展轉令人思蜀賦，解將惆悵感君王。"]'),
('cd4ebf0e-e152-452f-be15-f74881482926','關河道中','韋莊','唐','唐诗','tang','','[]','槐陌蟬聲柳市風，驛樓高倚夕陽東。',64,'全唐诗/poet.tang.39000.json','["槐陌蟬聲柳市風，驛樓高倚夕陽東。", "往來千里路長在，聚散十年人不同。", "但見時光流似箭，豈知天道曲如弓。", "平生志業匡堯舜，又擬滄浪學釣翁。"]'),
('2d7ee7bd-5036-4918-8b16-f0d9bb13a390','題盤豆驛水館後軒','韋莊','唐','唐诗','tang','','[]','極目晴川展畫屏，地從桃塞接蒲城。',64,'全唐诗/poet.tang.39000.json','["極目晴川展畫屏，地從桃塞接蒲城。", "灘頭鷺占清波立，原上人侵落照耕。", "去鴈數行天際沒，孤雲一點淨中生。", "馮軒盡日不迴首，楚水吳山無限情。"]'),
('3ff493ba-d9f5-46d8-8178-b4c96945dd50','梁氏水齋','韋莊','唐','唐诗','tang','','[]','獨醉任騰騰，琴棊亦自能。',48,'全唐诗/poet.tang.39000.json','["獨醉任騰騰，琴棊亦自能。", "卷簾山對客，開戶犬迎僧。", "看蟻移苔穴，聞蛙落石層。", "夜窗風雨急，松外一菴燈。"]'),
('28a42cb7-3941-46f8-98cc-f850fc9a2695','曲池作','韋莊','唐','唐诗','tang','','[]','細雨曲池濱，青袍草色新。',48,'全唐诗/poet.tang.39000.json','["細雨曲池濱，青袍草色新。", "詠詩行信馬，載酒喜逢人。", "性爲無機率，家因守道貧。", "若無詩自遣，誰奈寂寥春。"]'),
('b73ea2d1-d49b-4741-96ac-683ee5d89cc0','嘉會里閑居','韋莊','唐','唐诗','tang','','[]','豈知城闕內，有地出紅塵。',48,'全唐诗/poet.tang.39000.json','["豈知城闕內，有地出紅塵。", "草占一方綠，樹藏千古春。", "馬嘶遊寺客，犬吠探花人。", "寂寂無鐘鼓，槐行接紫宸。"]'),
('2007c906-bd55-4a7b-a62f-fa9601a8fdd6','夏夜','韋莊','唐','唐诗','tang','','[]','傍水遷書榻，開襟納夜涼。',48,'全唐诗/poet.tang.39000.json','["傍水遷書榻，開襟納夜涼。", "星繁愁晝熱，露重覺荷香。", "蛙吹鳴還息，蛛羅滅又光。", "正吟秋興賦，桐景下西牆。"]'),
('d61453ff-8d17-4621-9105-efaccfe4140f','早發','韋莊','唐','唐诗','tang','','[]','早霧濃於雨，田深黍稻低。',48,'全唐诗/poet.tang.39000.json','["早霧濃於雨，田深黍稻低。", "出門雞未唱，過客馬頻嘶。", "樹色遙藏店，泉聲暗傍畦。", "獨吟三十里，城月尚如珪。"]'),
('0b94137b-109a-4e54-b5e6-016650363115','寓言','韋莊','唐','唐诗','tang','','["\u6cf0\u5c71"]','黃金日日銷還鑄，僊桂年年折又生。',32,'全唐诗/poet.tang.39000.json','["黃金日日銷還鑄，僊桂年年折又生。", "兔走烏飛如未息，路塵終見泰山平。"]'),
('7128e591-fe45-4c8a-a62a-1d5bd70c34e4','對雪獻薛常侍','韋莊','唐','唐诗','tang','','[]','璚林瑤樹忽珊珊，急帶西風下晚天。',64,'全唐诗/poet.tang.39000.json','["璚林瑤樹忽珊珊，急帶西風下晚天。", "皓鶴䙰褷飛不辨，玉山重疊凍相連。", "松裝粉穗臨窗亞，水結冰錐簇溜懸。", "門外寒光利如劒，莫推紅袖訴金船。"]'),
('5fd2ae64-6557-4c30-8710-97197adf4396','題裴端公郊居','韋莊','唐','唐诗','tang','','["\u6292\u60c5"]','暫隨紅斾佐藩方，高跡終期臥故鄉。',64,'全唐诗/poet.tang.39000.json','["暫隨紅斾佐藩方，高跡終期臥故鄉。", "已近水聲開澗戶，更侵山色架書堂。", "蒲生岸脚青刀利，柳拂波心綠帶長。", "莫奪野人樵牧興，白雲不識繡衣郎。"]'),
('341cc81b-916f-4758-af25-5f3210ea07c0','登咸陽縣樓望雨','韋莊','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8"]','亂雲如獸出山前，細雨和風滿渭川。',32,'全唐诗/poet.tang.39000.json','["亂雲如獸出山前，細雨和風滿渭川。", "盡日空濛無所見，鴈行斜去字聯聯。"]'),
('ae555063-274e-40e3-bd1c-8236d997be67','貴公子','韋莊','唐','唐诗','tang','','[]','大道青樓御苑東，玉欄仙杏壓枝紅。',64,'全唐诗/poet.tang.39000.json','["大道青樓御苑東，玉欄仙杏壓枝紅。", "金鈴犬吠梧桐月，朱鬣馬嘶楊柳風。", "流水帶花穿巷陌，夕陽和樹入簾櫳。", "瑤池宴罷歸來醉，笑說君王在月宮。"]'),
('e23452a2-d247-4ae7-8e77-9df47613815c','聽趙秀才彈琴','韋莊','唐','唐诗','tang','','[]','滿匣冰泉咽又鳴，玉音閑澹入神清。',64,'全唐诗/poet.tang.39000.json','["滿匣冰泉咽又鳴，玉音閑澹入神清。", "巫山夜雨弦中起，湘水清波指下生。", "蜂簇野花吟細韻，蟬移高柳迸殘聲。", "不須更奏幽蘭曲，卓氏門前月正明。"]'),
('30dd45f4-f14e-4ee2-b3d6-5a744bf6bfb3','觀獵','韋莊','唐','唐诗','tang','','[]','苑牆東畔欲斜暉，傍苑穿花兔正肥。',64,'全唐诗/poet.tang.39000.json','["苑牆東畔欲斜暉，傍苑穿花兔正肥。", "公子喜逢朝罷日，將軍誇換戰時衣。", "鶻翻錦翅雲中落，犬帶金鈴草上飛。", "直待四郊高鳥盡，掉鞍齊向國門歸。"]'),
('fa88d19a-2195-4674-9fe0-b4211a37fc59','三堂東湖作','韋莊','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u95f2\u9002"]','滿塘秋水碧泓澄，十畝菱花晚鏡清。',64,'全唐诗/poet.tang.39000.json','["滿塘秋水碧泓澄，十畝菱花晚鏡清。", "景動新橋橫蝃蝀，岸鋪芳草睡鵁鶄。", "蟾投夜魄當湖落，嶽倒秋蓮入浪生。", "何處最添詩客興，黃昏煙雨亂蛙聲。"]'),
('b8f7fe0f-18e9-4a98-ab4b-246b74da1a48','放榜日作','韋莊','唐','唐诗','tang','','[]','一聲天鼓闢金扉，三十仙材上翠微。',64,'全唐诗/poet.tang.39000.json','["一聲天鼓闢金扉，三十仙材上翠微。", "葛水霧中龍乍變，緱山煙外鶴初飛。", "鄒陽暖豔催花發，太皞春光簇馬歸。", "迴首便辭塵土世，彩雲新換六銖衣。"]'),
('fc3cf179-d61d-4306-bac2-8ff84da1e618','寄薛先輩','韋莊','唐','唐诗','tang','','[]','懸知迴日綵衣榮，仙籍高標第一名。',64,'全唐诗/poet.tang.39000.json','["懸知迴日綵衣榮，仙籍高標第一名。", "瑤樹帶風侵物冷，玉山和雨射人清。", "龍翻瀚海波濤壯，鶴出金籠燕雀驚。", "不說文章與門地，自然毛骨是公卿。"]'),
('3c84f1b9-e458-402b-9db5-5e31ba932e14','訪含弘山僧不遇留題精舍','韋莊','唐','唐诗','tang','','[]','滿院桐花鳥雀喧，寂寥芳草茂芊芊。',64,'全唐诗/poet.tang.39000.json','["滿院桐花鳥雀喧，寂寥芳草茂芊芊。", "吾師正遇歸山日，閑客空題到寺年。", "池竹閉門教鶴守，琴書開篋任僧傳。", "人間不自尋行跡，一片孤雲在碧天。"]'),
('282d9d1f-119e-48fc-bd7b-bd0fb9be355b','寄從兄遵','韋莊','唐','唐诗','tang','','[]','江上秋風正釣鱸，九重天子夢翹車。',64,'全唐诗/poet.tang.39000.json','["江上秋風正釣鱸，九重天子夢翹車。", "不將高臥邀劉主，自吐清談護漢儲。", "滄海十年龍景斷，碧雲千里雁行疎。", "相逢莫話歸山計，明日東封待直廬。"]'),
('78bc34ed-50c2-4a21-b469-fc03fd08d186','漁塘十六韻','韋莊','唐','唐诗','tang','','[]','洛水分餘脈，穿巖出石稜。',192,'全唐诗/poet.tang.39000.json','["洛水分餘脈，穿巖出石稜。", "碧經嵐氣重，清帶露華澄。", "瑩澈通三島，巖梧積萬層。", "巢由應共到，劉阮想同登。", "壁峻苔如畫，山昏霧似蒸。", "撼松衣有雪，題石硯生冰。", "路熟雲中客，名留域外僧。", "飢猿尋落橡，鬬鼠墮高藤。", "嶮樹臨溪亞，殘莎帶岸崩。", "持竿聊藉草，待月好垂罾。", "對景思任父，開圖想不興。", "晚風輕浪疊，暮雨濕煙凝。", "似泛靈槎出，如迎羽客昇。", "仙源終不測，勝概自相仍。", "欲別誠堪戀，長歸又未能。", "他時操史筆，爲爾著良稱。"]'),
('04a0b9d9-04e7-423f-ac07-52a3714aaaee','冬日長安感志寄獻虢州崔郎中二十韻','韋莊','唐','唐诗','tang','','[]','帝里無成久滯淹，別家三度見新蟾。',320,'全唐诗/poet.tang.39000.json','["帝里無成久滯淹，別家三度見新蟾。", "郄詵丹桂無人指，阮籍青襟有淚霑。", "溪上却思雲滿屋，鏡中惟怕雪生髯。", "病如原憲誰能療，蹇似劉楨豈用占。", "霧雨十年同隱遁，風雷何日振沈潛。", "吁嗟每被更聲引，歌詠還因酒思添。", "客舍正甘愁寂寂，郡樓遙想醉懨懨。", "已聞鈴閣懸新詔，即向綸闈副具瞻。", "濟物便同川上檝，慰心還似邑中黔。", "觀星始覺中郎貴，問俗方知太守廉。", "宅後綠波棲畫鷁，馬前紅袖簇丹襜。", "閑招好客斟香蟻，悶對瓊花詠散鹽。", "積凍慢封寒霤細，暮雲高拔遠峰尖。", "訟堂無事冰生印，水榭高吟月透簾。", "松下圍棋期褚胤，筆頭飛箭薦陶謙。", "未知匣劒何時躍，但恐鉛刀不再銛。", "雖有遠心長擁篲，恥將新劒學編苫。", "纔驚素節移銅律，又見玄冥變玉籤。", "百口似萍依廣岸，一身如燕戀高簷。", "如今正困風波力，更向人中問宋纖。"]'),
('dfe2a0ac-2b27-4b06-9d04-479d73445559','和薛先輩見寄初秋寓懷即事之作二十韻','韋莊','唐','唐诗','tang','','[]','玉律初移候，清風乍遠襟。',240,'全唐诗/poet.tang.39000.json','["玉律初移候，清風乍遠襟。", "一聲蟬到耳，千炬火然心。", "嶽靜雲堆翠，樓高日半沈。", "引愁憎暮角，驚夢怯殘碪。", "露白凝湘簟，風篁韻蜀琴。", "鳥喧從果爛，堦淨任苔侵。", "柿葉添紅景，槐柯減綠陰。", "採珠逢寶窟，閱石見瑤林。", "魯殿鏗寒玉，苔山激碎金。", "郄堂流桂景，陳巷集車音。", "名自張華顯，詞因葛亮吟。", "水深龍易失，天遠鶴難尋。", "鑒貌寧慙樂，論才豈謝任。", "義心孤劒直，學海怒濤深。", "既覩文兼質，翻疑古在今。", "慙聞紆綠綬，即候挂朝簪。", "晚樹連秋塢，斜陽映暮岑。", "夜蟲方唧唧，疲馬正駸駸。", "託跡同吳燕，依仁似越禽。", "會隨仙羽化，香蟻且同斟。"]'),
('0168e1a6-e2bb-4df0-8b06-76d3855eb1c6','同舊韻','韋莊','唐','唐诗','tang','','[]','大火收殘暑，清光漸惹襟。',240,'全唐诗/poet.tang.39000.json','["大火收殘暑，清光漸惹襟。", "謝莊千里思，張翰五湖心。", "暮角迎風急，孤鐘向暝沈。", "露滋三徑草，日動四鄰碪。", "簟委班姬扇，蟬悲蔡琰琴。", "方愁丹桂遠，已怯二毛侵。", "甃石迴泉脈，移棊就竹陰。", "觸絲蛛墮網，避隼鳥投林。", "貌愧潘郎璧，文慙呂相金。", "但埋酆獄氣，未發爨桐音。", "靜笑劉琨舞，閑思阮籍吟。", "野花和雨斸，怪石入雲尋。", "跡竟終非切，幽閑且自任。", "趨時慙藝薄，託質仰恩深。", "美價方稀古，清名已絕今。", "既聞留縞帶，詎肯擲蓍簪。", "遲客虛高閣，迎僧出亂岑。", "壯心徒戚戚，逸足自駸駸。", "安羨倉中鼠，危同幕上禽。", "期君調鼎鼐，他日俟羊斟。"]'),
('45a866f5-3aeb-447c-8677-6bb09127a78e','三用韻','韋莊','唐','唐诗','tang','','[]','素律初迴馭，商飆暗觸襟。',240,'全唐诗/poet.tang.39000.json','["素律初迴馭，商飆暗觸襟。", "乍傷詩客思，還動旅人心。", "蟬噪因風斷，鱗遊見鷺沈。", "笛聲隨晚吹，松韻激遙砧。", "地覆青袍草，窗橫綠綺琴。", "煙霄難自致，歲月易相侵。", "澗柳橫孤彴，巖藤架密陰。", "瀟湘期釣侶，鄠杜別家林。", "遺愧虞卿璧，言依季布金。", "錚鏦聞郢唱，次第發巴音。", "螢影衝簾落，蟲聲擁砌吟。", "樓高思共釣，寺遠想同尋。", "入夜愁難遣，逢秋恨莫任。", "蝸遊苔徑滑，鶴步翠塘深。", "莫問榮兼辱，寧論古與今。", "固窮憐甕牖，感舊惜蒿簪。", "晚日舒霞綺，遙天倚黛岑。", "鴛鸞方翽翽，驊驥整駸駸。", "未化投陂竹，空思出谷禽。", "感多聊自遣，桑落且閑斟。"]'),
('aba16b50-122a-429e-8a0f-798c833ac89a','驚秋','韋莊','唐','唐诗','tang','','[]','不向煙波狎釣舟，強親文墨事儒丘。',32,'全唐诗/poet.tang.39000.json','["不向煙波狎釣舟，強親文墨事儒丘。", "長安十二槐花陌，曾負秋風多少秋。"]'),
('e71164ff-fe3e-4e76-b72a-1a73a3b68d6d','登漢高廟閑眺','韋莊','唐','唐诗','tang','','[]','獨尋仙境上高原，雲雨深藏古帝壇。',64,'全唐诗/poet.tang.39000.json','["獨尋仙境上高原，雲雨深藏古帝壇。", "天畔晚峰青簇簇，檻前春樹碧團團。", "參差郭外樓臺小，斷續風中鼓角殘。", "一帶遠光何處水，釣舟閑繫夕陽灘。"]'),
('391c1a2e-26b6-436c-b381-0fd5b91459ac','耒陽縣浮山神廟','韋莊','唐','唐诗','tang','','[]','一郡皆傳此廟靈，廟前松桂古今青。',64,'全唐诗/poet.tang.39000.json','["一郡皆傳此廟靈，廟前松桂古今青。", "山曾堯代浮洪水，地有唐臣奠綠醽。", "遶坐香風吹寶蓋，傍簷煙雨濕巖扃。", "爲霖自可成農歲，何用興師遠伐邢。"]'),
('76129a35-83f4-480b-882c-8c7494ff8418','愁','韋莊','唐','唐诗','tang','','[]','避愁愁又至，愁至事難忘。',48,'全唐诗/poet.tang.39000.json','["避愁愁又至，愁至事難忘。", "夜坐心中火，朝爲鬢上霜。", "不經公子夢，偏入旅人腸。", "借問高軒客，何鄉是醉鄉。"]'),
('b7b0f701-dd12-444a-b384-36e8a3df0827','村居書事','韋莊','唐','唐诗','tang','','[]','年年耕與釣，鷗鳥已相依。',48,'全唐诗/poet.tang.39000.json','["年年耕與釣，鷗鳥已相依。", "砌長蒼苔厚，藤抽紫蔓肥。", "風鶯移樹囀，雨燕入樓飛。", "不覺春光暮，遶籬紅杏稀。"]'),
('b75ba2fa-a99c-4aa1-ade3-6767de63a059','三堂早春','韋莊','唐','唐诗','tang','','[]','獨倚危樓四望遙，杏花春陌馬聲驕。',64,'全唐诗/poet.tang.39000.json','["獨倚危樓四望遙，杏花春陌馬聲驕。", "池邊冰刃暖初落，山上雪稜寒未銷。", "溪送綠波穿郡宅，日移紅影度村橋。", "主人年少多情味，笑換金龜解珥貂。"]'),
('14d03922-3b13-455f-a125-c85be1edc20d','雨霽晚眺','韋莊','唐','唐诗','tang','','[]','入谷路縈紆，巖巔日欲晡。',48,'全唐诗/poet.tang.39000.json','["入谷路縈紆，巖巔日欲晡。", "嶺雲寒埽蓋，溪雪凍黏鬚。", "臥草跧如兔，聽冰怯似狐。", "仍聞關外火，昨夜徹皇都。"]'),
('7cba0871-ada5-4c97-a42e-5fc4814cbac3','立春日作','韋莊','唐','唐诗','tang','','[]','九重天子去蒙塵，御柳無情依舊春。',32,'全唐诗/poet.tang.39000.json','["九重天子去蒙塵，御柳無情依舊春。", "今日不關妃妾事，始知辜負馬嵬人。"]'),
('652b31c5-7308-4f3c-83b1-911884c9cf37','贈雲陽裴明府','韋莊','唐','唐诗','tang','','[]','南北三年一解攜，海爲深谷岸爲蹊。',64,'全唐诗/poet.tang.39000.json','["南北三年一解攜，海爲深谷岸爲蹊。", "已聞陳勝心降漢，誰爲田橫國號齊。", "暴客至今猶戰鶴，故人何處尚驅雞。", "歸來能作煙波伴，我有魚舟在五溪。"]'),
('f5a14bc1-6d6f-4446-a552-ac36f35ea608','賊中與蕭韋二秀才同臥重疾二君尋愈余獨加焉恍惚之中因有題','韋莊','唐','唐诗','tang','','[]','與君同臥疾，獨我漸彌留。',48,'全唐诗/poet.tang.39000.json','["與君同臥疾，獨我漸彌留。", "弟妹不知處，兵戈殊未休。", "胸中疑晉豎，耳下鬬殷牛。", "縱有秦醫在，懷鄉亦淚流。"]'),
('a596faf4-a76a-4708-955f-cde90820f40a','重圍中逢蕭校書','韋莊','唐','唐诗','tang','','[]','相逢俱此地，此地是何鄉。',48,'全唐诗/poet.tang.39000.json','["相逢俱此地，此地是何鄉。", "側目不成語，撫心空自傷。", "劒高無鳥度，樹暗有兵藏。", "底事征西將，年年戍洛陽。"]'),
('e224462a-8d3d-46ce-9da8-b5cf2a41be56','咸通','韋莊','唐','唐诗','tang','','[]','咸通時代物情奢，歡殺金張許史家。',64,'全唐诗/poet.tang.39000.json','["咸通時代物情奢，歡殺金張許史家。", "破產競留天上樂，鑄山爭買洞中花。", "諸郎宴罷銀燈合，仙子遊迴璧月斜。", "人意似知今日事，急催弦管送年華。"]'),
('25156cd0-3e55-4f5e-95f3-dc50702805cb','白櫻桃','韋莊','唐','唐诗','tang','','[]','王母堦前種幾株，水精簾外看如無。',32,'全唐诗/poet.tang.39000.json','["王母堦前種幾株，水精簾外看如無。", "只應漢武金盤上，瀉得珊珊白露珠。"]'),
('9e5c0f56-def6-4fe7-8fb6-daec2302dc76','夜景','韋莊','唐','唐诗','tang','','[]','滿庭松桂雨餘天，宋玉秋聲韻蜀弦。',64,'全唐诗/poet.tang.39000.json','["滿庭松桂雨餘天，宋玉秋聲韻蜀弦。", "烏兔不知多事世，星辰長似太平年。", "誰家一笛吹殘暑，何處雙砧擣暮煙。", "欲把傷心問明月，素娥無語淚娟娟。"]'),
('4be1c589-2594-48bc-b8b7-0891ec06c553','宿山家','韋莊','唐','唐诗','tang','','[]','山行侵夜到，雲竇一星燈。',48,'全唐诗/poet.tang.39000.json','["山行侵夜到，雲竇一星燈。", "草動蛇尋穴，枝搖鼠上藤。", "背風開藥竈，向月展漁罾。", "明日前溪路，煙蘿更幾層。"]'),
('3551d6a5-61cf-41f3-8c28-586d1972ba8d','長年','韋莊','唐','唐诗','tang','','[]','長年方悟少年非，人道新詩勝舊詩。',64,'全唐诗/poet.tang.39000.json','["長年方悟少年非，人道新詩勝舊詩。", "十畝野塘留客釣，一軒春雨對僧棊。", "花間醉任黃鶯語，亭上吟從白鷺窺。", "大盜不將爐冶去，有心重築太平基。"]'),
('c27b7db3-d609-470f-848f-75bbb62805c4','辛丑年','韋莊','唐','唐诗','tang','','[]','九衢漂杵已成川，塞上黃雲戰馬閑。',64,'全唐诗/poet.tang.39000.json','["九衢漂杵已成川，塞上黃雲戰馬閑。", "但有羸兵填渭水，更無奇士出商山。", "田園已沒紅塵裏，弟妹相逢白刃間。", "西望翠華殊未返，淚痕空濕劒文斑。"]'),
('95982a81-b8b2-4910-bc0d-779e2d6b625b','思歸','韋莊','唐','唐诗','tang','','[]','暖絲無力自悠揚，牽引東風斷客腸。',64,'全唐诗/poet.tang.39000.json','["暖絲無力自悠揚，牽引東風斷客腸。", "外地見花終寂寞，異鄉聞樂更淒涼。", "紅垂野岸櫻還熟，綠染迴汀草又芳。", "舊里若爲歸去好，子期凋謝呂安亡。"]'),
('e0ffaa79-aabd-4959-8b6c-06cde607b6e0','憶昔','韋莊','唐','唐诗','tang','','[]','昔年曾向五陵遊，子夜歌清月滿樓。',64,'全唐诗/poet.tang.39000.json','["昔年曾向五陵遊，子夜歌清月滿樓。", "銀燭樹前長似晝，露桃華裏不知秋。", "西園公子名無忌，南國佳人號莫愁。", "今日亂離俱是夢，夕陽唯見水東流。"]'),
('bb03ae35-3159-48f5-aaf4-babb55c56861','合歡蓮花','韋莊','唐','唐诗','tang','','[]','虞舜南巡去不歸，二妃相誓死江湄。',32,'全唐诗/poet.tang.39000.json','["虞舜南巡去不歸，二妃相誓死江湄。", "空留萬古香魂在，結作雙葩合一枝。"]'),
('f16392ac-04ba-4b7f-9028-a6df9c92f891','覽蕭必先卷','韋莊','唐','唐诗','tang','','[]','滿軸編新句，翛然大雅風。',48,'全唐诗/poet.tang.39000.json','["滿軸編新句，翛然大雅風。", "名因五字得，命合一言通。", "景盡才難盡，吟終意未終。", "似逢曹與謝，煙雨思何窮。"]'),
('912d1762-4c68-4d11-8ac7-06847e82585e','和人歲宴旅舍見寄','韋莊','唐','唐诗','tang','','[]','積雪滿前除，寒光夜皎如。',48,'全唐诗/poet.tang.39000.json','["積雪滿前除，寒光夜皎如。", "老憂新歲近，貧覺故交疎。", "意合論文後，心降得句初。", "莫言常鬱鬱，天道有盈虛。"]'),
('99ef9f58-02b0-4d36-9b48-5ca9877be158','宿泊孟津寄三堂友人','韋莊','唐','唐诗','tang','','[]','解纜西征未有期，槐花又逼桂花時。',64,'全唐诗/poet.tang.39000.json','["解纜西征未有期，槐花又逼桂花時。", "鴻臚陌上歸耕晚，金馬門前獻賦遲。", "只恐愁苗生兩鬢，不堪離恨入雙眉。", "分明昨夜南池夢，還把漁竿詠楚詞。"]'),
('917ca818-9789-4ac6-a44a-0713ad93ac62','對酒賦友人','韋莊','唐','唐诗','tang','','[]','多病仍多感，君心自我心。',48,'全唐诗/poet.tang.39000.json','["多病仍多感，君心自我心。", "浮生都是夢，浩歎不如吟。", "白雪篇篇麗，清酤盞盞深。", "亂離俱老大，強醉莫霑襟。"]'),
('2086b2a0-555b-41a2-9827-ed1242d3415b','天井關','韋莊','唐','唐诗','tang','','[]','太行山上雲深處，誰向雲中築女牆。',64,'全唐诗/poet.tang.39000.json','["太行山上雲深處，誰向雲中築女牆。", "短綆詎能垂玉甃，繚垣何用學金湯。", "斸開嵐翠爲高壘，截斷雲霞作巨防。", "守吏不教飛鳥過，赤眉何路到吾鄉。"]'),
('aad6243a-b71a-41ad-927f-8ad6dd8d85fb','贈邊將','韋莊','唐','唐诗','tang','','[]','昔因征遠向金微，馬出榆關一鳥飛。',64,'全唐诗/poet.tang.39000.json','["昔因征遠向金微，馬出榆關一鳥飛。", "萬里只攜孤劒去，十年空逐塞鴻歸。", "手招都護新降虜，身著文皇舊賜衣。", "只待煙塵報天子，滿頭霜雪爲兵機。"]'),
('aeacc177-24c9-4559-b644-79ef2433536d','春日','韋莊','唐','唐诗','tang','','[]','忽覺東風景漸遲，野梅山杏暗芳菲。',64,'全唐诗/poet.tang.39000.json','["忽覺東風景漸遲，野梅山杏暗芳菲。", "落星樓上吹殘角，偃月營中挂夕暉。", "旅夢亂隨蝴蝶散，離魂漸逐杜鵑飛。", "紅塵遮斷長安陌，芳草王孫暮不歸。"]'),
('0174e7f2-c0a8-4511-a9f9-464d09d60811','早秋夜作','韋莊','唐','唐诗','tang','','[]','翠簟初清暑半銷，[撇]簾松韻送輕飆。',66,'全唐诗/poet.tang.39000.json','["翠簟初清暑半銷，[撇]簾松韻送輕飆。", "莎庭露永琴書潤，山郭月明砧杵遙。", "傍砌綠苔鳴蟋蟀，遶簷紅樹織蠨蛸。", "不須更作悲秋賦，王粲辭家鬢已凋。"]'),
('8ecfb3a4-3770-4fec-aef5-2e0913f2f802','寄江南逐客','韋莊','唐','唐诗','tang','','[]','二年音信阻湘潭，花下相思酒半酣。',32,'全唐诗/poet.tang.39000.json','["二年音信阻湘潭，花下相思酒半酣。", "記得竹齋風雨夜，對牀孤枕話江南。"]'),
('92f860a9-4e7a-41bf-95b4-a9e4540fe816','冬夜','韋莊','唐','唐诗','tang','','[]','睡覺寒爐酒半消，客情鄉夢兩遙遙。',32,'全唐诗/poet.tang.39000.json','["睡覺寒爐酒半消，客情鄉夢兩遙遙。", "無人爲我磨心劍，割斷愁腸一寸苗。"]'),
('f1a219a0-4303-47bd-8f7d-5ad817a2fd9d','又聞湖南荆渚相次陷沒','韋莊','唐','唐诗','tang','','[]','幾時聞唱凱旋歌，處處屯兵未倒戈。',64,'全唐诗/poet.tang.39000.json','["幾時聞唱凱旋歌，處處屯兵未倒戈。", "天子只憑紅斾壯，將軍空恃紫髯多。", "屍填漢水連荆阜，血染湘雲接楚波。", "莫問流離南越事，戰餘空有舊山河。"]'),
('83f0e706-661d-4ef6-9a53-1944d56c1ae6','家叔南遊却歸因獻賀','韋莊','唐','唐诗','tang','','[]','繚繞江南一歲歸，歸來行色滿戎衣。',64,'全唐诗/poet.tang.39000.json','["繚繞江南一歲歸，歸來行色滿戎衣。", "長聞鳳詔徵兵急，何事龍韜獻捷稀。", "旅夢遠依湘水闊，離魂空伴越禽飛。", "遙知倚棹思家處，澤國煙深暮雨微。"]'),
('d8614c7b-43e8-47f9-a77a-990a0e59ddd1','楚行吟','韋莊','唐','唐诗','tang','','[]','章華臺下草如煙，故郢城頭月似弦。',32,'全唐诗/poet.tang.39000.json','["章華臺下草如煙，故郢城頭月似弦。", "惆悵楚宮雲雨後，露啼花笑一年年。"]'),
('0aa6770d-4589-4db9-8b7e-68d4c8db9a39','洛陽吟','韋莊','唐','唐诗','tang','','[]','萬戶千門夕照邊，開元時節舊風煙。',64,'全唐诗/poet.tang.39000.json','["萬戶千門夕照邊，開元時節舊風煙。", "宮官試馬遊三市，舞女乘舟上九天。", "胡騎北來空進主，漢皇西去竟昇僊。", "如今父老偏垂淚，不見承平四十年。"]'),
('2d95f013-cbb9-4bac-badc-a91b41151f59','過舊宅','韋莊','唐','唐诗','tang','','[]','華軒不見馬蕭蕭，廷尉門人久寂寥。',64,'全唐诗/poet.tang.39000.json','["華軒不見馬蕭蕭，廷尉門人久寂寥。", "朱檻翠樓爲卜肆，玉欄僊杏作春樵。", "堦前雨落鴛鴦瓦，竹裏苔封螮蝀橋。", "莫問此中銷歇寺，娟娟紅淚滴芭蕉。"]'),
('f90f64be-4e9c-4d00-8278-d0e5a18cfb57','喻東軍','韋莊','唐','唐诗','tang','','[]','四年龍馭守峨嵋，鐵馬西來步步遲。',64,'全唐诗/poet.tang.39000.json','["四年龍馭守峨嵋，鐵馬西來步步遲。", "五運未教移漢鼎，六韜何必待秦師。", "幾時鸞鳳歸丹闕，到處烏鳶從白旗。", "獨把一樽和淚酒，隔雲遙奠武侯祠。"]'),
('071805e2-1158-426d-991a-084bd39e197e','清河縣樓作','韋莊','唐','唐诗','tang','','[]','有客微吟獨凭樓，碧雲紅樹不勝愁。',48,'全唐诗/poet.tang.39000.json','["有客微吟獨凭樓，碧雲紅樹不勝愁。", "盤鵰迥印天心沒，遠水斜牽日脚流。", "千里戰塵連上苑，九江歸路隔東周。"]'),
('82256c70-e7f2-43d6-93a8-46295905cb9f','北原閑眺','韋莊','唐','唐诗','tang','','[]','春城迴首樹重重，立馬平原夕照中。',64,'全唐诗/poet.tang.39000.json','["春城迴首樹重重，立馬平原夕照中。", "五鳳灰殘金翠滅，六龍遊去市朝空。", "千年王氣浮清洛，萬古坤靈鎮碧嵩。", "欲問向來陵谷事，野桃無語淚花紅。"]'),
('89c64a8a-8774-4ed9-9309-9253685d861c','贈戍兵','韋莊','唐','唐诗','tang','','[]','漢皇無事暫遊汾，底事狐狸嘯作羣。',64,'全唐诗/poet.tang.39000.json','["漢皇無事暫遊汾，底事狐狸嘯作羣。", "夜指碧天占晉分，曉磨孤劒望秦雲。", "紅旌不卷風長急，畫角閑吹日又曛。", "止竟有征須有戰，洛陽何用久屯軍。"]'),
('23e623c7-9060-426d-b4d1-1ea9898d8903','覩軍迴戈','韋莊','唐','唐诗','tang','','[]','關中羣盜已心離，關外猶聞羽檄飛。',64,'全唐诗/poet.tang.39000.json','["關中羣盜已心離，關外猶聞羽檄飛。", "御苑綠莎嘶戰馬，禁城寒月搗征衣。", "漫教韓信兵塗地，不及劉琨嘯解圍。", "昨日屯軍還夜遁，滿車空載洛神歸。"]'),
('a7068942-fab8-4511-8a9a-b83a1f290cb2','中渡晚眺','韋莊','唐','唐诗','tang','','[]','魏王堤畔草如煙，有客傷時獨扣舷。',64,'全唐诗/poet.tang.39000.json','["魏王堤畔草如煙，有客傷時獨扣舷。", "妖氣欲昏唐社稷，夕陽空照漢山川。", "千重碧樹籠春苑，萬縷紅霞襯碧天。", "家寄杜陵歸不得，一迴回首一潸然。"]'),
('f8ebd494-0f38-4fa3-b10b-c9f6382b8ab2','河內別村業閑題','韋莊','唐','唐诗','tang','','[]','阮氏清風竹巷深，滿溪松竹似山陰。',64,'全唐诗/poet.tang.39000.json','["阮氏清風竹巷深，滿溪松竹似山陰。", "門當谷路多樵客，地帶河聲足水禽。", "閑伴爾曹雖適意，靜思吾道好霑襟。", "鄰翁莫問傷時事，一曲高歌夕照沈。"]'),
('21aec4c7-4f49-49d2-83ac-5ff575f7e03a','聞官軍繼至未覩凱旋','韋莊','唐','唐诗','tang','','[]','嫖姚何日破重圍，秋草深來戰馬肥。',64,'全唐诗/poet.tang.39000.json','["嫖姚何日破重圍，秋草深來戰馬肥。", "已有孔明傳將略，更聞王導得神機。", "陣前鼙鼓晴應響，城上烏鳶飽不飛。", "何事小臣偏注目，帝鄉遙羨白雲歸。"]'),
('e55bbc83-e8c8-4f70-bb26-0b157899fe56','和集賢侯學士分司丁侍御秋日雨霽之作','韋莊','唐','唐诗','tang','','[]','洛岸秋晴夕照長，鳳樓龍闕倚清光。',64,'全唐诗/poet.tang.39000.json','["洛岸秋晴夕照長，鳳樓龍闕倚清光。", "玉泉山淨雲初散，金谷樹多風正涼。", "席上客知蓬島路，坐中寒有柏臺霜。", "多慙十載遊梁士，却伴賓鴻入帝鄉。"]'),
('f70fedff-3edb-49ed-bb93-1c21fbf4d652','題安定張使君','韋莊','唐','唐诗','tang','','[]','器度風標合出塵，桂宮何負一枝新。',64,'全唐诗/poet.tang.39000.json','["器度風標合出塵，桂宮何負一枝新。", "成丹始見金無滓，衝斗方知劒有神。", "憤氣不銷頭上雪，政聲空布海邊春。", "中興若繼開元事，堪向龍池作近臣。"]'),
('a599e4b8-aea5-40ff-8395-0179ba2601d2','潁陽縣','韋莊','唐','唐诗','tang','','[]','琴堂連少室，故事即僊蹤。',48,'全唐诗/poet.tang.39000.json','["琴堂連少室，故事即僊蹤。", "樹老風聲壯，山高臘候濃。", "雪多庭有鹿，縣僻寺無鐘。", "何處留詩客，茆簷倚後峰。"]'),
('8eb29d89-650a-490c-9052-d6164cb3c507','寄園林主人','韋莊','唐','唐诗','tang','','[]','主人常不在，春物爲誰開。',48,'全唐诗/poet.tang.39000.json','["主人常不在，春物爲誰開。", "桃豔紅將落，梨華雪又摧。", "曉鶯閑自囀，遊客暮空回。", "尚有餘芳在，猶堪載酒來。"]'),
('74b53b6c-d8bb-4e6d-95de-a38ba7d230fb','洛北村居','韋莊','唐','唐诗','tang','','[]','十畝松篁百畝田，歸來方屬大兵年。',64,'全唐诗/poet.tang.39000.json','["十畝松篁百畝田，歸來方屬大兵年。", "巖邊石室低臨水，雲外嵐峰半入天。", "鳥勢去投金谷樹，鐘聲遙出上陽煙。", "無人說得中興事，獨倚斜暉憶仲宣。"]'),
('3108e645-afe2-4f20-b8a8-cc280496b99c','對梨花贈皇甫秀才','韋莊','唐','唐诗','tang','','[]','林上梨花雪壓枝，獨攀瓊豔不勝悲。',64,'全唐诗/poet.tang.39000.json','["林上梨花雪壓枝，獨攀瓊豔不勝悲。", "依前此地逢君處，還是去年今日時。", "且戀殘陽留綺席，莫推紅袖訴金巵。", "騰騰戰鼓正多事，須信明朝難重持。"]'),
('83f75585-6e87-48f3-abea-6c8f4f313da6','立春','韋莊','唐','唐诗','tang','','[]','青帝東來日馭遲，煖煙輕逐曉風吹。',66,'全唐诗/poet.tang.39000.json','["青帝東來日馭遲，煖煙輕逐曉風吹。", "罽袍公子樽前覺，錦帳佳人夢裏知。", "雪圃乍開紅菜甲，綵幡新翦綠[楊]絲。", "殷勤爲作宜春曲，題向花牋帖繡楣。"]'),
('2c3d57ea-fd1b-477b-ad38-4dc5ccdee98c','村笛','韋莊','唐','唐诗','tang','','[]','簫韶九奏韻淒鏘，曲度雖高調不傷。',32,'全唐诗/poet.tang.39000.json','["簫韶九奏韻淒鏘，曲度雖高調不傷。", "却見孤村明月夜，一聲牛笛斷人腸。"]'),
('cf739c7c-1914-4edf-8884-a1fb81489574','題李斯傳','韋莊','唐','唐诗','tang','','[]','蜀魄湘魂萬古悲，未悲秦相死秦時。',32,'全唐诗/poet.tang.39000.json','["蜀魄湘魂萬古悲，未悲秦相死秦時。", "臨刑莫恨倉中鼠，上蔡東門去自遲。"]'),
('fb4cccdd-19eb-4bc6-9af1-17c9c17c1054','贈薛秀才','韋莊','唐','唐诗','tang','','[]','相辭因避世，相見尚兵戈。',48,'全唐诗/poet.tang.39000.json','["相辭因避世，相見尚兵戈。", "亂後故人少，別來新話多。", "但聞哀痛詔，未覩凱旋歌。", "欲結巖棲伴，何山好薜蘿。"]'),
('85bc0ae4-09e9-45a1-b774-8eac0761761a','和元秀才別業書事','韋莊','唐','唐诗','tang','','[]','僻居春事好，水曲亂花陰。',48,'全唐诗/poet.tang.39000.json','["僻居春事好，水曲亂花陰。", "浪過河移岸，雛成鳥別林。", "綠錢榆貫重，紅障杏籬深。", "莫飲宜城酒，愁多醉易沈。"]'),
('b63da6b7-c344-4eb8-8a7e-2d84182bbbc0','紀村事','韋莊','唐','唐诗','tang','','[]','綠蔓映雙扉，循牆一徑微。',36,'全唐诗/poet.tang.39000.json','["綠蔓映雙扉，循牆一徑微。", "雨多庭果爛，稻熟渚禽肥。", "釀酒迎新社，遙砧送暮暉。"]'),
('29c71fda-7e84-40ef-bacc-f6a56d3611b9','題許僊師院','韋莊','唐','唐诗','tang','','[]','地古多喬木，遊人到且吟。',48,'全唐诗/poet.tang.39000.json','["地古多喬木，遊人到且吟。", "院開金鏁澀，門映綠篁深。", "山色不離眼，鶴聲長在琴。", "往來誰與熟，乳鹿住前林。"]'),
('68713f88-a17f-44b6-851f-6509891c9d07','離筵訴酒','韋莊','唐','唐诗','tang','','[]','感君情重惜分離，送我殷勤酒滿巵。',32,'全唐诗/poet.tang.39000.json','["感君情重惜分離，送我殷勤酒滿巵。", "不是不能判酩酊，却憂前路酒醒時。"]'),
('0fc9d183-2cba-4dc9-9f02-432eac20fb45','不寐','韋莊','唐','唐诗','tang','','[]','不寐天將曉，心勞轉似灰。',48,'全唐诗/poet.tang.39000.json','["不寐天將曉，心勞轉似灰。", "蚊吟頻到耳，鼠鬬競緣臺。", "戶闇知蟾落，林喧覺雨來。", "馬嘶朝客過，知是禁門開。"]'),
('488af836-e0b1-4870-9395-8b8e9807c835','贈武處士','韋莊','唐','唐诗','tang','','[]','一身唯一室，高靜若僧家。',48,'全唐诗/poet.tang.39000.json','["一身唯一室，高靜若僧家。", "掃地留疎影，穿池浸落霞。", "綠蘿臨水合，白道向村斜。", "賣藥歸來醉，吟詩倚釣查。"]'),
('124efbed-003b-49c7-bd49-f261c2783f81','題吉澗盧拾遺莊','韋莊','唐','唐诗','tang','','[]','主人西遊去不歸，滿溪春雨長春薇。',32,'全唐诗/poet.tang.39000.json','["主人西遊去不歸，滿溪春雨長春薇。", "怪來馬上詩情好，印破青山白鷺飛。"]'),
('a15d8a30-1ee0-4feb-a36a-e6a09ea1039c','題潁源廟','韋莊','唐','唐诗','tang','','[]','曾是巢由棲隱地，百川唯說潁源清。',64,'全唐诗/poet.tang.39000.json','["曾是巢由棲隱地，百川唯說潁源清。", "微波乍向雲根吐，去浪遙衝雪嶂橫。", "萬木倚簷疎幹直，羣峰當戶曉嵐晴。", "臨川試問堯年事，猶被封人勸濯纓。"]'),
('8c16e0e4-700b-41c7-b153-706c566af80f','東遊遠歸','韋莊','唐','唐诗','tang','','[]','扣角干名計已疎，劒歌休恨食無魚。',64,'全唐诗/poet.tang.39000.json','["扣角干名計已疎，劒歌休恨食無魚。", "辭家柳絮三春半，臨路槐花七月初。", "江上欲尋漁父醉，日邊時得故人書。", "青雲不識楊生面，天子何由問子虛。"]'),
('5d507ed1-cbb0-44d3-86fa-948205151dc0','新正日商南道中作寄李明府','韋莊','唐','唐诗','tang','','[]','相看又見歲華新，依舊楊朱拭淚巾。',64,'全唐诗/poet.tang.39000.json','["相看又見歲華新，依舊楊朱拭淚巾。", "踏雪偶因尋戴客，論文還比聚星人。", "嵩山不改千年色，洛邑長生一路塵。", "今日與君同避世，却憐無事是家貧。"]'),
('fbeb3486-d194-411a-a183-2aa49cae2cbd','春暮','韋莊','唐','唐诗','tang','','[]','一春春事好，病酒起常遲。',48,'全唐诗/poet.tang.39000.json','["一春春事好，病酒起常遲。", "流水綠縈砌，落花紅墮枝。", "樓高喧乳燕，樹密鬬雛鸝。", "不學山公醉，將何自解頤。"]'),
('5ce677d6-4097-45c0-84d0-cdd4e32f323f','哭麻處士','韋莊','唐','唐诗','tang','','[]','却到歌吟地，閑門草色中。',48,'全唐诗/poet.tang.39000.json','["却到歌吟地，閑門草色中。", "百年流水盡，萬事落花空。", "繐帳扃秋月，詩樓鏁夜蟲。", "少微何處墮，留恨白楊風。"]'),
('50656f17-11ea-4510-93cf-2f71d066b5da','春早','韋莊','唐','唐诗','tang','','[]','聞鶯纔覺曉，閉戶已知晴。',24,'全唐诗/poet.tang.39000.json','["聞鶯纔覺曉，閉戶已知晴。", "一帶窗間月，斜穿枕上生。"]'),
('51e98317-94df-4341-b8d6-e8b6d7fd5830','和友人','韋莊','唐','唐诗','tang','','[]','閉門同隱士，不出動經時。',48,'全唐诗/poet.tang.39000.json','["閉門同隱士，不出動經時。", "靜閱王維畫，閑翻褚胤棋。", "落泉當戶急，殘月下窗遲。", "却想從來意，譙周亦自嗤。"]'),
('68acb362-79d9-4e09-83b4-dd485b591c0f','春愁','韋莊','唐','唐诗','tang','','[]','寓思本多傷，逢春恨更長。',48,'全唐诗/poet.tang.39000.json','["寓思本多傷，逢春恨更長。", "露霑湘竹淚，花墮越梅妝。", "睡怯交加夢，閑傾瀲灩觴。", "後庭人不到，斜月上松篁。"]'),
('45698e41-5984-476a-9915-01a2387c6e55','晚春','韋莊','唐','唐诗','tang','','[]','花開疑乍富，花落似初貧。',48,'全唐诗/poet.tang.39000.json','["花開疑乍富，花落似初貧。", "萬物不如酒，四時唯愛春。", "峨峨秦氏髻，皎皎洛川神。", "風月應相笑，年年醉病身。"]'),
('fa07a00e-a7a7-41fe-9d91-eb4883746c43','題許渾詩卷','韋莊','唐','唐诗','tang','','[]','江南才子許渾詩，字字清新句句奇。',34,'全唐诗/poet.tang.39000.json','["江南才子許渾詩，字字清新句句奇。", "十斛明珠量不盡，惠[休]虛作碧雲詞。"]'),
('df6c6cc5-3c70-48b0-a60f-821b4d2a963a','贈禮佛名者','韋莊','唐','唐诗','tang','','[]','何用辛勤禮佛名，我從無得到真庭。',32,'全唐诗/poet.tang.39000.json','["何用辛勤禮佛名，我從無得到真庭。", "尋思六祖傳心印，可是從來讀藏經。"]'),
('40518eb8-efa9-46df-98cc-bade54126f8a','殘花','韋莊','唐','唐诗','tang','','[]','和煙和露雪離披，金蘂紅鬚尚滿枝。',32,'全唐诗/poet.tang.39000.json','["和煙和露雪離披，金蘂紅鬚尚滿枝。", "十日笙歌一宵夢，苧蘿因雨失西施。"]'),
('bbeae8b0-813d-498b-b372-b461ccba5a82','上元縣','韋莊','唐','唐诗','tang','','[]','南朝三十六英雄，角逐興亡盡此中。',64,'全唐诗/poet.tang.39000.json','["南朝三十六英雄，角逐興亡盡此中。", "有國有家皆是夢，爲龍爲虎亦成空。", "殘花舊宅悲江令，落日青山弔謝公。", "止竟霸圖何物在，石麟無主臥秋風。"]'),
('34cc969e-c5b0-41a2-b965-d551a20e4a01','江上逢史館李學士','韋莊','唐','唐诗','tang','','[]','前年分袂陝城西，醉凭征軒日欲低。',64,'全唐诗/poet.tang.39000.json','["前年分袂陝城西，醉凭征軒日欲低。", "去浪指期魚必變，出門回首馬空嘶。", "關河自此爲征壘，城闕於今陷戰鼙。", "誰謂世途陵是谷，燕來還識舊巢泥。"]'),
('4c5b328d-2ab8-4f4d-a0c2-627b6cb0c92b','金陵圖','韋莊','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5510\u8bd7\u4e09\u767e\u9996", "\u9898\u753b", "\u4e03\u8a00\u7edd\u53e5", "\u548f\u53f2\u6000\u53e4", "\u5e26\u6709\u5730\u540d"]','誰謂傷心畫不成，畫人心逐世人情。',32,'全唐诗/poet.tang.39000.json','["誰謂傷心畫不成，畫人心逐世人情。", "君看六幅南朝事，老木寒雲滿故城。"]'),
('509ddbcb-a98e-4028-abf4-77890de85337','謁蔣帝廟','韋莊','唐','唐诗','tang','','[]','建業城邊蔣帝祠，素髯清骨舊風姿。',64,'全唐诗/poet.tang.39000.json','["建業城邊蔣帝祠，素髯清骨舊風姿。", "江聲似激秦軍破，山勢如匡晉祚危。", "殘雪嶺頭明組練，晚霞簷外簇旌旗。", "金陵客路方流落，空祝回鑾奠酒巵。"]'),
('34288a72-3109-4681-a1e3-629f08270d10','聞再幸梁洋','韋莊','唐','唐诗','tang','','[]','纔喜中原息戰鼙，又聞天子幸巴西。',64,'全唐诗/poet.tang.39000.json','["纔喜中原息戰鼙，又聞天子幸巴西。", "延燒魏闕非關燕，大狩陳倉不爲雞。", "興慶玉龍寒自躍，昭陵石馬夜空嘶。", "遙思萬里行宮夢，太白山前月欲低。"]'),
('4c9858ae-ae66-45fc-8486-4f7835697252','王道者','韋莊','唐','唐诗','tang','','[]','五雲遙指海中央，金鼎曾傳肘後方。',64,'全唐诗/poet.tang.39000.json','["五雲遙指海中央，金鼎曾傳肘後方。", "三島路岐空有月，十洲花木不知霜。", "因攜竹杖聞龍氣，爲使僊童帶橘香。", "應笑我曹身是夢，白頭猶自學詩狂。"]'),
('63205984-9e74-47a9-80a4-8cb18b081faa','陪金陵府相中堂夜宴','韋莊','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','滿耳笙歌滿眼花，滿樓珠翠勝吳娃。',64,'全唐诗/poet.tang.39000.json','["滿耳笙歌滿眼花，滿樓珠翠勝吳娃。", "因知海上神仙窟，只似人間富貴家。", "繡戶夜攢紅燭市，舞衣晴曳碧天霞。", "却愁宴罷青蛾散，楊子江頭月半斜。"]'),
('f157030d-da53-478c-886e-f082276da6f0','和侯秀才同友生泛舟溪中相招之作','韋莊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','嵇阮相將棹酒船，晚風侵浪水侵舷。',64,'全唐诗/poet.tang.39000.json','["嵇阮相將棹酒船，晚風侵浪水侵舷。", "輕如控鯉初離岸，遠似乘槎欲上天。", "雨外鳥歸吳苑樹，鏡中人入洞庭煙。", "憑君不用回舟疾，今夜西江月正圓。"]'),
('32d5b341-d935-4587-8d6f-f6176ee93c07','贈野童','韋莊','唐','唐诗','tang','','[]','羨爾無知野性真，亂搔蓬髮笑看人。',32,'全唐诗/poet.tang.39000.json','["羨爾無知野性真，亂搔蓬髮笑看人。", "閑衝暮雨騎牛去，肯問中興社稷臣。"]'),
('441d3c48-0cb8-48e9-a8af-96c7b568e5f9','代書寄馬','韋莊','唐','唐诗','tang','','[]','驅馳曾在五侯家，見說初生自渥洼。',64,'全唐诗/poet.tang.39000.json','["驅馳曾在五侯家，見說初生自渥洼。", "鬃白似披梁苑雪，頸肥如撲杏園花。", "休嫌綠綬嘶貧舍，好著紅纓入使衙。", "穩上雲衢千萬里，年年長踏魏堤沙。"]'),
('b0203630-bc4e-4e25-8dcf-41d0c48abb0b','題淮陰侯廟','韋莊','唐','唐诗','tang','','[]','滿把椒漿奠楚祠，碧幢黃鉞舊英威。',64,'全唐诗/poet.tang.39000.json','["滿把椒漿奠楚祠，碧幢黃鉞舊英威。", "能扶漢代成王業，忍見唐民陷戰機。", "雲夢去時高鳥盡，淮陰歸日故人稀。", "如何不借平齊策，空看長星落賊圍。"]'),
('69e3b34d-3c25-41c7-9fb0-ced2dc16aaeb','送崔郎中往使西川行在','韋莊','唐','唐诗','tang','','[]','拜書辭玉帳，萬里劒關長。',48,'全唐诗/poet.tang.39000.json','["拜書辭玉帳，萬里劒關長。", "新馬杏花色，綠袍春草香。", "一身朝玉陛，幾日過銅梁。", "莫戀爐邊醉，僊宮待侍郎。"]'),
('4e5e123f-cf58-4c07-b540-b9858810eba3','潤州顯濟閣曉望','韋莊','唐','唐诗','tang','','[]','清曉水如鏡，隔江人似鷗。',48,'全唐诗/poet.tang.39000.json','["清曉水如鏡，隔江人似鷗。", "遠煙藏海島，初日照揚州。", "地壯孫權氣，雲凝庾信愁。", "一篷何處客，吟凭釣魚舟。"]'),
('e78bbe6f-e671-496a-a78a-b590a8103635','觀淛西府相畋遊','韋莊','唐','唐诗','tang','','[]','十里旌旗十萬兵，等閑遊獵出軍城。',64,'全唐诗/poet.tang.39000.json','["十里旌旗十萬兵，等閑遊獵出軍城。", "紫袍日照金鵝鬬，紅斾風吹畫虎獰。", "帶箭彩禽雲外落，避鵰寒兔月中驚。", "歸來一路笙歌滿，更有僊娥載酒迎。"]'),
('84eefb8c-8cb7-4c6f-9966-89515e871a8e','官莊','韋莊','唐','唐诗','tang','','[]','誰氏園林一簇煙，路人遙指盡長歎。',32,'全唐诗/poet.tang.39000.json','["誰氏園林一簇煙，路人遙指盡長歎。", "桑田稻澤今無主，新犯香醪沒入官。"]'),
('50e96b09-fbdc-477f-aae6-f476cc67e742','解維','韋莊','唐','唐诗','tang','','[]','又解征帆落照中，暮程還過秣陵東。',32,'全唐诗/poet.tang.39000.json','["又解征帆落照中，暮程還過秣陵東。", "二年辛苦煙波裏，贏得風姿似釣翁。"]'),
('6f3ab383-a699-4921-b2c1-3b72a1bd8b99','雨霽池上作呈侯學士','韋莊','唐','唐诗','tang','','[]','鹿巾藜杖葛衣輕，雨歇池邊晚吹清。',32,'全唐诗/poet.tang.39000.json','["鹿巾藜杖葛衣輕，雨歇池邊晚吹清。", "正是如今江上好，白鱗紅稻紫蓴羹。"]'),
('1e26cdf0-1ef0-42c8-85ff-ed746dd74a2a','寓言','韋莊','唐','唐诗','tang','','[]','爲儒逢世亂，吾道欲何之。',48,'全唐诗/poet.tang.39000.json','["爲儒逢世亂，吾道欲何之。", "學劒已應晚，歸山今又遲。", "故人三載別，明月兩鄉悲。", "惆悵滄江上，星星鬢有絲。"]'),
('d36578a1-9756-4a64-89ab-da9292cd7fe6','哭同舍崔員外','韋莊','唐','唐诗','tang','','[]','却到同遊地，三年一電光。',48,'全唐诗/poet.tang.39000.json','["却到同遊地，三年一電光。", "池塘春草在，風燭故人亡。", "祭罷泉聲急，齋餘磬韻長。", "碧天應有恨，斜日弔松篁。"]'),
('e238f69a-5bed-4119-9935-bb921ed0cb04','題姑蘇凌處士莊','韋莊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一簇林亭返照間，門當官道不曾關。',64,'全唐诗/poet.tang.39000.json','["一簇林亭返照間，門當官道不曾關。", "花深遠岸黃鶯鬧，雨急春塘白鷺閑。", "載酒客尋吳苑寺，倚樓僧看洞庭山。", "怪來話得僊中事，新有人從物外還。"]'),
('7b80de46-ce5f-4800-9ff7-5434b0044b30','過當塗縣','韋莊','唐','唐诗','tang','','[]','客過當塗縣，停車訪舊遊。',48,'全唐诗/poet.tang.39000.json','["客過當塗縣，停車訪舊遊。", "謝公山有墅，李白酒無樓。", "采石花空發，烏江水自流。", "夕陽誰共感，寒鷺立汀洲。"]'),
('736031d7-69fe-4119-99b0-01e916bfe262','江亭酒醒却寄維揚餞客','韋莊','唐','唐诗','tang','','[]','別筵人散酒初醒，江步黃昏雨雪零。',32,'全唐诗/poet.tang.39000.json','["別筵人散酒初醒，江步黃昏雨雪零。", "滿坐綺羅皆不見，覺來紅樹背銀屏。"]'),
('9154fc22-5e19-45b7-a506-435298bb26fc','臺城','韋莊','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u666f", "\u6292\u60c5", "\u548f\u53f2\u6000\u53e4"]','江雨霏霏江草齊，六朝如夢鳥空啼。',32,'全唐诗/poet.tang.39000.json','["江雨霏霏江草齊，六朝如夢鳥空啼。", "無情最是臺城柳，依舊煙籠十里堤。"]'),
('b9401dc5-56b9-4866-be35-679626c5f64a','贈漁翁','韋莊','唐','唐诗','tang','','[]','草衣荷笠鬢如霜，自說家編楚水陽。',64,'全唐诗/poet.tang.39000.json','["草衣荷笠鬢如霜，自說家編楚水陽。", "滿岸秋風吹枳橘，遶陂煙雨種菰蔣。", "蘆刀夜鱠紅鱗膩，水甑朝蒸紫芋香。", "曾向五湖期范蠡，爾來空闊久相忘。"]'),
('37257869-211d-4819-9f27-57a061366ae7','過揚州','韋莊','唐','唐诗','tang','','[]','當年人未識兵戈，處處青樓夜夜歌。',64,'全唐诗/poet.tang.39000.json','["當年人未識兵戈，處處青樓夜夜歌。", "花發洞中春日永，月明衣上好風多。", "淮王去後無雞犬，煬帝歸來葬綺羅。", "二十四橋空寂寂，綠楊摧折舊官河。"]'),
('c2facde8-bd8f-4709-b90b-5c2f42fe614f','寄右省李起居','韋莊','唐','唐诗','tang','','[]','已向鴛行接雁行，便應雙拜紫薇郎。',64,'全唐诗/poet.tang.39000.json','["已向鴛行接雁行，便應雙拜紫薇郎。", "纔聞闕下徵書急，已覺回朝草詔忙。", "白馬似憐朱紱貴，綵衣遙惹御爐香。", "多慙十載遊梁客，未換青襟侍素王。"]'),
('a53a7f3b-2737-4143-9983-a116018e19d6','鑷白','韋莊','唐','唐诗','tang','','[]','白髮太無情，朝朝鑷又生。',48,'全唐诗/poet.tang.39000.json','["白髮太無情，朝朝鑷又生。", "始因絲一縷，漸至雪千莖。", "不避佳人笑，唯慙稚子驚。", "新年過半百，猶歎未休兵。"]'),
('e3db3890-d9ce-40fd-bd8f-a92800a1482b','漳亭驛小櫻桃','韋莊','唐','唐诗','tang','','[]','當年此樹正花開，五馬僊郎載酒來。',32,'全唐诗/poet.tang.39000.json','["當年此樹正花開，五馬僊郎載酒來。", "李白已亡工部死，何人堪伴玉山頹。"]'),
('fb8de1ea-1be9-40ee-b6d7-5274ed082893','酬吳秀才霅川相送','韋莊','唐','唐诗','tang','','[]','一葉南浮去似飛，楚鄉雲水本無依。',64,'全唐诗/poet.tang.39000.json','["一葉南浮去似飛，楚鄉雲水本無依。", "離心不忍聞春鳥，病眼何堪送落暉。", "摻袂客從花下散，棹舟人向鏡中歸。", "夫君別我應惆悵，十五年來識素衣。"]'),
('d1bc6416-c647-4a40-82be-70902023b227','對雨獨酌','韋莊','唐','唐诗','tang','','[]','榴花新釀綠於苔，對雨閑傾滿滿杯。',64,'全唐诗/poet.tang.39000.json','["榴花新釀綠於苔，對雨閑傾滿滿杯。", "荷鍤醉翁真達者，臥雲逋客竟悠哉。", "能詩豈是經時策，愛酒原非命世才。", "門外綠蘿連洞口，馬嘶應是步兵來。"]'),
('b2006807-1328-464b-8195-7b34ce3dfe8c','夏初與侯補闕江南有約同泛淮汴西赴行朝莊自九驛路先至甬橋補闕由淮楚續至泗上寢病旬日遽聞捐館回首悲慟因成長句四韻弔之','韋莊','唐','唐诗','tang','','[]','本約同來謁帝閽，忽隨川浪去東奔。',64,'全唐诗/poet.tang.39000.json','["本約同來謁帝閽，忽隨川浪去東奔。", "九重聖主方虛席，千里高堂尚倚門。", "世德只應榮伯仲，詩名終自付兒孫。", "遙憐月落清淮上，寂寞何人弔旅魂。"]'),
('0e8b9741-b085-4046-9286-818a528371ec','汴堤行','韋莊','唐','唐诗','tang','','[]','欲上隋堤舉步遲，隔雲烽燧呌非時。',64,'全唐诗/poet.tang.39000.json','["欲上隋堤舉步遲，隔雲烽燧呌非時。", "纔聞破虜將休馬，又道征遼再出師。", "朝見西來爲過客，暮看東去作浮屍。", "綠楊千里無飛鳥，日落空投舊店基。"]'),
('5cd47bbd-87f3-423a-a8df-50ba844166cb','旅次甬西見兒童以竹槍紙旗戲爲陣列主人叟曰斯子也三世沒於陣思所襲祖父讐余因感之','韋莊','唐','唐诗','tang','','[]','已聞三世沒軍營，又見兒孫學戰爭。',32,'全唐诗/poet.tang.39000.json','["已聞三世沒軍營，又見兒孫學戰爭。", "見爾此言堪慟哭，遣予何日望時平。"]'),
('9172174c-11ee-4dd7-b73b-96f114c72870','自孟津舟西上雨中作','韋莊','唐','唐诗','tang','','[]','秋煙漠漠與濛濛，不卷征帆任晚風。',64,'全唐诗/poet.tang.39000.json','["秋煙漠漠與濛濛，不卷征帆任晚風。", "百口寄安滄海上，一身逃難綠林中。", "來時楚岸楊花白，去日隋堤蓼穗紅。", "却到故園翻似客，歸心迢遞秣陵東。"]'),
('86697e59-7a96-46aa-86fa-b1e259e98c88','含山店夢覺作','韋莊','唐','唐诗','tang','','[]','曾爲流離慣別家，等閑揮袂客天涯。',32,'全唐诗/poet.tang.39000.json','["曾爲流離慣別家，等閑揮袂客天涯。", "燈前一覺江南夢，惆悵起來山月斜。"]'),
('eb8be5a9-e284-4791-ac39-c41b3f0bc06e','題貂黃嶺官軍','韋莊','唐','唐诗','tang','','[]','散騎蕭蕭下太行，遠從吳會去陳倉。',32,'全唐诗/poet.tang.39000.json','["散騎蕭蕭下太行，遠從吳會去陳倉。", "斜風細雨江亭上，盡日凭欄憶楚鄉。"]'),
('28a57ab5-4742-43d1-af23-35493b920a27','過內黃縣','韋莊','唐','唐诗','tang','','[]','相州吹角欲斜陽，匹馬搖鞭宿內黃。',64,'全唐诗/poet.tang.39000.json','["相州吹角欲斜陽，匹馬搖鞭宿內黃。", "僻縣不容投刺客，野陂時遇射鵰郎。", "雲中粉堞新城壘，店後荒郊舊戰場。", "猶指去程千萬里，秣陵煙樹在何鄉。"]'),
('dda99784-2b0e-42be-a063-68dfb28e3a93','雜感','韋莊','唐','唐诗','tang','','[]','莫悲建業荆榛滿，昔日繁華是帝京。',64,'全唐诗/poet.tang.39000.json','["莫悲建業荆榛滿，昔日繁華是帝京。", "莫愛廣陵臺榭好，也曾蕪沒作荒城。", "魚龍爵馬皆如夢，風月煙花豈有情。", "行客不勞頻悵望，古來朝市歎衰榮。"]'),
('2e5a8134-8f64-4ed8-8eb0-f2a5eedfa83c','垣縣山中尋李書記山居不遇留題河次店','韋莊','唐','唐诗','tang','','[]','白雲紅樹𡵻㟍東，名鳥羣飛古畫中。',32,'全唐诗/poet.tang.39000.json','["白雲紅樹𡵻㟍東，名鳥羣飛古畫中。", "僊吏不知何處隱，山南山北雨濛濛。"]'),
('8b023413-2be6-45e9-9c37-8ee395d805f8','送人遊幷汾','韋莊','唐','唐诗','tang','','[]','風雨蕭蕭欲暮秋，獨攜孤劒塞垣遊。',32,'全唐诗/poet.tang.39000.json','["風雨蕭蕭欲暮秋，獨攜孤劒塞垣遊。", "如今虜騎方南牧，莫過陰關第一州。"]'),
('43851f4d-e2cd-4226-b7f3-fb7637e43805','李氏小池亭十二韻','韋莊','唐','唐诗','tang','','[]','積石亂巉巉，庭莎綠不芟。',144,'全唐诗/poet.tang.39000.json','["積石亂巉巉，庭莎綠不芟。", "小橋低跨水，危檻半依巖。", "花落魚爭唼，櫻紅鳥競鵮。", "引泉疏地脈，掃絮積山嵌。", "古柳紅綃織，新篁紫綺緘。", "養猿秋嘯月，放鶴夜棲杉。", "枕簟谿雲膩，池塘海雨鹹。", "語窗雞逞辨，舐鼎犬偏饞。", "踏蘚青粘屐，攀蘿綠映衫。", "訪僧舟北渡，貰酒日西銜。", "遲客登高閣，題詩遶翠嵒。", "家藏何所寶，清韻滿琅函。"]'),
('3a40ecbf-4cfe-4f59-9402-3b372312722e','遣興','韋莊','唐','唐诗','tang','','[]','如幻如泡世，多愁多病身。',48,'全唐诗/poet.tang.39000.json','["如幻如泡世，多愁多病身。", "亂來知酒聖，貧去覺錢神。", "異國清明節，空江寂寞春。", "聲聲林上鳥，喚我北歸秦。"]'),
('8cfd98a7-5abc-4ffe-9626-03fc1445b98e','婺州和陸諫議將赴闕懷陽羨山居','韋莊','唐','唐诗','tang','','[]','望闕路仍遠，子牟魂欲飛。',48,'全唐诗/poet.tang.39000.json','["望闕路仍遠，子牟魂欲飛。", "道開燒藥鼎，僧寄臥雲衣。", "故國饒芳草，他山挂夕暉。", "東陽雖勝地，王粲奈思歸。"]'),
('05e3b507-d722-46ae-a723-a60fd1776422','江上題所居','韋莊','唐','唐诗','tang','','[]','故人相別盡朝天，苦竹江頭獨閉關。',64,'全唐诗/poet.tang.39000.json','["故人相別盡朝天，苦竹江頭獨閉關。", "落日亂蟬蕭帝寺，碧雲歸鳥謝家山。", "青州從事來偏熟，泉布先生老漸慳。", "不是對花長酩酊，永嘉時代不如閑。"]'),
('dfa4a789-a8cc-400c-a03b-cdea2490bb7a','婺州屏居蒙右省王拾遺車枉降訪病中延候不得因成寄謝','韋莊','唐','唐诗','tang','','[]','三年流落臥漳濱，王粲思家拭淚頻。',64,'全唐诗/poet.tang.39000.json','["三年流落臥漳濱，王粲思家拭淚頻。", "畫角莫吹殘月夜，病心方憶故園春。", "自爲江上樵蘇客，不識天邊侍從臣。", "怪得白鷗驚去盡，綠蘿門外有朱輪。"]'),
('cd042987-5f1a-4f3e-8401-97e8d1224cd0','將卜蘭芷村居留別郡中在仕','韋莊','唐','唐诗','tang','','[]','蘭芷江頭寄斷蓬，移家空載一颿風。',64,'全唐诗/poet.tang.39000.json','["蘭芷江頭寄斷蓬，移家空載一颿風。", "伯倫嗜酒還因亂，平子歸田不爲窮。", "避世漂零人境外，結茅依約畫屏中。", "從今隱去應難覓，深入蘆花作釣翁。"]'),
('87bc2877-47be-4f3a-9c53-225244438b55','和陸諫議避地寄東陽進退未決見寄','韋莊','唐','唐诗','tang','','[]','未歸天路紫雲深，暫駐東陽歲月侵。',64,'全唐诗/poet.tang.39000.json','["未歸天路紫雲深，暫駐東陽歲月侵。", "入洛聲華當世重，閔周章句滿朝吟。", "開爐夜看黃芽鼎，臥甕閑欹白玉簪。", "讀易草玄人不會，憂君心是致君心。"]'),
('b44839fc-4498-453a-80f6-77603cb86c2f','山墅閑題','韋莊','唐','唐诗','tang','','[]','邐迤前岡壓後岡，一川桑柘好殘陽。',64,'全唐诗/poet.tang.39000.json','["邐迤前岡壓後岡，一川桑柘好殘陽。", "主人饋餉炊紅黍，鄰父攜竿釣紫魴。", "靜極却嫌流水鬧，閑多翻笑野雲忙。", "有名不那無名客，獨閉衡門避建康。"]'),
('758f43ff-6f51-43ee-b08a-1729a6347023','江上逢故人','韋莊','唐','唐诗','tang','','[]','前年送我曲江西，紅杏園中醉似泥。',64,'全唐诗/poet.tang.39000.json','["前年送我曲江西，紅杏園中醉似泥。", "今日逢君越溪上，杜鵑花發鷓鴣啼。", "來時舊里人誰在，別後滄波路幾迷。", "江畔玉樓多美酒，仲宣懷土莫淒淒。"]'),
('2abf89ce-edda-4fd6-b35e-1fcdb37814ab','旅中感遇寄呈李秘書昆仲','韋莊','唐','唐诗','tang','','[]','南望愁雲鏁翠微，謝家樓閣雨霏霏。',64,'全唐诗/poet.tang.39000.json','["南望愁雲鏁翠微，謝家樓閣雨霏霏。", "劉楨病後新詩少，阮籍貧來好客稀。", "猶喜故人天外至，許將孤劒日邊歸。", "懷鄉不怕嚴陵笑，只待秋風別釣磯。"]'),
('67af398a-45dd-4b2f-98f9-06919708d697','送范評事入關','韋莊','唐','唐诗','tang','','[]','寂寥門戶寡相親，日日頻來只有君。',64,'全唐诗/poet.tang.39000.json','["寂寥門戶寡相親，日日頻來只有君。", "正喜琴尊長作伴，忽攜書劒遠辭羣。", "傷心柳色離亭見，聒耳蟬聲故國聞。", "爲報明年杏園客，與留絕豔待終軍。"]'),
('95d6d7ab-b5f6-4383-b1f0-791437da27f8','東陽酒家贈別二絕句 一','韋莊','唐','唐诗','tang','','[]','送君同上酒家樓，酩酊翻成一笑休。',32,'全唐诗/poet.tang.39000.json','["送君同上酒家樓，酩酊翻成一笑休。", "正是落花饒悵望，醉鄉前路莫回頭。"]'),
('8b036282-bbe4-43d9-9208-f52b29f000b3','東陽酒家贈別二絕句 二','韋莊','唐','唐诗','tang','','[]','天涯方歎異鄉身，又向天涯別故人。',32,'全唐诗/poet.tang.39000.json','["天涯方歎異鄉身，又向天涯別故人。", "明日五更孤店月，醉醒何處淚霑巾。"]'),
('6835208d-fa29-42aa-a166-f058dc9dec01','江上村居','韋莊','唐','唐诗','tang','','[]','本無踪跡戀柴扃，世亂須教識道情。',64,'全唐诗/poet.tang.39000.json','["本無踪跡戀柴扃，世亂須教識道情。", "顚倒夢魂愁裏得，撅奇詩句望中生。", "花緣豔絕栽難好，山爲看多詠不成。", "聞道漢軍新破虜，使來仍說近離京。"]'),
('0e893616-4568-4b65-b18f-949f4864935f','江外思鄉','韋莊','唐','唐诗','tang','','["\u601d\u4e61"]','年年春日異鄉悲，杜曲黃鶯可得知。',32,'全唐诗/poet.tang.39000.json','["年年春日異鄉悲，杜曲黃鶯可得知。", "更被夕陽江岸上，斷腸煙柳一絲絲。"]'),
('f58a6146-593f-4be1-aaf8-98493527d576','和鄭拾遺秋日感事一百韻','韋莊','唐','唐诗','tang','','[]','禍亂天心厭，流離客思傷。',288,'全唐诗/poet.tang.39000.json','["禍亂天心厭，流離客思傷。", "有家拋上國，無罪謫遐方。", "負笈將辭越，揚帆欲泛湘。", "避時難駐足，感事易回腸。", "雅道何銷德，妖星忽耀芒。", "中原初縱燎，下國竟探湯。", "盜據三秦地，兵纏八水鄉。", "戰塵輕犯闕，羽斾遠巡梁。", "自此修文代，俄成講武場。", "熊羆驅涿鹿，犀象走昆陽。", "御馬迷新棧，宮娥改舊妝。", "五丁功再覩，八難事難忘。", "鳳引金根疾，兵環玉弩彊。", "建牙雖可恃，摩壘詎能防。", "霍廟神遐遠，圯橋路杳茫。", "出師威似虎，禦敵狠如羊。", "眉畫猶思赤，巾裁未厭黃。", "晨趨鳴鐵騎，夜舞挹瓊觴。", "僭侈彤襜亂，諠呼繡𩭪攘。", "但聞爭曳組，詎見學垂韁。", "鵲印提新篆，龍泉奪曉霜。", "軍威徒逗撓，我武自維揚。", "負扆勞天眷，凝旒念國章。", "繡旗張畫獸，寶馬躍紅鴦。"]'),
('0998eaa1-544c-448c-9d3e-d7f4ecd17795','夢入關','韋莊','唐','唐诗','tang','','[]','夢中乘傳過關亭，南望蓮峰簇簇青。',32,'全唐诗/poet.tang.39000.json','["夢中乘傳過關亭，南望蓮峰簇簇青。", "馬上正吟歸去好，覺來江月滿前庭。"]'),
('76bb0a0b-55af-4272-a266-a56f8ec9832e','送人歸上國','韋莊','唐','唐诗','tang','','[]','送君江上日西斜，泣向江邊滿樹花。',32,'全唐诗/poet.tang.39000.json','["送君江上日西斜，泣向江邊滿樹花。", "若見青雲舊相識，爲言流落在天涯。"]'),
('0f7b07e0-a8bc-4f69-87bf-606faf0fd049','聞春鳥','韋莊','唐','唐诗','tang','','[]','雲晴春鳥滿江村，還似長安舊日聞。',32,'全唐诗/poet.tang.39000.json','["雲晴春鳥滿江村，還似長安舊日聞。", "紅杏花前應笑我，我今顦顇亦羞君。"]'),
('f7e085f0-2a77-4931-9522-1e42c4f78743','櫻桃樹','韋莊','唐','唐诗','tang','','[]','記得初生雪滿枝，和蜂和蝶帶花移。',32,'全唐诗/poet.tang.39000.json','["記得初生雪滿枝，和蜂和蝶帶花移。", "而今花落遊蜂去，空作主人惆悵詩。"]'),
('4b166d63-2fbc-4b40-8d6f-e09210b8b3bb','獨鶴','韋莊','唐','唐诗','tang','','[]','夕陽灘上立裴回，紅蓼風前雪翅開。',32,'全唐诗/poet.tang.39000.json','["夕陽灘上立裴回，紅蓼風前雪翅開。", "應爲不知棲宿處，幾回飛去又飛來。"]'),
('f6db22a7-5f21-4230-81b0-11879d7800c0','新栽竹','韋莊','唐','唐诗','tang','','[]','寂寞堦前見此君，遶欄吟罷却沾巾。',32,'全唐诗/poet.tang.39000.json','["寂寞堦前見此君，遶欄吟罷却沾巾。", "異鄉流落誰相識，唯有叢篁似主人。"]'),
('5d1baf09-b73e-44f0-9aa1-7930ed9ab662','稻田','韋莊','唐','唐诗','tang','','["\u559c\u60a6", "\u5199\u666f", "\u7530\u56ed"]','綠波春浪滿前陂，極目連雲䆉稏肥。',32,'全唐诗/poet.tang.39000.json','["綠波春浪滿前陂，極目連雲䆉稏肥。", "更被鷺鷀千點雪，破煙來入畫屏飛。"]'),
('37080749-b509-4d10-806e-6c44a8a92156','稻田','韋莊','唐','唐诗','tang','','[]','浪波春稻滿前坡，極目連雲𥝧稏肥。',32,'全唐诗/poet.tang.39000.json','["浪波春稻滿前坡，極目連雲𥝧稏肥。", "更被鷺鷥千㸃白，披烟來入畫屏飛。"]'),
('b491a2b9-392b-4444-bc77-e398aa84a9d0','庭前菊','韋莊','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u601d\u4e61", "\u548f\u7269\u8bd7"]','爲憶長安爛熳開，我今移爾滿庭栽。',32,'全唐诗/poet.tang.39000.json','["爲憶長安爛熳開，我今移爾滿庭栽。", "紅蘭莫笑青青色，曾向龍山泛酒來。"]'),
('9590d9ae-a6c8-40d4-ae4a-58c0c67f7cce','燕來','韋莊','唐','唐诗','tang','','[]','去歲辭巢別近鄰，今來空訝草堂新。',32,'全唐诗/poet.tang.39000.json','["去歲辭巢別近鄰，今來空訝草堂新。", "花開對語應相問，不是村中舊主人。"]'),
('5a4678f1-255a-43f4-bc96-92d6afd83034','倚柴關','韋莊','唐','唐诗','tang','','[]','杖策無言獨倚關，如癡如醉又如閑。',32,'全唐诗/poet.tang.39000.json','["杖策無言獨倚關，如癡如醉又如閑。", "孤吟盡日何人會，依約前山似故山。"]'),
('b1ff4374-9f50-403f-a9f9-8d74adb604ad','題七步廊','韋莊','唐','唐诗','tang','','[]','席門無計那殘陽，更接簷前七步廊。',32,'全唐诗/poet.tang.39000.json','["席門無計那殘陽，更接簷前七步廊。", "不羨東都丞相宅，每行吟得好篇章。"]'),
('990ed4ff-5bd3-47c5-90de-1a4b07d6132b','語松竹','韋莊','唐','唐诗','tang','','[]','庭前芳草綠於袍，堂上詩人欲二毛。',32,'全唐诗/poet.tang.39000.json','["庭前芳草綠於袍，堂上詩人欲二毛。", "多病不禁秋寂寞，雨松風竹莫騷騷。"]'),
('cf5704d0-bf00-47c9-9492-b7a8ab1217d8','不出院楚公','韋莊','唐','唐诗','tang','','[]','一自蟬關閉，心猿日漸馴。',48,'全唐诗/poet.tang.39000.json','["一自蟬關閉，心猿日漸馴。", "不知城郭路，稀識市朝人。", "履帶堦前雪，衣無寺外塵。", "却嫌山翠好，詩客往來頻。"]'),
('d26c4553-22c8-4621-b8ae-2147970b4f7e','江邊吟','韋莊','唐','唐诗','tang','','[]','江邊烽燧幾時休，江上行人雪滿頭。',64,'全唐诗/poet.tang.39000.json','["江邊烽燧幾時休，江上行人雪滿頭。", "誰信亂離花不見，只應惆悵水東流。", "陶潛政事千杯酒，張翰生涯一葉舟。", "若有片颿歸去好，可堪重倚仲宣樓。"]'),
('d8620f21-a69f-4121-81f2-1d7809a2d15e','江南送李明府入關','韋莊','唐','唐诗','tang','','[]','雨花煙柳傍江邨，流落天涯酒一罇。',64,'全唐诗/poet.tang.39000.json','["雨花煙柳傍江邨，流落天涯酒一罇。", "分首不辭多下淚，回頭唯恐更消魂。", "我爲孟館三千客，君繼寧王五代孫。", "正是中興磐石重，莫將顦顇入都門。"]'),
('d3aa7334-1431-4eb5-a820-bb73dd42c3f7','送福州王先輩南歸','韋莊','唐','唐诗','tang','','[]','豫章城下偶相逢，自說今方遇至公。',64,'全唐诗/poet.tang.39000.json','["豫章城下偶相逢，自說今方遇至公。", "八韻賦吟梁苑雪，六銖衣惹杏園風。", "名標玉籍僊壇上，家寄閩山畫障中。", "明日一杯何處別，綠楊煙岸雨濛濛。"]'),
('83dd52f0-e87f-4b5a-8432-a3c775baac9e','夜雪泛舟遊南溪','韋莊','唐','唐诗','tang','','[]','大江西面小溪斜，入竹穿松似若耶。',64,'全唐诗/poet.tang.39000.json','["大江西面小溪斜，入竹穿松似若耶。", "兩岸嚴風吹玉樹，一灘明月曬銀砂。", "因尋野渡逢漁舍，更泊前灣上酒家。", "去去不知歸路遠，棹聲煙裏獨嘔啞。"]'),
('1b7b7881-792e-4873-8486-510cf4532343','江行西望','韋莊','唐','唐诗','tang','','[]','西望長安白日遙，半年無事駐蘭橈。',32,'全唐诗/poet.tang.39000.json','["西望長安白日遙，半年無事駐蘭橈。", "欲將張翰秋江雨，畫作屏風寄鮑昭。"]'),
('06cfe600-30db-4c82-a20a-16a298187714','銅儀','韋莊','唐','唐诗','tang','','["\u957f\u6c5f"]','銅儀一夜變葭灰，暖律還吹嶺上梅。',64,'全唐诗/poet.tang.39000.json','["銅儀一夜變葭灰，暖律還吹嶺上梅。", "已喜漢官今再覩，更驚堯曆又重開。", "窗中遠岫青如黛，門外長江綠似苔。", "誰念閉關張仲蔚，滿庭春雨長蒿萊。"]'),
('ae620e35-8907-46cf-aeea-cd8dd79b7042','含香','韋莊','唐','唐诗','tang','','[]','含香高步已難陪，鶴到清霄勢未回。',64,'全唐诗/poet.tang.39000.json','["含香高步已難陪，鶴到清霄勢未回。", "遇物旋添芳草句，逢春寧滯碧雲才。", "微紅幾處花心吐，嫩綠誰家柳眼開。", "却去金鑾爲近侍，便辭鷗鳥不歸來。"]'),
('afd85777-84a9-4fb2-a14f-f3c46e3c55fd','春雲','韋莊','唐','唐诗','tang','','[]','春雲春水兩溶溶，倚郭樓臺晚翠濃。',64,'全唐诗/poet.tang.39000.json','["春雲春水兩溶溶，倚郭樓臺晚翠濃。", "山好只因人化石，地靈曾有劒爲龍。", "官辭鳳闕頻經歲，家住峨嵋第幾峰。", "王粲不知多少恨，夕陽吟斷一聲鐘。"]'),
('f4fd8930-b645-4cdc-a563-5eb869ca221e','雲散','韋莊','唐','唐诗','tang','','[]','雲散天邊落照和，關關春樹鳥聲多。',64,'全唐诗/poet.tang.39000.json','["雲散天邊落照和，關關春樹鳥聲多。", "劉伶避世唯沈醉，甯戚傷時亦浩歌。", "已恨歲華添皎鏡，更悲人事逐頹波。", "青雲自有鵷鴻待，莫說他山好薜蘿。"]'),
('dc2d6b98-8553-44f4-a398-78af5dd9fab9','袁州作','韋莊','唐','唐诗','tang','','[]','家家生計只琴書，一郡清風似魯儒。',64,'全唐诗/poet.tang.39000.json','["家家生計只琴書，一郡清風似魯儒。", "山色東南連紫府，水聲西北屬洪都。", "煙霞盡入新詩卷，郭邑閑開古畫圖。", "正是江村春酒熟，更聞春鳥勸提壺。"]'),
('1dabfd08-ff4b-4a8f-a56c-ade43678d853','題袁州謝秀才所居','韋莊','唐','唐诗','tang','','[]','主人年少已能詩，更有松軒挂夕暉。',64,'全唐诗/poet.tang.39000.json','["主人年少已能詩，更有松軒挂夕暉。", "芳草似袍連徑合，白雲如鳥傍簷飛。", "但將竹葉消春恨，莫遣楊花上客衣。", "若有前山好煙雨，與君吟到暝鐘歸。"]'),
('a939686e-42be-4670-95f4-2d498a171e4e','謁巫山廟','韋莊','唐','唐诗','tang','','[]','亂猿啼處訪高唐，路入煙霞草木香。',64,'全唐诗/poet.tang.39000.json','["亂猿啼處訪高唐，路入煙霞草木香。", "山色未能忘宋玉，水聲猶似哭襄王。", "朝朝暮暮陽臺下，爲雨爲雲楚國亡。", "惆悵廟前無限柳，春來空鬬畫眉長。"]'),
('921c572e-10bd-45e0-8e17-7813a1d951ef','鷓鴣','韋莊','唐','唐诗','tang','','[]','南禽無侶似相依，錦翅雙雙傍馬飛。',64,'全唐诗/poet.tang.39000.json','["南禽無侶似相依，錦翅雙雙傍馬飛。", "孤竹廟前啼暮雨，汨羅祠畔弔殘暉。", "秦人只解歌爲曲，越女空能畫作衣。", "懊惱澤家非有恨，年年長憶鳳城歸。"]'),
('cde536cb-cf79-4543-997c-768acd86d327','宿蓬船','韋莊','唐','唐诗','tang','','[]','夜來江雨宿蓬船，臥聽淋鈴不忍眠。',32,'全唐诗/poet.tang.39000.json','["夜來江雨宿蓬船，臥聽淋鈴不忍眠。", "却憶紫微情調逸，阻風中酒過年年。"]'),
('ccea0a0b-28d2-4a3e-8ce5-d8e4ae6f0cf2','送李秀才歸荆溪','韋莊','唐','唐诗','tang','','[]','八月中秋月正圓，送君吟上木蘭船。',64,'全唐诗/poet.tang.39000.json','["八月中秋月正圓，送君吟上木蘭船。", "人言格調勝玄度，我愛篇章敵浪僊。", "晚渡去時衝細雨，夜灘何處宿寒烟。", "楚王宮去陽臺近，莫倚風流滯少年。"]'),
('484132fe-901a-4d9b-959b-36ef00b1dbb1','洪州送西明寺省上人遊福建','韋莊','唐','唐诗','tang','','[]','記得初騎竹馬年，送師來往御溝邊。',64,'全唐诗/poet.tang.39000.json','["記得初騎竹馬年，送師來往御溝邊。", "荆榛已失當時路，槐柳全無舊日煙。", "遠自嵇山遊楚澤，又從廬岳去閩川。", "新春闕下應相見，紅杏花中覓酒僊。"]'),
('b41b9303-9afe-4bb9-8366-35aee44831ce','建昌渡暝吟','韋莊','唐','唐诗','tang','','[]','月照臨官渡，鄉情獨浩然。',48,'全唐诗/poet.tang.39000.json','["月照臨官渡，鄉情獨浩然。", "鳥棲彭蠡樹，月上建昌船。", "市散漁翁醉，樓深賈客眠。", "隔江何處笛，吹斷綠楊煙。"]'),
('d917a353-bf00-4ca1-bee4-f92974ac02c4','歲除對王秀才作','韋莊','唐','唐诗','tang','','[]','我惜今宵促，君愁玉漏頻。',48,'全唐诗/poet.tang.39000.json','["我惜今宵促，君愁玉漏頻。", "豈知新歲酒，猶作異鄉身。", "雪向寅前凍，花從子後春。", "到明追此會，俱是隔年人。"]'),
('397e7de1-fc07-419c-9941-9cedfc1d2d8f','酒渴愛江清','韋莊','唐','唐诗','tang','','[]','酒渴何方療，江波一掬清。',48,'全唐诗/poet.tang.39000.json','["酒渴何方療，江波一掬清。", "瀉甌如練色，漱齒作泉聲。", "味帶他山雪，光含白露精。", "只應千古後，長稱伯倫情。"]'),
('74065f92-6ff4-49db-b03d-c139668fc171','和李秀才郊墅早春吟興十韻','韋莊','唐','唐诗','tang','','["\u5e90\u5c71"]','暖律變寒光，東君景漸長。',120,'全唐诗/poet.tang.39000.json','["暖律變寒光，東君景漸長。", "我悲遊海嶠，君說住柴桑。", "雪色隨高嶽，冰聲陷古塘。", "草根微吐翠，梅朵半含霜。", "酒市多逋客，漁家足夜航。", "匡廬雲傍屋，彭蠡浪衝牀。", "綠擺楊枝嫩，紅挑菜甲香。", "鳳皇城已盡，鸚鵡賦應狂。", "佇見龍辭沼，寧憂雁失行。", "不應雙劒氣，長在斗牛傍。"]'),
('8627206a-8e17-462d-8bc4-06e716ddb304','泛鄱陽湖','韋莊','唐','唐诗','tang','','[]','四顧無邊鳥不飛，大波驚隔楚山微。',64,'全唐诗/poet.tang.39000.json','["四顧無邊鳥不飛，大波驚隔楚山微。", "紛紛雨外靈均過，瑟瑟雲中帝子歸。", "迸鯉似梭投遠浪，小舟如葉傍斜暉。", "鴟夷去後何人到，愛者雖多見者稀。"]'),
('9738a1c6-a764-4e9e-8161-43f6f265dea4','黃藤山下聞猿','韋莊','唐','唐诗','tang','','[]','黃藤山下駐歸程，一夜號猿弔旅情。',64,'全唐诗/poet.tang.39000.json','["黃藤山下駐歸程，一夜號猿弔旅情。", "入耳便能生百恨，斷腸何必待三聲。", "穿雲宿處人難見，望月啼時兔正明。", "好笑五陵年少客，壯心無事也沾纓。"]'),
('87776b10-6055-479e-8f55-79aaf37282af','章江作','韋莊','唐','唐诗','tang','','[]','杜陵歸客正裴回，玉笛誰家呌落梅。',64,'全唐诗/poet.tang.39000.json','["杜陵歸客正裴回，玉笛誰家呌落梅。", "之子棹從天外去，故人書自日邊來。", "楊花慢惹霏霏雨，竹葉閑傾滿滿杯。", "欲問維揚舊風月，一江紅樹亂猿哀。"]'),
('7e9bd994-9f57-4add-a7dc-0066cce3e269','南遊富陽江中作','韋莊','唐','唐诗','tang','','[]','南去又南去，此行非自期。',48,'全唐诗/poet.tang.39000.json','["南去又南去，此行非自期。", "一帆雲作伴，千里月相隨。", "浪跡花應笑，衰容鏡每知。", "鄉園不可問，禾黍正離離。"]'),
('127ef46b-ca56-49cb-ba92-11f1417659b3','饒州餘干縣琵琶洲有故韓賓客宣城裴尚書脩行李侍郎舊居遺址猶存客有過之感舊因以和吟','韋莊','唐','唐诗','tang','','[]','琵琶洲近斗牛星，鸞鳳曾於此放情。',64,'全唐诗/poet.tang.39000.json','["琵琶洲近斗牛星，鸞鳳曾於此放情。", "已覺地靈因昴降，更聞川媚有珠生。", "一灘紅樹留佳氣，萬古清弦續政聲。", "戟戶盡移天上去，里人空說舊簪纓。"]'),
('e65753e0-40ab-44a8-9f0d-bae8017c60ac','九江逢盧員外','韋莊','唐','唐诗','tang','','[]','前年風月宿琴堂，大媚僊山近帝鄉。',64,'全唐诗/poet.tang.39000.json','["前年風月宿琴堂，大媚僊山近帝鄉。", "別後幾沾新雨露，亂來猶記舊篇章。", "陶潛豈是銅符吏，田鳳終爲錦帳郎。", "莫怪相逢倍惆悵，九江煙月似瀟湘。"]'),
('e548022e-08e1-4baf-b6b2-458c030db8c7','南昌晚眺','韋莊','唐','唐诗','tang','','[]','南昌城郭枕江煙，章水悠悠浪拍天。',64,'全唐诗/poet.tang.39000.json','["南昌城郭枕江煙，章水悠悠浪拍天。", "芳草綠遮僊尉宅，落霞紅襯賈人船。", "霏霏閣上千山雨，嘒嘒雲中萬樹蟬。", "怪得地多章句客，庾家樓在斗牛邊。"]'),
('b0d09a6a-e710-4c48-a016-d85adedb53a5','衢州江上別李秀才','韋莊','唐','唐诗','tang','','[]','千山紅樹萬山雲，把酒相看日又曛。',32,'全唐诗/poet.tang.39000.json','["千山紅樹萬山雲，把酒相看日又曛。", "一曲離歌兩行淚，更知何地再逢君。"]'),
('12fa19e6-3d98-41ae-85be-0f313c243a0d','湘中作','韋莊','唐','唐诗','tang','','[]','千重煙樹萬重波，因便何妨弔汨羅。',64,'全唐诗/poet.tang.39000.json','["千重煙樹萬重波，因便何妨弔汨羅。", "楚地不知秦地亂，南人空怪北人多。", "臣心未肯教遷鼎，天道還應欲止戈。", "否去泰來終可待，夜寒休唱飯牛歌。"]'),
('c50ece82-7746-463e-abf4-5eb6ce3e6afd','桐廬縣作','韋莊','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','錢塘江盡到桐廬，水碧山青畫不如。',64,'全唐诗/poet.tang.39000.json','["錢塘江盡到桐廬，水碧山青畫不如。", "白羽鳥飛嚴子瀨，綠蓑人釣季鷹魚。", "潭心倒影時開合，谷口閑雲自卷舒。", "此境只應詞客愛，投文空弔木玄虛。"]'),
('57929676-0aff-416d-898a-c92712486519','東陽贈別','韋莊','唐','唐诗','tang','','[]','繡袍公子出旌旗，送我搖鞭入翠微。',64,'全唐诗/poet.tang.39000.json','["繡袍公子出旌旗，送我搖鞭入翠微。", "大抵行人難訴酒，就中辭客易沾衣。", "去時此地題橋去，歸日何年佩印歸。", "無限別情言不得，回看溪柳恨依依。"]'),
('e0f77079-cfbb-45d8-b5d9-57d54a8a8ce6','寄湖州舍弟','韋莊','唐','唐诗','tang','','[]','半年江上愴離襟，把得新詩喜又吟。',64,'全唐诗/poet.tang.39000.json','["半年江上愴離襟，把得新詩喜又吟。", "多病似逢秦氏藥，久貧如得顧家金。", "雲煙但有穿楊志，塵土多無作吏心。", "何況別來詞轉麗，不愁明代少知音。"]'),
('0b6c1ef7-6dd8-4470-aa2d-c9d2d425ca47','信州西三十里山名僊人城下有月巖山其狀秀拔中有山門如滿月之狀余因行役過其下聊賦是詩','韋莊','唐','唐诗','tang','','[]','驅車過閩越，路出饒陽西。',120,'全唐诗/poet.tang.39000.json','["驅車過閩越，路出饒陽西。", "僊山翠如畫，簇簇生虹蜺。", "羣峰若侍從，衆阜如嬰提。", "巖巒互吞吐，嶺岫相追攜。", "中有月輪滿，皎潔如圓珪。", "玉皇恣遊覽，到此神應迷。", "常娥曳霞帔，引我同攀躋。", "騰騰上天半，玉鏡懸飛梯。", "瑤池何悄悄，鸞鶴煙中棲。", "回頭望塵世，露下寒淒淒。"]'),
('d0ac7bd1-f833-450c-ad85-d718116734c6','婺州水館重陽日作','韋莊','唐','唐诗','tang','','[]','異國逢佳節，憑高獨苦吟。',48,'全唐诗/poet.tang.39000.json','["異國逢佳節，憑高獨苦吟。", "一杯今日醉，萬里故園心。", "水館紅蘭合，山城紫菊深。", "白衣雖不至，鷗鳥自相尋。"]'),
('4d8c2404-0f3d-43d4-b9bc-255a39c1c1e1','避地越中作','韋莊','唐','唐诗','tang','','[]','避世移家遠，天涯歲已周。',48,'全唐诗/poet.tang.39000.json','["避世移家遠，天涯歲已周。", "豈知今夜月，還是去年愁。", "露果珠沈水，風螢燭上樓。", "傷心潘騎省，華髮不禁秋。"]'),
('e8cee61b-ae15-4dd6-ace1-4b406efb5bef','撫州江口雨中作','韋莊','唐','唐诗','tang','','[]','江上閑衝細雨行，滿衣風灑綠荷聲。',32,'全唐诗/poet.tang.39000.json','["江上閑衝細雨行，滿衣風灑綠荷聲。", "金騮掉尾橫鞭望，猶指廬陵半日程。"]'),
('064394d6-3293-411e-8fd7-4b3088063efd','信州溪岸夜吟作','韋莊','唐','唐诗','tang','','[]','夜倚臨溪店，懷鄉獨苦吟。',48,'全唐诗/poet.tang.39000.json','["夜倚臨溪店，懷鄉獨苦吟。", "月當山頂出，星倚水湄沈。", "霧氣漁燈冷，鐘聲谷寺深。", "一城人悄悄，琪樹宿僊禽。"]'),
('c5bd3317-d0ec-4d23-9020-b0274d508296','訪潯陽友人不遇','韋莊','唐','唐诗','tang','','[]','不見安期悔上樓，寂寥人對鷺鷥愁。',32,'全唐诗/poet.tang.39000.json','["不見安期悔上樓，寂寥人對鷺鷥愁。", "蘆花雨急江煙暝，何處潺潺獨棹舟。"]'),
('886b1d8d-dbb7-4371-b57d-352dd24fec1c','東林寺再遇僧益大德','韋莊','唐','唐诗','tang','','[]','見師初事懿皇朝，三殿歸來白馬驕。',64,'全唐诗/poet.tang.39000.json','["見師初事懿皇朝，三殿歸來白馬驕。", "上講每教傾國聽，承恩偏得內官饒。", "當時可愛人如畫，今日相逢鬢已凋。", "若向君門逢舊友，爲傳音信到雲霄。"]'),
('ded1e6c4-1a76-4625-963a-0748e5197fd3','西塞山下作','韋莊','唐','唐诗','tang','','[]','西塞山前水似藍，亂雲如絮滿澄潭。',64,'全唐诗/poet.tang.39000.json','["西塞山前水似藍，亂雲如絮滿澄潭。", "孤峰漸映湓城北，片月斜生夢澤南。", "爨動曉煙烹紫蕨，露和香蔕摘黃柑。", "他年却棹扁舟去，終傍蘆花結一菴。"]'),
('8e14f1b6-a358-4c9d-86a0-bf0f7cb5e64e','齊安郡','韋莊','唐','唐诗','tang','','[]','彌棹齊安郡，孤城百戰殘。',48,'全唐诗/poet.tang.39000.json','["彌棹齊安郡，孤城百戰殘。", "傍村林有虎，帶郭縣無官。", "暮角梅花怨，清江桂影寒。", "黍離緣底事，撩我起長歎。"]'),
('82509d1a-e202-4331-a178-d05b325ec4a0','夏口行寄婺州諸弟','韋莊','唐','唐诗','tang','','[]','回頭煙樹各天涯，婺女星邊遠寄家。',64,'全唐诗/poet.tang.39000.json','["回頭煙樹各天涯，婺女星邊遠寄家。", "盡眼楚波連夢澤，滿衣春雪落江花。", "雙雙得伴爭如雁，一一歸巢却羨鵶。", "誰道我隨張博望，悠悠空外泛僊槎。"]'),
('11113074-30b2-4fa3-84ba-efcd8c8fd92a','南省伴直','韋莊','唐','唐诗','tang','','[]','文昌二十四僊曹，盡倚紅簷種露桃。',64,'全唐诗/poet.tang.39000.json','["文昌二十四僊曹，盡倚紅簷種露桃。", "一洞煙霞人迹少，六行槐柳鳥聲高。", "星分夜彩寒侵帳，蘭惹春香綠映袍。", "何事愛留詩客宿，滿庭風雨竹蕭騷。"]'),
('e713c00b-1987-46ab-9352-6e7495e2d0e1','鄠杜舊居二首 一','韋莊','唐','唐诗','tang','','[]','却到山陽事事非，谷雲谿鳥尚相依。',64,'全唐诗/poet.tang.39000.json','["却到山陽事事非，谷雲谿鳥尚相依。", "阮咸貧去田園盡，向秀歸來父老稀。", "秋雨幾家紅稻熟，野塘何處錦鱗肥？", "年年爲獻東堂策，長是蘆花別釣磯。"]'),
('5da86153-6ca9-4766-9b43-e281669e6e60','鄠杜舊居二首 二','韋莊','唐','唐诗','tang','','[]','一徑尋村渡碧溪，稻花香澤水千畦。',64,'全唐诗/poet.tang.39000.json','["一徑尋村渡碧溪，稻花香澤水千畦。", "雲中寺遠磬難識，竹裏巢深鳥易迷。", "紫菊亂開連井合，紅榴初綻拂簷低。", "歸來滿把如澠酒，何用傷時歎鳳兮。"]'),
('327cbf28-1b90-494c-92cd-99b9a50f25f6','寄江南諸弟','韋莊','唐','唐诗','tang','','[]','萬里逢歸雁，鄉書忍淚封。',48,'全唐诗/poet.tang.39000.json','["萬里逢歸雁，鄉書忍淚封。", "吾身不自保，爾道各何從。", "性拙唯多蹇，家貧半爲慵。", "祗思溪影上，臥看玉華峰。"]'),
('e510e2a2-f4c3-4954-bcd4-4bd09e9b7b0e','投寄舊知','韋莊','唐','唐诗','tang','','[]','却將顦顇入都門，自喜青霄足故人。',64,'全唐诗/poet.tang.39000.json','["却將顦顇入都門，自喜青霄足故人。", "萬里有家留百越，十年無路到三秦。", "摧殘不是當時貌，流落空餘舊日貧。", "多謝青雲好知己，莫教歸去重沾巾。"]'),
('528b3005-3a06-4b52-861c-e6e573615e5a','癸丑年下第獻新先輩','韋莊','唐','唐诗','tang','','[]','五更殘月省牆邊，絳斾蜺旌卓曉煙。',96,'全唐诗/poet.tang.39000.json','["五更殘月省牆邊，絳斾蜺旌卓曉煙。", "千炬火中鶯出谷，一聲鐘後鶴沖天。", "皆乘駿馬先歸去，獨被羸童笑晚眠。", "對酒暫時情豁爾，見花依舊涕潸然。", "未酬闞澤傭書債，猶欠君平賣卜錢。", "何事欲休休不得，來年公道似今年。"]'),
('c13e0174-866c-443e-b891-c15311f2d06f','題汧陽縣馬跑泉李學士別業','韋莊','唐','唐诗','tang','','[]','水滿寒塘菊滿籬，籬邊無限彩禽飛。',64,'全唐诗/poet.tang.39000.json','["水滿寒塘菊滿籬，籬邊無限彩禽飛。", "西園夜雨紅櫻熟，南畝清風白稻肥。", "草色自留閑客住，泉聲如待主人歸。", "九霄岐路忙於火，肯戀斜陽守釣磯。"]'),
('918eefe5-fd66-441d-ac06-01ad799fb485','絳州過夏留獻鄭尚書','韋莊','唐','唐诗','tang','','[]','朝朝沈醉引金船，不覺西風滿樹蟬。',64,'全唐诗/poet.tang.39000.json','["朝朝沈醉引金船，不覺西風滿樹蟬。", "光景暗消銀燭下，夢魂長寄玉輪邊。", "因循每被時流誚，奮發須由國士憐。", "明月客腸何處斷，綠槐風裏獨揚鞭。"]'),
('9148b00d-5d70-4ecb-8547-0c67ad92d70a','綏州作','韋莊','唐','唐诗','tang','','[]','雕陰無樹水難流，雉堞連雲古帝州。',64,'全唐诗/poet.tang.39000.json','["雕陰無樹水難流，雉堞連雲古帝州。", "帶雨晚駝鳴遠戍，望鄉孤客倚高樓。", "明妃去日花應笑，蔡琰歸時鬢已秋。", "一曲單于暮烽起，扶蘇城上月如鉤。"]'),
('57e8a2e9-6299-425b-a852-0d5c05795d53','與東吳生相遇','韋莊','唐','唐诗','tang','','[]','十年身事各如萍，白首相逢淚滿纓。',64,'全唐诗/poet.tang.39000.json','["十年身事各如萍，白首相逢淚滿纓。", "老去不知花有態，亂來唯覺酒多情。", "貧疑陋巷春偏少，貴想豪家月最明。", "且對一尊開口笑，未衰應見泰階平。"]'),
('4593e8cb-0fb8-42dc-bffc-1f6fd3d27ef0','庭前桃','韋莊','唐','唐诗','tang','','[]','曾向桃源爛漫遊，也同漁父泛僊舟。',64,'全唐诗/poet.tang.39000.json','["曾向桃源爛漫遊，也同漁父泛僊舟。", "皆言洞裏千株好，未勝庭前一樹幽。", "帶露似垂湘女淚，無言如伴息媯愁。", "五陵公子饒春恨，莫引香風上酒樓。"]'),
('4f1703e7-d04b-4505-9a4b-de9fee595295','丙辰年鄜州遇寒食城外醉吟五首 一','韋莊','唐','唐诗','tang','','[]','滿街楊柳綠絲煙，畫出清明二月天。',32,'全唐诗/poet.tang.39000.json','["滿街楊柳綠絲煙，畫出清明二月天。", "好是隔簾花樹動，女郎撩亂送鞦韆。"]'),
('86f7170b-c795-4d80-976d-50a418c25be2','丙辰年鄜州遇寒食城外醉吟五首 二','韋莊','唐','唐诗','tang','','[]','雕陰寒食足遊人，金鳳羅衣濕麝薰。',32,'全唐诗/poet.tang.39000.json','["雕陰寒食足遊人，金鳳羅衣濕麝薰。", "腸斷入城芳草路，淡紅香白一羣羣。"]'),
('31b2a994-69ac-450e-9990-7daa5fb589ac','丙辰年鄜州遇寒食城外醉吟五首 三','韋莊','唐','唐诗','tang','','[]','開元坡下日初斜，拜掃歸來走鈿車。',32,'全唐诗/poet.tang.39000.json','["開元坡下日初斜，拜掃歸來走鈿車。", "可惜數株紅豔好，不知今夜落誰家。"]'),
('cb7de205-d319-4733-95a6-180dca8f2ccf','丙辰年鄜州遇寒食城外醉吟五首 四','韋莊','唐','唐诗','tang','','[]','馬驕風疾玉鞭長，過去唯留一陣香。',32,'全唐诗/poet.tang.39000.json','["馬驕風疾玉鞭長，過去唯留一陣香。", "閑客不須燒破眼，好花皆屬富家郎。"]'),
('d5fe79be-8580-4f5f-a180-8ea68b92f531','丙辰年鄜州遇寒食城外醉吟五首 五','韋莊','唐','唐诗','tang','','[]','雨絲煙柳欲清明，金屋人閑煖鳳笙。',32,'全唐诗/poet.tang.39000.json','["雨絲煙柳欲清明，金屋人閑煖鳳笙。", "永日迢迢無一事，隔街聞築氣毬聲。"]'),
('aadf0d8f-e53c-4c0d-b5f5-8f412df86aa2','宜君縣比卜居不遂留題王秀才別墅二首 一','韋莊','唐','唐诗','tang','','[]','本期同此臥林丘，榾柮爐前擁布裘。',32,'全唐诗/poet.tang.39000.json','["本期同此臥林丘，榾柮爐前擁布裘。", "何事却騎羸馬去，白雲紅樹不相留。"]'),
('b17f1411-673f-4a4b-b75b-61b01d7f65b4','宜君縣比卜居不遂留題王秀才別墅二首 二','韋莊','唐','唐诗','tang','','[]','明月嚴霜撲皁貂，羨君高臥正逍遙。',32,'全唐诗/poet.tang.39000.json','["明月嚴霜撲皁貂，羨君高臥正逍遙。", "門前積雪深三尺，火滿紅爐酒滿瓢。"]'),
('9d7122f6-a1d3-4219-8be7-64ddd46aa3c5','鄜州留別張員外','韋莊','唐','唐诗','tang','','[]','江南相送君山下，塞北相逢朔漠中。',64,'全唐诗/poet.tang.39000.json','["江南相送君山下，塞北相逢朔漠中。", "三楚故人皆是夢，十年陳事只如風。", "莫言身世他時異，且喜琴尊數日同。", "惆悵却愁明日別，馬嘶山店雨濛濛。"]'),
('5eddc04b-8923-41ae-87b6-653330c8087d','病中聞相府夜宴戲贈集賢盧學士','韋莊','唐','唐诗','tang','','[]','滿筵紅蠟照香鈿，一夜歌鐘欲沸天。',64,'全唐诗/poet.tang.39000.json','["滿筵紅蠟照香鈿，一夜歌鐘欲沸天。", "花裏亂飛金錯落，月中爭認繡連乾。", "尊前莫話詩三百，醉後寧辭酒十千。", "無那兩三新進士，風流長得飲徒憐。"]'),
('d75c1f73-ae54-4f10-9ffc-7f6c00209595','出關','韋莊','唐','唐诗','tang','','[]','馬嘶煙岸柳陰斜，東去關山路轉賒。',64,'全唐诗/poet.tang.39000.json','["馬嘶煙岸柳陰斜，東去關山路轉賒。", "到處因循緣嗜酒，一生惆悵爲判花。", "危時祗合身無著，白日那堪事有涯。", "正是灞陵春酬綠，仲宣何事獨辭家。"]'),
('3c0eead3-d227-4a76-a6c8-630d3fbe7c0f','過樊川舊居','韋莊','唐','唐诗','tang','','[]','却到樊川訪舊遊，夕陽衰草杜陵秋。',64,'全唐诗/poet.tang.39000.json','["却到樊川訪舊遊，夕陽衰草杜陵秋。", "應劉去後苔生閣，稽阮歸來雪滿頭。", "能說亂離惟有燕，解偷閑暇不如鷗。", "千桑萬海無人見，橫笛一聲空淚流。"]'),
('2aa34f46-9cd6-471a-af8e-e79889cd8fdf','長安舊里','韋莊','唐','唐诗','tang','','[]','滿目牆匡春草深，傷時傷事更傷心。',32,'全唐诗/poet.tang.39000.json','["滿目牆匡春草深，傷時傷事更傷心。", "車輪馬跡今何在，十二玉樓無處尋。"]'),
('38e6bd79-75ae-4500-9987-530ce51ade47','過渼陂懷舊','韋莊','唐','唐诗','tang','','[]','辛勤曾寄玉峰前，一別雲溪二十年。',64,'全唐诗/poet.tang.39000.json','["辛勤曾寄玉峰前，一別雲溪二十年。", "三徑荒涼迷竹樹，四鄰凋謝變桑田。", "渼陂可是當時事，紫閣空餘舊日煙。", "多少亂離無處問，夕陽吟罷涕潸然。"]'),
('2e9a3500-fb1c-4883-9441-37a4903a9ecd','汧陽間','韋莊','唐','唐诗','tang','','[]','汧水悠悠去似絣，遠山如畫翠眉橫。',64,'全唐诗/poet.tang.39000.json','["汧水悠悠去似絣，遠山如畫翠眉橫。", "僧尋野渡歸吳嶽，雁帶斜陽入渭城。", "邊靜不收蕃帳馬，地貧惟賣隴山鸚。", "牧童何處吹羌笛，一曲梅花出塞聲。"]'),
('d8b2519b-9b24-4f9c-83c0-f66430c0e137','焦崖閣','韋莊','唐','唐诗','tang','','[]','李白曾歌蜀道難，長聞白日上青天。',32,'全唐诗/poet.tang.39000.json','["李白曾歌蜀道難，長聞白日上青天。", "今朝夜過焦崖閣，始信星河在馬前。"]'),
('c8b6a8eb-8f4c-45ab-9030-0ac8d55d6174','雞公幘','韋莊','唐','唐诗','tang','','[]','石狀雖如幘，山形可類雞。',48,'全唐诗/poet.tang.39000.json','["石狀雖如幘，山形可類雞。", "向風疑欲鬬，帶雨似聞啼。", "蔓織青籠合，松長翠羽低。", "不鳴非有意，爲怕客奔齊。"]'),
('6065f389-5f50-4804-8c2e-2e094104cc42','平陵老將','韋莊','唐','唐诗','tang','','[]','白羽金僕姑，腰懸雙轆轤。',48,'全唐诗/poet.tang.39000.json','["白羽金僕姑，腰懸雙轆轤。", "前年蔥嶺北，獨戰雲中胡。", "匹馬塞垣老，一身如鳥孤。", "歸來辭第宅，却占平陵居。"]'),
('e843268a-0cbd-4f2d-b446-9797ec76e51e','即事','韋莊','唐','唐诗','tang','','[]','亂世時偏促，陰天日易昏。',24,'全唐诗/poet.tang.39000.json','["亂世時偏促，陰天日易昏。", "無言搔白首，憔悴倚東門。"]'),
('87170517-a2da-4b5e-93a1-8c302b707417','姬人養蠶','韋莊','唐','唐诗','tang','','[]','昔年愛笑蠶家婦，今日辛勤自養蠶。',32,'全唐诗/poet.tang.39000.json','["昔年愛笑蠶家婦，今日辛勤自養蠶。", "仍道不愁羅與綺，女郎初解織桑籃。"]'),
('aa5690a4-1392-4de3-984d-37311fdcda37','長干塘別徐茂才','韋莊','唐','唐诗','tang','','[]','亂離時節別離輕，別酒應須滿滿傾。',32,'全唐诗/poet.tang.39000.json','["亂離時節別離輕，別酒應須滿滿傾。", "纔喜相逢又相送，有情爭得似無情。"]'),
('7cb5b066-9685-45d5-8a1d-f2e59d494efb','勉兒子','韋莊','唐','唐诗','tang','','[]','養爾逢多難，常憂學已遲。',24,'全唐诗/poet.tang.39000.json','["養爾逢多難，常憂學已遲。", "辟彊爲上相，何必待從師。"]'),
('76bf8b2e-a6dc-4102-9f91-5f029b692596','乞彩牋歌','韋莊','唐','唐诗','tang','','[]','浣花溪上如花客，綠闇紅藏人不識。',192,'全唐诗/poet.tang.39000.json','["浣花溪上如花客，綠闇紅藏人不識。", "留得溪頭瑟瑟波，潑成紙上猩猩色。", "手把金刀擘綵雲，有時翦破秋天碧。", "不使紅霓段段飛，一時驅上丹霞壁。", "蜀客才多染不供，卓文醉後開無力。", "孔雀銜來向日飛，翩翩壓折黃金翼。", "我有歌詩一千首，磨礱山岳羅星斗。", "開卷長疑雷電驚，揮毫只怕龍蛇走。", "班班布在時人口，滿袖松花都未有。", "人間無處買煙霞，須知得自神僊手。", "也知價重連城璧，一紙萬金猶不惜。", "薛濤昨夜夢中來，殷勤勸向君邊覓。"]'),
('63428866-f599-4162-a3f1-9052f4d2a8c4','白牡丹','韋莊','唐','唐诗','tang','','[]','閨中莫妬新妝歸，陌上須慚傅粉郎。',32,'全唐诗/poet.tang.39000.json','["閨中莫妬新妝歸，陌上須慚傅粉郎。", "昨夜月明渾似水，入門唯覺一庭香。"]'),
('cd1a591e-98c5-406d-97e9-6f90592b1bfe','憫耕者','韋莊','唐','唐诗','tang','','[]','何代何王不戰爭，盡從離亂見清平。',32,'全唐诗/poet.tang.39000.json','["何代何王不戰爭，盡從離亂見清平。", "如今暴骨多於土，猶點鄉兵作戍兵。"]'),
('7b6f6b37-fcd3-46aa-8422-094e4d6073fc','壺關道中作','韋莊','唐','唐诗','tang','','[]','處處兵戈路不通，却從山北去江東。',32,'全唐诗/poet.tang.39000.json','["處處兵戈路不通，却從山北去江東。", "黃昏欲到壺關寨，匹馬寒嘶野草中。"]'),
('e0184140-23d9-4d27-976d-fca298b2ed6e','題酒家','韋莊','唐','唐诗','tang','','[]','酒綠花紅客愛詩，落花春岸酒家旗。',32,'全唐诗/poet.tang.39000.json','["酒綠花紅客愛詩，落花春岸酒家旗。", "尋思避世爲逋客，不醉長醒也是癡。"]'),
('a05bb44d-92fc-4844-8e29-375615b688e0','寄舍弟','韋莊','唐','唐诗','tang','','[]','每吟富貴他人合，不覺汍瀾又濕衣。',32,'全唐诗/poet.tang.39000.json','["每吟富貴他人合，不覺汍瀾又濕衣。", "萬里日邊鄉樹遠，何年何路得同歸。"]'),
('6a167cfa-b286-4b7b-85d4-93de02e319a0','僕者楊金','韋莊','唐','唐诗','tang','','[]','半年辛苦葺荒居，不獨單寒腹亦虛。',32,'全唐诗/poet.tang.39000.json','["半年辛苦葺荒居，不獨單寒腹亦虛。", "努力且爲田舍客，他年爲爾覓金魚。"]'),
('e0d19572-f0e9-4af7-9b32-9c33d722b4c7','春陌二首 一','韋莊','唐','唐诗','tang','','[]','滿街芳草卓香車，僊子門前白日斜。',32,'全唐诗/poet.tang.39000.json','["滿街芳草卓香車，僊子門前白日斜。", "腸斷東風各回首，一枝春雪凍梅花。"]'),
('00729e0e-ac41-4e31-b2df-f09c4c54eff2','春陌二首 二','韋莊','唐','唐诗','tang','','[]','嫩煙輕染柳絲黃，句引花枝笑凭牆。',32,'全唐诗/poet.tang.39000.json','["嫩煙輕染柳絲黃，句引花枝笑凭牆。", "馬上王孫莫回首，好風偏逐羽林郎。"]'),
('949fcea1-ca0f-459f-a0c8-f91043bce4ee','贈姬人','韋莊','唐','唐诗','tang','','[]','莫恨紅裙破，休嫌白屋低。',24,'全唐诗/poet.tang.39000.json','["莫恨紅裙破，休嫌白屋低。", "請看京與洛，誰在舊香閨。"]'),
('fc053859-773f-4bdf-945d-15dc749b9c49','中酒','韋莊','唐','唐诗','tang','','[]','南鄰酒熟愛相招，蘸甲傾來綠滿瓢。',32,'全唐诗/poet.tang.39000.json','["南鄰酒熟愛相招，蘸甲傾來綠滿瓢。", "一醉不知三日事，任他童穉作漁樵。"]'),
('b42a2989-20e1-4283-a5e7-79db9f265518','暴雨','韋莊','唐','唐诗','tang','','[]','江村入夏多雷雨，曉作狂霖晚又晴。',32,'全唐诗/poet.tang.39000.json','["江村入夏多雷雨，曉作狂霖晚又晴。", "波浪不知深幾許，南湖今與北湖平。"]'),
('484213a8-72ee-46a7-80df-3725590b2ce2','悼亡姬','韋莊','唐','唐诗','tang','','[]','鳳去鸞歸不可尋，十洲仙路彩雲深。',48,'全唐诗/poet.tang.39000.json','["鳳去鸞歸不可尋，十洲仙路彩雲深。", "若無少女花應老，爲有姮娥月易沈。", "竹葉豈能消積恨，丁香空解結同心。"]'),
('65a62527-e0bd-40f1-9d8b-4b6c9a4fff49','獨吟','韋莊','唐','唐诗','tang','','[]','默默無言惻惻悲，閑吟獨傍菊花籬。',64,'全唐诗/poet.tang.39000.json','["默默無言惻惻悲，閑吟獨傍菊花籬。", "只今已作經年別，此後如爲幾歲期。", "開篋每尋遺念物，倚樓空綴悼亡詩。", "夜來孤枕空腸斷，窗月斜輝夢覺時。"]'),
('589d516f-cbb9-442e-90fe-033410af3057','悔恨','韋莊','唐','唐诗','tang','','[]','六七年來春又秋，也同歡笑也同愁。',64,'全唐诗/poet.tang.39000.json','["六七年來春又秋，也同歡笑也同愁。", "纔聞及第心先喜，試說求婚淚便流。", "幾爲妒來頻斂黛，每思閑事不梳頭。", "如今悔恨將何益，腸斷千休與萬休。"]'),
('a8fb4bc0-33bb-468e-8292-047eacaf2703','虛席','韋莊','唐','唐诗','tang','','[]','一閉香閨後，羅衣盡施僧。',48,'全唐诗/poet.tang.39000.json','["一閉香閨後，羅衣盡施僧。", "鼠偷筵上果，蛾撲帳前燈。", "土蝕釵無鳳，塵生鏡少菱。", "有時還影響，花葉曳香繒。"]'),
('379bca5e-f317-4c48-abe8-4d5e1269d902','舊居','韋莊','唐','唐诗','tang','','[]','芳草又芳草，故人楊子家。',48,'全唐诗/poet.tang.39000.json','["芳草又芳草，故人楊子家。", "青雲容易散，白日等閑斜。", "皓質留殘雪，香魂逐斷霞。", "不知何處笛，一夜呌梅花。"]'),
('83f1050c-d2e0-4552-aa14-0917ab9de08f','晏起','韋莊','唐','唐诗','tang','','[]','爾來中酒起常遲，臥看南山改舊詩。',32,'全唐诗/poet.tang.39000.json','["爾來中酒起常遲，臥看南山改舊詩。", "開戶日高春寂寂，數聲啼鳥上花枝。"]'),
('2ed6550a-7281-4ea9-994a-14a2469e7d44','幽居春思','韋莊','唐','唐诗','tang','','[]','綠映紅藏江上村，一聲雞犬似山源。',32,'全唐诗/poet.tang.39000.json','["綠映紅藏江上村，一聲雞犬似山源。", "閉門盡日無人到，翠羽春禽滿樹喧。"]'),
('b39275f0-34a2-46c3-9230-5815af62c677','思歸引','韋莊','唐','唐诗','tang','','[]','越鳥南翔鴈北飛，兩鄉雲路各言歸。',32,'全唐诗/poet.tang.39000.json','["越鳥南翔鴈北飛，兩鄉雲路各言歸。", "如何我是飄飄者，獨向江頭戀釣磯。"]'),
('f2a48a3c-edfe-4102-941e-8a2c911e9236','與小女','韋莊','唐','唐诗','tang','','["\u513f\u7ae5"]','見人初解語嘔啞，不肯歸眠戀小車。',32,'全唐诗/poet.tang.39000.json','["見人初解語嘔啞，不肯歸眠戀小車。", "一夜嬌啼緣底事，爲嫌衣少縷金華。"]'),
('c53dcfc2-1eee-4f2a-a8ec-d1a476f9d9dd','虎跡','韋莊','唐','唐诗','tang','','[]','白額頻頻夜到門，水邊蹤跡漸成羣。',32,'全唐诗/poet.tang.39000.json','["白額頻頻夜到門，水邊蹤跡漸成羣。", "我今避世棲巖穴，巖穴如何又見君。"]'),
('e7722c42-54cc-447a-b197-5499d5fd8336','買酒不得','韋莊','唐','唐诗','tang','','[]','停尊待爾怪來遲，手挈空缾毷氉歸。',32,'全唐诗/poet.tang.39000.json','["停尊待爾怪來遲，手挈空缾毷氉歸。", "滿面春愁消不得，更看溪鷺寂寥飛。"]'),
('3cba95d3-3473-4bfa-9d5f-9aaa2915d887','得故人書','韋莊','唐','唐诗','tang','','[]','正向溪頭自采蘇，青雲忽得故人書。',32,'全唐诗/poet.tang.39000.json','["正向溪頭自采蘇，青雲忽得故人書。", "殷勤問我歸來否，雙闕而今畫不如。"]'),
('d17c423d-4847-42f9-accf-f3d1264db27e','洪州送僧遊福建','韋莊','唐','唐诗','tang','','[]','八月風波似鼓鼙，可堪波上各東西。',32,'全唐诗/poet.tang.39000.json','["八月風波似鼓鼙，可堪波上各東西。", "殷勤早作歸來計，莫戀猿聲住建溪。"]'),
('b7bd573e-002b-4310-8074-c1ce93a3f84b','聞回戈軍','韋莊','唐','唐诗','tang','','[]','上將鏖兵又欲旋，翠華巡幸已三年。',32,'全唐诗/poet.tang.39000.json','["上將鏖兵又欲旋，翠華巡幸已三年。", "營中不用栽楊柳，願戴儒冠爲控弦。"]'),
('73024b46-aa81-4846-9870-cdd6d6980ec1','南鄰公子','韋莊','唐','唐诗','tang','','[]','南鄰公子夜歸聲，數炬銀燈隔竹明。',32,'全唐诗/poet.tang.39000.json','["南鄰公子夜歸聲，數炬銀燈隔竹明。", "醉凭馬鬃扶不起，更邀紅袖出門迎。"]'),
('a4070be4-79c3-42c9-8a0f-f8385108c5ec','憶小女銀娘','韋莊','唐','唐诗','tang','','[]','睦州江上水門西，蕩槳揚帆各解攜。',32,'全唐诗/poet.tang.39000.json','["睦州江上水門西，蕩槳揚帆各解攜。", "今日天涯夜深坐，斷腸偏憶阿銀犂。"]'),
('c3b81d14-d4ed-45e7-84a0-de1c988e7e52','女僕阿汪','韋莊','唐','唐诗','tang','','[]','念爾辛勤歲已深，亂離相失又相尋。',32,'全唐诗/poet.tang.39000.json','["念爾辛勤歲已深，亂離相失又相尋。", "他年待我門如市，報爾千金與萬金。"]'),
('64bf645c-5c3a-4fcc-bac2-f2720be4c3dc','河清縣河亭','韋莊','唐','唐诗','tang','','[]','由來多感莫憑高，竟日衷腸似有刀。',32,'全唐诗/poet.tang.39000.json','["由來多感莫憑高，竟日衷腸似有刀。", "人事任成陵與谷，大河東去自滔滔。"]'),
('b87efa81-b749-47e4-a2a6-ec43dcbaa306','鍾陵夜闌作','韋莊','唐','唐诗','tang','','[]','鍾陵風雪夜將深，坐對寒江獨苦吟。',32,'全唐诗/poet.tang.39000.json','["鍾陵風雪夜將深，坐對寒江獨苦吟。", "流落天涯誰見問，少卿應識子卿心。"]'),
('c8679bf2-5b5c-45b5-aa89-baaeb8470c7c','悼楊氏妓琴弦','韋莊','唐','唐诗','tang','','[]','魂歸寥廓魄歸煙，只住人間十八年。',32,'全唐诗/poet.tang.39000.json','["魂歸寥廓魄歸煙，只住人間十八年。", "昨日施僧裙帶上，斷腸猶繫琵琶弦。"]'),
('dd45c018-417b-4000-9e1d-b948bc43a48c','殘花','韋莊','唐','唐诗','tang','','[]','江頭沈醉泥斜暉，却向花前慟哭歸。',32,'全唐诗/poet.tang.39000.json','["江頭沈醉泥斜暉，却向花前慟哭歸。", "惆悵一年春又去，碧雲芳草兩依依。"]'),
('885d9525-9c23-4ff2-abc2-60d1988541b5','歲晏同左生作','韋莊','唐','唐诗','tang','','[]','歲暮鄉關遠，天涯手重攜。',48,'全唐诗/poet.tang.39000.json','["歲暮鄉關遠，天涯手重攜。", "雪埋江樹短，雲壓夜城低。", "寶瑟湘靈怨，清砧杜魄啼。", "不須臨皎鏡，年長易淒淒。"]'),
('3119d358-731f-4bc8-991d-ddf56bcf0f2c','咸陽懷古','韋莊','唐','唐诗','tang','','[]','城邊人倚夕陽樓，城上雲凝萬古愁。',64,'全唐诗/poet.tang.39000.json','["城邊人倚夕陽樓，城上雲凝萬古愁。", "山色不知秦苑廢，水聲空傍漢宮流。", "李斯不向倉中悟，徐福應無物外遊。", "莫怪楚吟偏斷骨，野煙蹤跡似東周。"]'),
('c162e3ec-4c71-4964-8cc6-c746ef1fc633','和同年韋學士華下途中見寄','韋莊','唐','唐诗','tang','','[]','綠楊城郭雨淒淒，過盡千輪與萬蹄。',64,'全唐诗/poet.tang.39000.json','["綠楊城郭雨淒淒，過盡千輪與萬蹄。", "送我獨遊三蜀路，羨君新上九霄梯。", "馬驚門外山如活，花笑尊前客似泥。", "正是清和好時節，不堪離恨劍門西。"]'),
('025b9928-43ed-4424-b271-36169df11222','春愁','韋莊','唐','唐诗','tang','','[]','自有春愁正斷魂，不堪芳草思王孫。',32,'全唐诗/poet.tang.39000.json','["自有春愁正斷魂，不堪芳草思王孫。", "落花寂寂黃昏雨，深院無人獨倚門。"]'),
('8995e452-a0e8-40aa-b092-0a0ba33d245d','傷灼灼','韋莊','唐','唐诗','tang','','[]','嘗聞灼灼麗於花，雲髻盤時未破瓜。',64,'全唐诗/poet.tang.39000.json','["嘗聞灼灼麗於花，雲髻盤時未破瓜。", "桃臉曼長橫綠水，玉肌香膩透紅紗。", "多情不住神仙界，薄命曾嫌富貴家。", "流落錦江無處問，斷魂飛作碧天霞。"]'),
('1f180195-2cba-4d01-af74-19a28c90633f','漢州','韋莊','唐','唐诗','tang','','[]','比儂初到漢州城，郭邑樓臺觸目驚。',64,'全唐诗/poet.tang.39000.json','["比儂初到漢州城，郭邑樓臺觸目驚。", "松桂影中旌斾色，芰荷風裏管弦聲。", "人心不似經離亂，時運還應却太平。", "十日醉眠金鴈驛，臨岐無恨臉波橫。"]'),
('78070251-8d63-420c-9c34-56cef2d11c64','長安清明','韋莊','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u6000\u5ff5"]','蚤是傷春夢雨天，可堪芳草更芊芊。',66,'全唐诗/poet.tang.39000.json','["蚤是傷春夢雨天，可堪芳草更芊芊。", "內官初賜清明火，上相閑分白打錢。", "紫陌亂嘶紅叱撥，綠[楊]高映畫鞦韆。", "遊人記得承平事，暗喜風光似昔年。"]'),
('0abe04f0-a0e5-4811-be2e-119834638c1a','秋霽晚景','韋莊','唐','唐诗','tang','','[]','秋霽禁城晚，六街煙雨殘。',48,'全唐诗/poet.tang.39000.json','["秋霽禁城晚，六街煙雨殘。", "牆頭山色健，林外鳥聲歡。", "翹日樓臺麗，清風劒佩寒。", "玉人襟袖薄，斜凭翠闌干。"]'),
('e2dea72c-7608-4e44-b12a-00aed6ef1913','和人春暮書事寄崔秀才','韋莊','唐','唐诗','tang','','[]','半掩朱門白日長，晚風輕墮落梅妝。',64,'全唐诗/poet.tang.39000.json','["半掩朱門白日長，晚風輕墮落梅妝。", "不知芳草情何限，只怪遊人思易傷。", "纔見早春鶯出谷，已驚新夏燕巢梁。", "相逢只賴如澠酒，一曲狂歌入醉鄉。"]'),
('f6051f86-74d0-4457-b0db-d81615f0e488','古離別','韋莊','唐','唐诗','tang','','[]','一生風月供惆悵，到處煙花恨別離。',32,'全唐诗/poet.tang.39000.json','["一生風月供惆悵，到處煙花恨別離。", "止竟多情何處好，少年長抱少年悲。"]'),
('93646161-5228-4075-ba0c-16c11c34d8f7','邊上逢薛秀才話舊','韋莊','唐','唐诗','tang','','[]','前年同醉武陵亭，絕倒閑譚坐到明。',64,'全唐诗/poet.tang.39000.json','["前年同醉武陵亭，絕倒閑譚坐到明。", "也有絳脣歌白雪，更憐紅袖奪金觥。", "秦雲一散如春夢，楚市千燒作故城。", "今日皤然對芳草，不勝東望涕交橫。"]'),
('61e25bc2-1a35-40af-b3a6-4f4e48bf91f5','飲散呈主人','韋莊','唐','唐诗','tang','','[]','夢覺笙歌散，空堂寂寞秋。',24,'全唐诗/poet.tang.39000.json','["夢覺笙歌散，空堂寂寞秋。", "更聞城角弄，煙雨不勝愁。"]'),
('8fd2e3d4-cca8-4c7d-808b-8ec86a13441b','使院黃葵花','韋莊','唐','唐诗','tang','','[]','薄妝新著澹黃衣，對捧金爐侍醮遲。',64,'全唐诗/poet.tang.39000.json','["薄妝新著澹黃衣，對捧金爐侍醮遲。", "向月似矜傾國貌，倚風如唱步虛詞。", "乍開檀炷疑聞語，試與雲和必解吹。", "爲報同人看來好，不禁秋露即離披。"]'),
('ab556704-b0d0-459b-890d-959c5e16ee36','搖落','韋莊','唐','唐诗','tang','','[]','搖落秋天酒易醒，淒淒長似別離情。',32,'全唐诗/poet.tang.39000.json','["搖落秋天酒易醒，淒淒長似別離情。", "黃昏倚柱不歸去，腸斷綠荷風雨聲。"]'),
('e5d5b599-5c1b-403d-9279-54f55be44374','奉和觀察郎中春暮憶花言懷見寄四韻之什','韋莊','唐','唐诗','tang','','[]','天畔峨嵋簇簇青，楚雲何處隔重扃。',64,'全唐诗/poet.tang.39000.json','["天畔峨嵋簇簇青，楚雲何處隔重扃。", "落花帶雪埋芳草，春雨和風濕畫屏。", "對酒莫辭衝暮角，望鄉誰解倚南亭。", "惟君信我多惆悵，只願陶陶不願醒。"]'),
('d0598ec3-6803-4372-ab49-4058f293fe4e','奉和左司郎中春物暗度感而成章','韋莊','唐','唐诗','tang','','[]','纔喜新春已暮春，夕陽吟殺倚樓人。',64,'全唐诗/poet.tang.39000.json','["纔喜新春已暮春，夕陽吟殺倚樓人。", "錦江風散霏霏雨，花市香飄漠漠塵。", "今日尚追巫峽夢，少年應遇洛川神。", "有時自患多情病，莫是生前宋玉身。"]'),
('117f1a06-7426-4142-8b2d-3cffbb7cb45b','少年行','韋莊','唐','唐诗','tang','','[]','五陵豪客多，買酒黃金𧣴。',48,'全唐诗/poet.tang.39000.json','["五陵豪客多，買酒黃金𧣴。", "醉下酒家樓，美人雙翠幰。", "揮劒邯鄲市，走馬梁王苑。", "樂事殊未央，年華已云晚。"]'),
('68ea735a-cca0-4f06-a1b8-2bf1f1d667eb','令狐亭','韋莊','唐','唐诗','tang','','[]','若非天上神仙宅，須是人間將相家。',32,'全唐诗/poet.tang.39000.json','["若非天上神仙宅，須是人間將相家。", "想得當時好煙月，管弦吹殺後庭花。"]'),
('2f728009-17da-499f-923d-ff6e755b11b9','閨月','韋莊','唐','唐诗','tang','','[]','明月照前除，煙華蕙蘭濕。',48,'全唐诗/poet.tang.39000.json','["明月照前除，煙華蕙蘭濕。", "清風行處來，白露寒蟬急。", "美人情易傷，暗上紅樓立。", "欲言無處言，但向姮娥泣。"]'),
('51d9e4e1-1518-447f-8b42-c70be52a22e7','閨怨','韋莊','唐','唐诗','tang','','[]','戚戚彼何人，明眸利於月。',48,'全唐诗/poet.tang.39000.json','["戚戚彼何人，明眸利於月。", "啼妝曉不乾，素面凝香雪。", "良人去淄右，鏡破金簪折。", "空藏蘭蕙心，不忍琴中說。"]'),
('47f0cad8-c295-4540-a348-ecf0c16ae7a9','上春詞','韋莊','唐','唐诗','tang','','[]','曈曨赫日東方來，禁城煙煖蒸青苔。',96,'全唐诗/poet.tang.39000.json','["曈曨赫日東方來，禁城煙煖蒸青苔。", "金樓美人花屏開，晨妝未罷車聲催。", "幽蘭報暖紫芽折，夭花愁豔蝶飛迴。", "五陵年少惜花落，酒濃歌極翻如哀。", "四時輪環終又始，百年不見南山摧。", "遊人陌上騎生塵，顏子門前吹死灰。"]'),
('87f9de92-ca54-419c-8482-94a3446f158b','擣練篇','韋莊','唐','唐诗','tang','','[]','月華吐豔明燭燭，青樓婦唱擣衣曲。',64,'全唐诗/poet.tang.39000.json','["月華吐豔明燭燭，青樓婦唱擣衣曲。", "白袷絲光織魚目，菱花綬帶鴛鴦簇。", "臨風縹緲疊秋雪，月下丁冬擣寒玉。", "樓蘭欲寄在何鄉，憑人與繫征鴻足。"]'),
('37f1b5c3-c60c-4a27-8d83-473822447da3','雜體聯錦','韋莊','唐','唐诗','tang','','[]','攜手重攜手，夾江金線柳。',204,'全唐诗/poet.tang.39000.json','["攜手重攜手，夾江金線柳。", "江上柳能長，行人戀尊酒。", "尊酒意何深，爲郎歌玉簪。", "玉簪聲斷續，鈿軸鳴雙轂。", "雙轂去何方，隔江春樹綠。", "樹綠酒旗高，淚痕沾繡袍。", "袍縫紫鵝濕，重持金錯刀。", "錯刀何燦爛，使我腸千斷。", "腸斷欲何言，簾動真珠繁。", "真珠綴秋露，秋露沾金盤。", "金盤湛瓊液，仙子無歸跡。", "無跡又無言，海煙空寂寂。", "寂寂古城道，馬嘶芳岸草。", "岸草接長堤，長堤人解攜。", "解攜忽已久，緬邈空回首。", "回首隔天河，恨唱蓮塘歌。", "蓮塘在何許，日暮西山雨。"]'),
('2f094838-1355-47c9-8c38-8698d7c5527a','長安春','韋莊','唐','唐诗','tang','','[]','長安二月多香塵，六街車馬聲轔轔。',80,'全唐诗/poet.tang.39000.json','["長安二月多香塵，六街車馬聲轔轔。", "家家樓上如花人，千枝萬枝紅豔新。", "簾間笑語自相問，何人占得長安春。", "長安春色本無主，古來盡屬紅樓女。", "如今無奈杏園人，駿馬輕車擁將去。"]'),
('a816c62d-a75f-4648-8cf7-1beb84156246','撫盈歌','韋莊','唐','唐诗','tang','','[]','鳳縠兮鴛綃，霞疏兮綺寮。',108,'全唐诗/poet.tang.39000.json','["鳳縠兮鴛綃，霞疏兮綺寮。", "玉庭兮春晝，金屋兮秋宵。", "愁瞳兮月皎，笑頰兮花嬌。", "羅輕兮濃麝，室煖兮香椒。", "鑾輿去兮蕭屑，七絲斷兮泬寥。", "主父臥兮漳水，君王幸兮雲軺。", "鉛華窅窈兮穠姿，棠公肸蠁兮靡依。", "翠華長逝兮莫追，晏相望門兮空悲。"]'),
('f2ce27cb-87c1-4ba9-858b-d553c678d124','贈峨嵋山彈琴李處士','韋莊','唐','唐诗','tang','','["\u5ce8\u7709\u5c71"]','峨嵋山下能琴客，似醉似狂人不測。',288,'全唐诗/poet.tang.39000.json','["峨嵋山下能琴客，似醉似狂人不測。", "何須見我眼偏青，未見我身頭已白。", "茫茫四海本無家，一片愁雲颺秋碧。", "壺中醉臥日月明，世上長遊天地窄。", "晉朝叔夜舊相知，蜀郡文君小來識。", "後生常建彼何人，贈我篇章苦雕刻。", "名卿名相盡知音，遇酒遇琴無間隔。", "如今世亂獨翛然，天外鴻飛招不得。", "余今正泣楊朱淚，八月邊城風刮地。", "霓旌絳斾忽相尋，爲我尊前橫綠綺。", "一彈猛雨隨手來，再彈白雪連天起。", "淒淒清清松上風，咽咽幽幽隴頭水。", "吟蜂遶樹去不來，別鶴引雛飛又止。", "錦麟不動惟側頭，白馬仰聽空豎耳。", "廣陵故事無人知，古人不說今人疑。", "子期子野俱不見，烏啼鬼哭空傷悲。", "坐中詞客悄無語，簾外月華庭欲午。", "爲君吟作聽琴歌，爲我留名係仙譜。"]'),
('02bfa763-8e00-4356-a31a-4ba3a0b12254','江臯贈別','韋莊','唐','唐诗','tang','','[]','金管多情恨解攜，一聲歌罷客如泥。',64,'全唐诗/poet.tang.39000.json','["金管多情恨解攜，一聲歌罷客如泥。", "江亭繫馬綠楊短，野岸維舟春草齊。", "帝子夢魂煙水闊，謝公詩思碧雲低。", "風前不用頻揮手，我有家山白日西。"]'),
('0acefef6-61ee-4a97-8b3c-0209486de6ff','南陽小將張彥硤口鎮稅人場射虎歌','韋莊','唐','唐诗','tang','','[]','海內昔年狎太平，橫目穰穰何崢嶸。',160,'全唐诗/poet.tang.39000.json','["海內昔年狎太平，橫目穰穰何崢嶸。", "天生天殺豈天怒，忍使朝朝餵猛虎。", "關東驛路多丘荒，行人最忌稅人場。", "張彥雄特制殘暴，見之叱起如叱羊。", "鳴弦霹靂越幽阻，往往依林猶抵拒。", "草際旋看委錦茵，腰間不更抽白羽。", "老饕已斃衆雛恐，童稚揶揄皆自勇。", "忠良效順勢亦然，一劒猜狂敢輕動。", "有文有武方爲國，不是英雄伏不得。", "試徵張彥作將軍，幾箇將軍願策勳。"]'),
('2731c0f4-aaa0-4647-8cfa-27e1cd2fa588','下邽感舊','韋莊','唐','唐诗','tang','','[]','昔爲童稚不知愁，竹馬閑乘遶縣遊。',64,'全唐诗/poet.tang.39000.json','["昔爲童稚不知愁，竹馬閑乘遶縣遊。", "曾爲看花偷出郭，也因逃學暫登樓。", "招他邑客來還醉，儳得先生去始休。", "今日故人何處問，夕陽衰草盡荒丘。"]'),
('7c956a22-3724-46ee-ab11-dabaf0b3e779','塗次逢李氏兄弟感舊','韋莊','唐','唐诗','tang','','[]','御溝四面朱門宅，記得當時好弟兄。',64,'全唐诗/poet.tang.39000.json','["御溝四面朱門宅，記得當時好弟兄。", "曉傍柳陰騎竹馬，夜隈燈影弄先生。", "巡街趂蝶衣裳破，上屋探雛手脚輕。", "今日相逢俱老大，憂家憂國盡公卿。"]'),
('4adaa050-5773-4ccc-b353-0df7198a7f3f','龍潭','韋莊','唐','唐诗','tang','','[]','激石懸流雪滿灣，九龍潛處野雲閑。',64,'全唐诗/poet.tang.39000.json','["激石懸流雪滿灣，九龍潛處野雲閑。", "欲行甘雨四天下，且隱澄潭一頃間。", "浪引浮槎依北岸，波分晚日見東山。", "垂髯儻遇穆王駕，閬苑周流應未還。"]'),
('f77cc56b-83a4-45e6-b39c-a721f7f69cba','江上別李秀才','韋莊','唐','唐诗','tang','','[]','前年相送灞陵春，今日天涯各避秦。',32,'全唐诗/poet.tang.39000.json','["前年相送灞陵春，今日天涯各避秦。", "莫向尊前惜沈醉，與君俱是異鄉人。"]'),
('9dfab20e-5fa7-4034-9eee-4d3c382850f3','句','韋莊','唐','唐诗','tang','','[]','印將金鏁鏁，簾用玉鉤鉤。',40,'全唐诗/poet.tang.39000.json','["印將金鏁鏁，簾用玉鉤鉤。", "不隨妖豔開，獨媚玄冥節。", "豈是爲窮常見隔，只應嫌酒不相過。"]'),
('f0d8b5f9-b29c-4ad6-b22b-91721f742a6d','擬塞外征行','王貞白','唐','唐诗','tang','','[]','寇騎滿雞田，都護欲臨邊。',120,'全唐诗/poet.tang.39000.json','["寇騎滿雞田，都護欲臨邊。", "青泥方絕漠，懷劍始辭燕。", "旌旗挂龍虎，壯士募鷹鸇。", "長城威十萬，高嶺奮三千。", "行行向馬邑，去去指祁連。", "鼓聲遙赤塞，兵氣遠衝天。", "對陣雲初上，臨城月始懸。", "風驚烽易滅，沙暗馬難前。", "恩重恆思報，勞心屢損年。", "微功一可立，身輕不自憐。"]'),
('6f4dc728-d7b7-4567-913c-e862f7270a2d','蘆葦','王貞白','唐','唐诗','tang','','[]','高士想江湖，湖閑庭植蘆。',120,'全唐诗/poet.tang.39000.json','["高士想江湖，湖閑庭植蘆。", "清風時有至，綠竹興何殊。", "嫩喜日光薄，疎憂雨點麤。", "驚蛙跳得過，鬬雀裊如無。", "未織巴籬護，幾擡邛竹扶。", "惹煙輕弱柳，蘸水漱清蒲。", "溉灌情偏重，琴樽賞不孤。", "穿花思釣叟，吹葉少羌雛。", "寒色暮天映，秋聲遠籟俱。", "郎吟應有趣，瀟灑十餘株。"]'),
('3e8be69d-0088-4692-89fa-3d18edd76c4e','田舍曲','王貞白','唐','唐诗','tang','','[]','古今利名路，只在儂門前。',72,'全唐诗/poet.tang.39000.json','["古今利名路，只在儂門前。", "至老不離家，一生常晏眠。", "牛羊晚自歸，兒童戲野田。", "豈思封侯貴，唯只待豐年。", "征賦豈辭苦，但願時官賢。", "時官苟貪濁，田舍生憂煎。"]'),
('32f0efe9-8688-4b01-b1a0-4d636f5e76f2','妾薄命','王貞白','唐','唐诗','tang','','[]','薄命頭欲白，頻年嫁不成。',48,'全唐诗/poet.tang.39000.json','["薄命頭欲白，頻年嫁不成。", "秦娥未十五，昨夜事公卿。", "豈有機杼力，空傳歌舞名。", "妾專脩婦德，媒氏却相輕。"]'),
('a1199ea6-7e22-4fde-954d-5e319dbaea19','湘妃怨','王貞白','唐','唐诗','tang','','[]','舜欲省蠻陬，南巡非逸遊。',48,'全唐诗/poet.tang.39000.json','["舜欲省蠻陬，南巡非逸遊。", "九江沉白日，二女泣滄洲。", "目極楚雲斷，恨深湘水流。", "至今聞鼓瑟，咽絕不勝愁。"]'),
('98a00e95-2867-40a4-80b9-9a3e5f33cdb4','長門怨二首 一','王貞白','唐','唐诗','tang','','[]','寂寞故宮春，殘燈曉尚存。',48,'全唐诗/poet.tang.39000.json','["寂寞故宮春，殘燈曉尚存。", "從來非妾過，偶爾失君恩。", "花落傷容鬢，鶯啼驚夢魂。", "翠華如可待，應免老長門。"]'),
('61930a0e-bcf7-40db-9305-da177f83b988','長門怨二首 二','王貞白','唐','唐诗','tang','','[]','葉落長門靜，苔生永巷幽。',48,'全唐诗/poet.tang.39000.json','["葉落長門靜，苔生永巷幽。", "相思對明月，獨坐向空樓。", "鑾駕迷終轉，蛾眉老自愁。", "昭陽歌舞伴，此夕未知秋。"]'),
('d0144770-0ab5-41f8-a8bf-160c92093ad6','有所思','王貞白','唐','唐诗','tang','','[]','芙蓉出水時，偶爾便分離。',48,'全唐诗/poet.tang.39000.json','["芙蓉出水時，偶爾便分離。", "自此無因見，長教挂所思。", "殘春不入夢，芳信欲傳誰。", "寂寞秋堂下，空吟小謝詩。"]'),
('f1219e15-2f83-436c-8d1a-0dc2329a016b','短歌','王貞白','唐','唐诗','tang','','[]','物候來相續，新蟬送晚鶯。',48,'全唐诗/poet.tang.39000.json','["物候來相續，新蟬送晚鶯。", "百年休倚賴，一夢甚分明。", "金鼎神仙隱，銅壺晝夜傾。", "不如早立德，萬古有其名。"]'),
('07155ffa-86ee-46df-8fac-d864bb4362b4','御溝水','王貞白','唐','唐诗','tang','','[]','一帶御溝水，綠槐相蔭清。',48,'全唐诗/poet.tang.39000.json','["一帶御溝水，綠槐相蔭清。", "此中涵帝澤，無處濯塵纓。", "鳥道來雖險，龍池到自平。", "朝宗本心切，願向急流傾。"]'),
('990a9e14-8b30-457c-b9e6-72615f7270ee','少年行二首 一','王貞白','唐','唐诗','tang','','[]','遊讌不知厭，杜陵狂少年。',48,'全唐诗/poet.tang.39000.json','["遊讌不知厭，杜陵狂少年。", "花時輕暖酒，春服薄裝綿。", "戲馬上林苑，鬬雞寒食天。", "魯儒甘被笑，對策鬢皤然。"]'),
('651f7be3-023a-4ec8-95ef-007e7b754566','少年行二首 二','王貞白','唐','唐诗','tang','','[]','弱冠投邊急，驅兵夜渡河。',48,'全唐诗/poet.tang.39000.json','["弱冠投邊急，驅兵夜渡河。", "追奔鐵馬走，殺虜寶刀訛。", "威靜黑山路，氣含清海波。", "常聞爲突騎，天子賜長戈。"]'),
('ffb281d2-cd57-4383-91fb-41ddc1849010','塞上曲','王貞白','唐','唐诗','tang','','[]','歲歲但防虜，西征早晚休。',48,'全唐诗/poet.tang.39000.json','["歲歲但防虜，西征早晚休。", "匈奴不繫頸，漢將但封侯。", "夕照低烽火，寒笳咽戍樓。", "燕然山上字，男子見須羞。"]'),
('ea516347-32e6-4fa7-b33a-2d4105558f49','長安道','王貞白','唐','唐诗','tang','','[]','曉鼓人已行，暮鼓人未息。',48,'全唐诗/poet.tang.39000.json','["曉鼓人已行，暮鼓人未息。", "梯航萬國來，爭先貢金帛。", "不問賢與愚，但論官與職。", "如何貧書生，只獻安邊策。"]'),
('3d5d0008-954b-42a6-b6ab-fb82135159b4','洛陽道','王貞白','唐','唐诗','tang','','[]','喧喧洛陽路，奔走爭先步。',48,'全唐诗/poet.tang.39000.json','["喧喧洛陽路，奔走爭先步。", "唯恐著鞭遲，誰能更迴顧。", "覆車雖在前，潤屋何曾懼。", "賢哉只二疏，東門掛冠去。"]'),
('223f6361-8149-43bc-aa51-8db381e5ed6a','度關山','王貞白','唐','唐诗','tang','','[]','只領千餘騎，長驅磧邑間。',48,'全唐诗/poet.tang.39000.json','["只領千餘騎，長驅磧邑間。", "雲州多警急，雪夜度關山。", "石響鈴聲遠，天寒弓力慳。", "秦樓休悵望，不日凱歌還。"]'),
('cb38dfd8-614d-447a-b8a5-47654f379ab3','出自薊北門行','王貞白','唐','唐诗','tang','','[]','薊北連極塞，塞色晝冥冥。',48,'全唐诗/poet.tang.39000.json','["薊北連極塞，塞色晝冥冥。", "戰地骸骨滿，長時風雨腥。", "沙河留不定，春草凍難青。", "萬戶封侯者，何謀靜虜庭。"]'),
('8c02ee7a-e1ec-4af7-8ef3-d10c0bfc1b93','從軍行','王貞白','唐','唐诗','tang','','[]','從軍朔方久，未省用干戈。',48,'全唐诗/poet.tang.39000.json','["從軍朔方久，未省用干戈。", "秪以恩信及，自然戎虜和。", "邊聲動白草，燒色入枯河。", "每度因看獵，令人勇氣多。"]'),
('666fbd5e-7376-4efb-b43f-1d309d06e4d3','古悔從軍行','王貞白','唐','唐诗','tang','','[]','憶昔仗孤劍，十年從武威。',48,'全唐诗/poet.tang.39000.json','["憶昔仗孤劍，十年從武威。", "論兵親玉帳，逐虜過金微。", "隴水秋先凍，關雲寒不飛。", "辛懃功業在，麟閣志猶違。"]'),
('4eacf00c-af1c-4eb9-992f-deb062a6e2f6','胡笳曲','王貞白','唐','唐诗','tang','','[]','隴底悲笳引，隴頭鳴北風。',48,'全唐诗/poet.tang.39000.json','["隴底悲笳引，隴頭鳴北風。", "一輪霜月落，萬里塞天空。", "戍卒淚應盡，胡兒哭未終。", "爭教班定遠，不念玉關中。"]'),
('fc7c6f0f-57ee-4f63-bfaf-a974ee3ad0ea','入塞','王貞白','唐','唐诗','tang','','[]','玉殿論兵事，君王詔出征。',48,'全唐诗/poet.tang.39000.json','["玉殿論兵事，君王詔出征。", "新除羽林將，曾破月支兵。", "慣歷塞垣險，能分部落情。", "從今一戰勝，不使虜塵生。"]'),
('458d9efc-e91e-4d2a-9fee-d56b271b6728','遊僊','王貞白','唐','唐诗','tang','','[]','我家三島上，洞戶眺波濤。',48,'全唐诗/poet.tang.39000.json','["我家三島上，洞戶眺波濤。", "醉背雲屏臥，誰知海日高。", "露香紅玉樹，風綻碧蟠桃。", "悔與仙子別，思歸夢釣鼇。"]'),
('38a52265-adaf-46e2-8cf8-0baa3d40cfd9','歌','王貞白','唐','唐诗','tang','','[]','誰唱關西曲，寂寞夜景深。',48,'全唐诗/poet.tang.39000.json','["誰唱關西曲，寂寞夜景深。", "一聲長在耳，萬恨重經心。", "調古清風起，曲終涼月沉。", "却應筵上客，未必是知音。"]'),
('dbed4d44-b9ab-41db-a5ff-c335969a3c42','經故洛城','王貞白','唐','唐诗','tang','','[]','卜世何久遠，由來仰聖明。',48,'全唐诗/poet.tang.39000.json','["卜世何久遠，由來仰聖明。", "山河徒自壯，周召不長生。", "幾主任姦諂，諸侯各戰爭。", "但餘崩壘在，今古共傷情。"]'),
('52a1875d-293c-4cbe-971b-b372ecfa9230','金陵','王貞白','唐','唐诗','tang','','[]','六代江山在，繁華古帝都。',48,'全唐诗/poet.tang.39000.json','["六代江山在，繁華古帝都。", "亂來城不守，戰後地多蕪。", "寒日隨潮落，歸帆與鳥孤。", "興亡多少事，回首一長吁。"]'),
('5dd9ffd8-e4da-4514-8618-10b2ccf34d3b','金陵懷古','王貞白','唐','唐诗','tang','','[]','恃險不種德，興亡歎數窮。',48,'全唐诗/poet.tang.39000.json','["恃險不種德，興亡歎數窮。", "石城幾換主，天塹謾連空。", "御路疊民塚，臺基聚牧童。", "折碑猶有字，多記晉英雄。"]'),
('b1a79e67-9a12-4829-a7f0-4d87fbff07c7','商山','王貞白','唐','唐诗','tang','','[]','商山名利路，夜亦有人行。',48,'全唐诗/poet.tang.39000.json','["商山名利路，夜亦有人行。", "四皓臥雲處，千秋疊蘚生。", "晝燒籠澗黑，殘雪隔林明。", "我待酬恩了，來聽水石聲。"]'),
('0ae3ae53-6f0c-4e0d-a387-9c6b0bb921ac','廬山','王貞白','唐','唐诗','tang','','["\u5e90\u5c71"]','嶽立鎮南楚，雄名天下聞。',48,'全唐诗/poet.tang.39000.json','["嶽立鎮南楚，雄名天下聞。", "五峰高閡日，九疊翠連雲。", "夏谷雪猶在，陰巖晝不分。", "唯應嵩與華，清峻得爲羣。"]'),
('719aca7b-b7e4-4c71-8304-fed39379519f','終南山','王貞白','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','終朝異五岳，列翠滿長安。',48,'全唐诗/poet.tang.39000.json','["終朝異五岳，列翠滿長安。", "地去搜揚近，人謀隱遁難。", "水穿諸苑過，雪照一城寒。", "爲問紅塵裏，誰同駐馬看。"]'),
('3b1a7cc8-2849-4347-af5f-932938d300c3','寄鄭谷','王貞白','唐','唐诗','tang','','[]','五百首新詩，緘封寄去時。',48,'全唐诗/poet.tang.39000.json','["五百首新詩，緘封寄去時。", "秪憑夫子鑒，不要俗人知。", "火鼠重收布，冰蠶乍吐絲。", "直須天上手，裁作領巾披。"]'),
('5c966095-35dd-452a-8496-dd3c6b3e8213','題嚴陵釣臺','王貞白','唐','唐诗','tang','','[]','山色四時碧，溪聲七里清。',48,'全唐诗/poet.tang.39000.json','["山色四時碧，溪聲七里清。", "嚴陵愛此景，下視漢公卿。", "垂釣月初上，放歌風正輕。", "應憐渭濱叟，匡國正論兵。"]'),
('8e880fca-acc1-4bcb-a650-71516cec4510','曉泊漢陽渡','王貞白','唐','唐诗','tang','','[]','落月臨古渡，武昌城未開。',48,'全唐诗/poet.tang.39000.json','["落月臨古渡，武昌城未開。", "殘燈明市井，曉色辨樓臺。", "雲自蒼梧去，水從嶓冢來。", "芳洲號鸚鵡，用記禰生才。"]'),
('67fe5088-387a-4eab-8db4-230688cb4291','隨計','王貞白','唐','唐诗','tang','','[]','徒步隨計吏，辛勤鬢易凋。',48,'全唐诗/poet.tang.39000.json','["徒步隨計吏，辛勤鬢易凋。", "歸期無定日，鄉思羨迴潮。", "冒雨投前驛，侵星過斷橋。", "何堪穆陵路，霜葉更瀟瀟。"]'),
('8e356f4e-0997-4f89-8cd3-960d80c3faaa','白牡丹','王貞白','唐','唐诗','tang','','[]','穀雨洗纖素，裁爲白牡丹。',48,'全唐诗/poet.tang.39000.json','["穀雨洗纖素，裁爲白牡丹。", "異香開玉合，輕粉泥銀盤。", "曉貯露華濕，宵傾月魄寒。", "家人淡粧罷，無語倚朱欄。"]'),
('aef21a8f-1a5a-48e3-be6c-5be80d024a88','述松','王貞白','唐','唐诗','tang','','[]','遠谷呈材幹，何由入棟粱。',48,'全唐诗/poet.tang.39000.json','["遠谷呈材幹，何由入棟粱。", "歲寒虛勝竹，功績不如桑。", "秋露落松子，春深裛嫩黃。", "雖蒙匠者顧，樵採日難防。"]'),
('2e9fe395-6ef2-4708-b766-ee4b4e662667','宮池產瑞蓮','王貞白','唐','唐诗','tang','','[]','雨露及萬物，嘉祥有瑞蓮。',48,'全唐诗/poet.tang.39000.json','["雨露及萬物，嘉祥有瑞蓮。", "香飄雞樹近，榮占鳳池先。", "聖日臨雙麗，恩波照並妍。", "願同指佞草，生向帝堯前。"]'),
('261b1934-825b-473c-9822-8e51169b3371','送友人南歸','王貞白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南國菖蒲老，知君憶釣船。',48,'全唐诗/poet.tang.39000.json','["南國菖蒲老，知君憶釣船。", "離京近殘暑，歸路有新蟬。", "峴首白雲起，洞庭秋月懸。", "若教吟興足，西笑是何年。"]'),
('4145d5a4-a43d-4347-b4cb-811e72f39864','送馬明府歸山','王貞白','唐','唐诗','tang','','["\u5e90\u5c71"]','辭秩入匡廬，重脩靖節居。',48,'全唐诗/poet.tang.39000.json','["辭秩入匡廬，重脩靖節居。", "免遭黑綬束，不與白雲疎。", "送吏各獻酒，羣兒自擔書。", "到時看瀑布，爲我謝清虛。"]'),
('12e84743-0225-4aa8-8e79-b59b78dab05b','送韓從事歸本道','王貞白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','獻捷靈州倅，歸時寵拜新。',48,'全唐诗/poet.tang.39000.json','["獻捷靈州倅，歸時寵拜新。", "論邊多稱旨，許國誓亡身。", "馬渴黃河凍，雁回青塚春。", "到蕃唯促戰，應不肯和親。"]'),
('71a985ba-f0e8-4f00-a512-67b60623362f','秋日旅懷寄右省鄭拾遺','王貞白','唐','唐诗','tang','','[]','永夕愁不寐，草蟲喧客庭。',48,'全唐诗/poet.tang.39000.json','["永夕愁不寐，草蟲喧客庭。", "半窗分曉月，當枕落殘星。", "鬢髮遊梁白，家山近越青。", "知音在諫省，苦調有誰聽。"]'),
('a78a3e4b-66b1-448c-86b7-561757e79769','贈劉凝評事','王貞白','唐','唐诗','tang','','[]','棘寺官初罷，梁園靜掩扉。',48,'全唐诗/poet.tang.39000.json','["棘寺官初罷，梁園靜掩扉。", "春深顏子巷，花映老萊衣。", "談史曾無滯，攻書已造微。", "即膺新寵命，稱慶向庭闈。"]'),
('f517805a-e85f-4db5-a3f1-6268926da391','憶張處士','王貞白','唐','唐诗','tang','','[]','天台張處士，詩句造玄微。',48,'全唐诗/poet.tang.39000.json','["天台張處士，詩句造玄微。", "古藥知音少，名言與俗違。", "山風入松徑，海月上巖扉。", "畢世唯高臥，無人說是非。"]'),
('a400727a-d4ca-41cf-bd11-568edd8348c9','雲居長老','王貞白','唐','唐诗','tang','','[]','巘路躡雲上，來參出世僧。',48,'全唐诗/poet.tang.39000.json','["巘路躡雲上，來參出世僧。", "松高半巖雪，竹覆一溪冰。", "不說有爲法，非傳無盡燈。", "了然方寸內，應秪見南能。"]'),
('ac19d50b-93ae-40bb-b41f-067f6722fad8','洗竹','王貞白','唐','唐诗','tang','','[]','道院竹繁教畧洗，鳴琴酌酒看扶疎。',64,'全唐诗/poet.tang.39000.json','["道院竹繁教畧洗，鳴琴酌酒看扶疎。", "不圖結實來雙鳳，且要長竿釣巨魚。", "錦籜裁冠添散逸，玉芽脩饌稱清虛。", "有時記得三天事，自向琅玕節下書。"]'),
('96b981e6-2ec3-41b4-89d2-d6999cff08ca','庾樓曉望','王貞白','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u666f", "\u767b\u9ad8"]','獨凭朱檻亦凌晨，山色初明水色新。',64,'全唐诗/poet.tang.39000.json','["獨凭朱檻亦凌晨，山色初明水色新。", "竹霧曉籠銜嶺月，蘋風暖送過江春。", "子城陰處猶殘雪，衙鼓聲前未有塵。", "三百年來庾樓上，曾經多少望鄉人。"]'),
('5f792611-cd25-48c9-b9ae-222d1f9dded2','送芮尊師','王貞白','唐','唐诗','tang','','[]','石上菖蒲節節靈，先生服食得長生。',64,'全唐诗/poet.tang.39000.json','["石上菖蒲節節靈，先生服食得長生。", "早知避世憂身老，近日登山覺步輕。", "黃鶴待傳蓬島信，丹書應換蘂宮名。", "他年控鯉昇天去，廬岳逋民願從行。"]'),
('0683764e-f711-46ba-9ba4-f1f4cde32c99','折楊柳三首 一','王貞白','唐','唐诗','tang','','[]','枝枝交影鎖長門，嫩色曾沾雨露恩。',32,'全唐诗/poet.tang.39000.json','["枝枝交影鎖長門，嫩色曾沾雨露恩。", "鳳輦不來春欲盡，空留鶯語到黃昏。"]'),
('0c9764a9-234c-46da-b8cb-1ea0aeef5c79','折楊柳三首 二','王貞白','唐','唐诗','tang','','[]','水殿年年占早芳，柔條風裏御爐香。',32,'全唐诗/poet.tang.39000.json','["水殿年年占早芳，柔條風裏御爐香。", "如今萬乘多巡狩，輦路無陰綠草長。"]'),
('bafac919-3509-4d91-b700-809818965980','折楊柳三首 三','王貞白','唐','唐诗','tang','','[]','嫩葉初齊不耐寒，風和時拂玉欄干。',32,'全唐诗/poet.tang.39000.json','["嫩葉初齊不耐寒，風和時拂玉欄干。", "征人去日曾攀折，泣雨傷春翠黛殘。"]'),
('349419cc-03cc-4404-9985-f6d130dac81a','遠聞本郡行春到舊山二首 一','王貞白','唐','唐诗','tang','','[]','一身從宦留京邑，五馬遙聞到舊山。',32,'全唐诗/poet.tang.39000.json','["一身從宦留京邑，五馬遙聞到舊山。", "已領煙霞光野徑，深慙老幼候柴關。"]'),
('dac0b35e-cbd5-458f-9364-a50424698c81','遠聞本郡行春到舊山二首 二','王貞白','唐','唐诗','tang','','[]','清風借響松筠外，畫隼停暉水石間。',32,'全唐诗/poet.tang.39000.json','["清風借響松筠外，畫隼停暉水石間。", "定掩溪名在圖傳，共知軒蓋此登攀。"]'),
('45932bac-3957-4849-ae55-4e2fdaab10c2','宿新安村步','王貞白','唐','唐诗','tang','','[]','淅淅寒流漲淺沙，月明空渚徧蘆花。',32,'全唐诗/poet.tang.39000.json','["淅淅寒流漲淺沙，月明空渚徧蘆花。", "離人偶宿孤邨下，永夜聞砧一兩家。"]'),
('3b30f9b2-7222-4141-9ccb-87b494bf3b02','僊巖二首 一','王貞白','唐','唐诗','tang','','[]','白煙晝起丹竈，紅葉秋書篆文。',28,'全唐诗/poet.tang.39000.json','["白煙晝起丹竈，紅葉秋書篆文。", "二十四巖天上，一雞啼破晴雲。"]'),
('7f75bf04-5754-4640-a8cc-95b2e77f94fb','僊巖二首 二','王貞白','唐','唐诗','tang','','[]','風呼山鬼服役，月照衡薇結花。',28,'全唐诗/poet.tang.39000.json','["風呼山鬼服役，月照衡薇結花。", "江暖客尋瑤草，洞深人嚥丹霞。"]'),
('c1f1ccf9-4d5a-4ebd-afbc-8bbdafd01f6e','雨後從陶郎中登庾樓','王貞白','唐','唐诗','tang','','[]','庾樓逢霽色，夏日欲西曛。',48,'全唐诗/poet.tang.39000.json','["庾樓逢霽色，夏日欲西曛。", "虹截半江雨，風驅大澤雲。", "島邊漁艇聚，天畔鳥行分。", "此景堪誰畫，文翁請綴文。"]'),
('369e6a49-eed7-4a28-abc6-6983aff9640d','九日長安作','王貞白','唐','唐诗','tang','','[]','無酒泛金菊，登高但憶秋。',48,'全唐诗/poet.tang.39000.json','["無酒泛金菊，登高但憶秋。", "歸心隨旅雁，萬里在滄洲。", "殘照明天闕，孤砧隔御溝。", "誰能思落帽，兩鬢已添愁。"]'),
('8c88d837-c717-4f35-950d-cb6d4b6bb4b5','曉發蕭關','王貞白','唐','唐诗','tang','','[]','早發長風裏，邊城曙色間。',48,'全唐诗/poet.tang.39000.json','["早發長風裏，邊城曙色間。", "數鴻寒背磧，片月落臨關。", "隴上明星沒，沙中夜探還。", "歸程不可問，幾日到家山。"]'),
('e640728d-789a-48ac-bfee-3c4744c7114d','釣臺','王貞白','唐','唐诗','tang','','[]','異代有巢許，方知嚴子情。',48,'全唐诗/poet.tang.39000.json','["異代有巢許，方知嚴子情。", "舊交雖建國，高臥不求榮。", "溪鳥寒來浴，汀蘭暖重生。", "何顏吟過此，辛苦得浮名。"]'),
('a5d27c21-7045-4e33-8a1e-f50862de0e25','寄天台葉尊師','王貞白','唐','唐诗','tang','','[]','師住天台久，長聞過石橋。',48,'全唐诗/poet.tang.39000.json','["師住天台久，長聞過石橋。", "晴峯見滄海，深洞徹丹霄。", "採藥霞衣濕，煎芝古鼎焦。", "念予無俗骨，頻與鶴書招。"]'),
('2737bdf7-c299-4081-86b2-9b3efbb4e5d2','御試後進詩','王貞白','唐','唐诗','tang','','[]','三時賜食天廚近，再宿偷吟禁漏清。',32,'全唐诗/poet.tang.39000.json','["三時賜食天廚近，再宿偷吟禁漏清。", "二十五家齊拔宅，人間已寫上昇名。"]'),
('14874375-0d55-47f8-a8a4-c5b4c093fe2d','春日詠梅花','王貞白','唐','唐诗','tang','','[]','靚妝纔罷粉痕新，迨曉風迴散玉塵。',32,'全唐诗/poet.tang.39000.json','["靚妝纔罷粉痕新，迨曉風迴散玉塵。", "若遣有情應悵望，已兼殘雪又兼春。"]'),
('2226812f-a839-4943-9bcb-aa27fd9461fd','句','王貞白','唐','唐诗','tang','','[]','太陽雖不照，梁棟每重陰。',56,'全唐诗/poet.tang.39000.json','["太陽雖不照，梁棟每重陰。", "白髮未逢媒，對景且裴回。", "別酒莫辭今夜醉，故人知我幾時來。", "改貫永留鄉黨額，減租重感郡侯恩。"]'),
('1d66281b-96e0-4f20-a42f-4f1ac5cbd3f6','登單于臺','張蠙','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u5199\u666f", "\u8fb9\u585e"]','邊兵春盡迴，獨上單于臺。',48,'全唐诗/poet.tang.39000.json','["邊兵春盡迴，獨上單于臺。", "白日地中出，黃河天外來。", "沙翻痕似浪，風急響疑雷。", "欲向陰關度，陰關曉不開。"]'),
('8883b48a-866a-4c98-86dd-416d3c8821cc','寄友人','張蠙','唐','唐诗','tang','','[]','戀道欲何如，東西遠索居。',48,'全唐诗/poet.tang.39000.json','["戀道欲何如，東西遠索居。", "長疑即見面，翻致久無書。", "甸麥深藏雉，淮苔淺露魚。", "相思不我會，明月幾盈虛。"]'),
('44b0faa4-22cd-4ba8-9655-2fcc5048c83c','和崔監丞春遊鄭僕射東園','張蠙','唐','唐诗','tang','','[]','春興隨花盡，東園自養閒。',48,'全唐诗/poet.tang.39000.json','["春興隨花盡，東園自養閒。", "不離三畝地，似入萬重山。", "白鳥穿蘿去，清泉抵石遠。", "豈同秦代客，無位隱商山。"]'),
('f1c25888-cffb-417e-9fb4-8f394b3e482f','過蕭關','張蠙','唐','唐诗','tang','','[]','出得蕭關北，儒衣不稱身。',48,'全唐诗/poet.tang.39000.json','["出得蕭關北，儒衣不稱身。", "隴狐來試客，沙鶻下欺人。", "曉戍殘烽火，晴原起獵塵。", "邊戎莫相忌，非是霍家親。"]'),
('d7ca59d0-69fd-42a0-aa39-15cb3dd55a68','盆池','張蠙','唐','唐诗','tang','','[]','圓內陶化功，外絕衆流通。',48,'全唐诗/poet.tang.39000.json','["圓內陶化功，外絕衆流通。", "選處離松影，穿時減藥叢。", "別疑天在地，長對月當空。", "每使登門客，煙波入夢中。"]'),
('5a9a7b99-f1b2-4fec-9282-74f893c83c8c','野泉','張蠙','唐','唐诗','tang','','[]','遠出白雲中，長年聽不同。',48,'全唐诗/poet.tang.39000.json','["遠出白雲中，長年聽不同。", "清聲縈亂石，寒色入長空。", "挂壁聊成雨，穿林別起風。", "溫泉非爾數，源發在深空。"]'),
('3e0d4d39-b290-4fdd-8f26-375de2449827','送成州牧','張蠙','唐','唐诗','tang','','[]','清時爲塞郡，自古有儒流。',48,'全唐诗/poet.tang.39000.json','["清時爲塞郡，自古有儒流。", "素望知難愜，新恩且用酬。", "犬牙連蜀國，兵額貫秦州。", "秪作三年別，誰能聽邑留。"]'),
('4691bf04-5ef8-4553-94ff-5b1a46cc5161','薊北書事','張蠙','唐','唐诗','tang','','[]','度磧如經海，茫然但見空。',48,'全唐诗/poet.tang.39000.json','["度磧如經海，茫然但見空。", "戍樓承落日，沙塞礙驚蓬。", "暑過燕僧出，時平虜客通。", "逢人皆上將，誰有定邊功。"]'),
('bff74753-3209-47cf-8bc4-662c9b6d34ea','送徐州薛尚書','張蠙','唐','唐诗','tang','','[]','上將出儒中，論詩擬立功。',48,'全唐诗/poet.tang.39000.json','["上將出儒中，論詩擬立功。", "州從禹後別，軍自漢來雄。", "遠驛銷寒日，嚴城肅暮空。", "龍顏有遺廟，猶得奠英風。"]'),
('c228bd5d-bee3-4a1a-8808-0585b1c4c0ef','貽曹郎中','張蠙','唐','唐诗','tang','','[]','所作高前古，封章自曲臺。',48,'全唐诗/poet.tang.39000.json','["所作高前古，封章自曲臺。", "細看明主意，終用出人才。", "省印尋僧鎖，書樓領鶴開。", "南山有舊友，時向白雲來。"]'),
('8ac8678a-1d5b-470c-a7c9-a5ca97cd7610','送縉雲尉','張蠙','唐','唐诗','tang','','[]','釋褐從仙尉，之官興若何。',48,'全唐诗/poet.tang.39000.json','["釋褐從仙尉，之官興若何。", "去程唯水石，公署在雲蘿。", "野飯樓中迥，晴峰案上多。", "三年罷趨府，應更戰高科。"]'),
('f54e6868-143d-4ab6-91aa-69baeeb4c5a0','送董卿赴台州','張蠙','唐','唐诗','tang','','[]','九陌除書出，尋僧問海城。',48,'全唐诗/poet.tang.39000.json','["九陌除書出，尋僧問海城。", "家從中路挈，吏隔數州迎。", "夜蚌侵燈影，春禽雜櫓聲。", "開圖見異跡，思上石橋行。"]'),
('424a85f0-f480-4111-82a1-5a069a2785fd','送友人赴涇州幕','張蠙','唐','唐诗','tang','','[]','杏園沈飲散，榮別就佳招。',48,'全唐诗/poet.tang.39000.json','["杏園沈飲散，榮別就佳招。", "日月相期盡，山川獨去遙。", "府樓明蜀雪，關磧轉胡鵰。", "縱有煙塵動，應隨上策銷。"]'),
('3b1b2eec-8a9a-48a3-8ad2-5f4d37312677','逢漳州崔使君北歸','張蠙','唐','唐诗','tang','','[]','在郡多殊稱，無人不望回。',48,'全唐诗/poet.tang.39000.json','["在郡多殊稱，無人不望回。", "離城攜客去，度嶺擔猿來。", "障寫經冬蘂，瓶緘落暑梅。", "長安有歸宅，歸見鎖青苔。"]'),
('056b58c6-0902-42aa-97d9-c8adef05ef77','雲朔逢山友','張蠙','唐','唐诗','tang','','[]','會面却生疑，居然似夢歸。',48,'全唐诗/poet.tang.39000.json','["會面却生疑，居然似夢歸。", "塞深行客少，家遠識人稀。", "戰馬分旗牧，驚禽曳箭飛。", "將軍雖異禮，難便脫麻衣。"]'),
('7526030b-d50b-4cb1-b3ba-8b2f9e303aba','別後寄友生','張蠙','唐','唐诗','tang','','[]','上馬如飛鳥，飄然隔去塵。',48,'全唐诗/poet.tang.39000.json','["上馬如飛鳥，飄然隔去塵。", "共看今夜月，獨作異鄉人。", "就養江南熟，移居井賦新。", "襄陽曾卜隱，應與孟家鄰。"]'),
('28c345b7-7090-4b3d-be4c-c08e8d275f8e','邊遊別友人','張蠙','唐','唐诗','tang','','[]','欲別不止淚，當杯難強歌。',48,'全唐诗/poet.tang.39000.json','["欲別不止淚，當杯難強歌。", "家貧隨日長，身病涉寒多。", "雨雪迷燕路，田園隔楚波。", "良時未自致，歸去欲如何。"]'),
('5ed3648c-3514-428e-bb3e-4aaf64bb7695','邊庭送別','張蠙','唐','唐诗','tang','','[]','一生雖達理，遠別亦相悲。',48,'全唐诗/poet.tang.39000.json','["一生雖達理，遠別亦相悲。", "白髮無修處，青松有老時。", "暮煙傳戍起，寒日隔沙垂。", "若是長安去，何難定後期。"]'),
('733e08d1-b8bf-43a2-b7f2-f997e3c87905','將之京師留別親友','張蠙','唐','唐诗','tang','','[]','達命何勞問，西遊且自期。',48,'全唐诗/poet.tang.39000.json','["達命何勞問，西遊且自期。", "至公如有日，知我豈無時。", "野迥蟬相答，堤長柳對垂。", "酣歌一舉袂，明發不堪思。"]'),
('d6866b4a-2733-46f7-8b6e-acfa942745e9','贈別山友','張蠙','唐','唐诗','tang','','[]','從容無限意，不獨爲離羣。',48,'全唐诗/poet.tang.39000.json','["從容無限意，不獨爲離羣。", "年長驚黃葉，時清厭白雲。", "舊山迴馬見，寒瀑別家聞。", "相與存吾道，窮通各自分。"]'),
('22923d09-b7eb-481e-9268-da7f1a920c0b','途次績溪先寄陳明府','張蠙','唐','唐诗','tang','','[]','入境風煙好，幽人不易傳。',48,'全唐诗/poet.tang.39000.json','["入境風煙好，幽人不易傳。", "新居多是客，舊隱半成仙。", "山斷雲衝騎，溪長柳拂船。", "何當許過縣，聞有篋中篇。"]'),
('cda2a3c2-9f4c-4004-b23e-0e622f0fcc4e','送友人歸武陵','張蠙','唐','唐诗','tang','','[]','聞近桃源住，無村不是花。',50,'全唐诗/poet.tang.39000.json','["聞近桃源住，無村不是花。", "戍旗招海客，廟鼓集江鴉。", "別島垂橙實，閑田長荻[芽]。", "遊秦未得意，看即更離家。"]'),
('e9471aab-9a5e-45f5-b13f-a6d99507445c','亂中寄友人','張蠙','唐','唐诗','tang','','[]','別來難覓信，何處避艱危。',48,'全唐诗/poet.tang.39000.json','["別來難覓信，何處避艱危。", "鬢黑無多日，塵清是幾時。", "人情將厭武，王澤即興詩。", "若便懷深隱，還應聖主知。"]'),
('7dad5eb4-1f34-4def-aa0e-5a0e494e765f','哭建州李員外','張蠙','唐','唐诗','tang','','[]','詩名不易出，名出又何爲。',48,'全唐诗/poet.tang.39000.json','["詩名不易出，名出又何爲。", "捷到重科早，官終一郡卑。", "素風無後嗣，遺跡有生祠。", "自罷羊公市，溪猿哭舊時。"]'),
('40ed7a97-e705-44d1-be65-2f01d6df965a','弔孟浩然','張蠙','唐','唐诗','tang','','[]','每每樵家說，孤墳亦夜吟。',48,'全唐诗/poet.tang.39000.json','["每每樵家說，孤墳亦夜吟。", "若重生此世，應更苦前心。", "名與襄陽遠，詩同漢水深。", "親栽鹿門樹，猶蓋石牀陰。"]'),
('07288408-593c-4f8e-b616-02e813e22efc','送友人及第歸','張蠙','唐','唐诗','tang','','[]','家林滄海東，未曉日先紅。',48,'全唐诗/poet.tang.39000.json','["家林滄海東，未曉日先紅。", "作貢諸蕃別，登科幾國同。", "遠聲魚呷浪，層氣蜃迎風。", "鄉俗稀攀桂，爭來問月宮。"]'),
('c6608ef1-e7e4-4321-88dc-e1989d2be883','次韻和友人冬月書齋','張蠙','唐','唐诗','tang','','[]','四季多花木，窮冬亦不凋。',50,'全唐诗/poet.tang.39000.json','["四季多花木，窮冬亦不凋。", "薄冰行處斷，殘火睡來消。", "象版簽書帙，蠻藤絡酒[瓢]。", "公卿有知己，時得一相招。"]'),
('0b3a1cef-5c22-4eb7-b2e2-e92bfccbd604','過山家','張蠙','唐','唐诗','tang','','[]','避暑得探幽，忘言遂久留。',48,'全唐诗/poet.tang.39000.json','["避暑得探幽，忘言遂久留。", "雲深窗失曙，松合徑先秋。", "響谷傳人語，鳴泉洗客愁。", "家山不在此，至此可歸休。"]'),
('20c1984f-1540-4915-856e-2958e94703d8','宿山驛','張蠙','唐','唐诗','tang','','[]','驛在千峰裏，寒宵獨此身。',48,'全唐诗/poet.tang.39000.json','["驛在千峰裏，寒宵獨此身。", "古墳時見火，荒壁悄無隣。", "月白翻驚鳥，雲閑欲就人。", "秪應明日鬢，更與老相親。"]'),
('5bf36fc9-76cc-4378-a027-f5ad3bee19ac','宿開照寺光澤上人院','張蠙','唐','唐诗','tang','','[]','靜室譚玄旨，清宵獨細聽。',48,'全唐诗/poet.tang.39000.json','["靜室譚玄旨，清宵獨細聽。", "真身非有像，至理本無經。", "鐘定遙聞水，樓高別見星。", "不教人觸穢，偏說此山靈。"]'),
('6288b803-c05e-404e-bddf-7f81d7e0ffe3','宿山寺','張蠙','唐','唐诗','tang','','[]','中峰半夜起，忽覺有青冥。',48,'全唐诗/poet.tang.39000.json','["中峰半夜起，忽覺有青冥。", "此界自生雨，上方猶有星。", "樓高鐘尚遠，殿古像多靈。", "好是潺湲水，房房伴誦經。"]'),
('fe9e5b40-d5a4-48ba-b488-c9e8079e5cbb','題紫閣院','張蠙','唐','唐诗','tang','','[]','上方人海外，苔徑上千層。',48,'全唐诗/poet.tang.39000.json','["上方人海外，苔徑上千層。", "洞壑有靈藥，房廊無老僧。", "古巖雕素像，喬木挂寒燈。", "每到思修隱，將回苦不能。"]'),
('456a210f-0864-430e-bd45-b69c820ab291','白菊','張蠙','唐','唐诗','tang','','[]','秋天木葉乾，猶有白花殘。',48,'全唐诗/poet.tang.39000.json','["秋天木葉乾，猶有白花殘。", "舉世稀栽得，豪家却畫看。", "片苔相應綠，諸卉獨宜寒。", "幾度攜佳客，登高欲折難。"]'),
('19d5299e-b287-432c-9c23-87e45dd7b53f','叢葦','張蠙','唐','唐诗','tang','','[]','叢叢寒水邊，曾折打魚船。',48,'全唐诗/poet.tang.39000.json','["叢叢寒水邊，曾折打魚船。", "忽與亭臺近，翻嫌島嶼偏。", "花明無月夜，聲急正秋天。", "遙憶巴陵渡，殘陽一望煙。"]'),
('26535eff-108e-4625-bb84-938efe54e109','鄭轂補闕山松','張蠙','唐','唐诗','tang','','[]','心將積雪欺，根與白雲離。',48,'全唐诗/poet.tang.39000.json','["心將積雪欺，根與白雲離。", "遠寄僧猶憶，高看鶴未知。", "影交新長葉，皴匝舊生枝。", "多少同時種，深山不得移。"]'),
('79b9e220-89e2-4de3-9457-8d6526e2386f','新竹','張蠙','唐','唐诗','tang','','[]','新鞭暗入庭，初長兩三莖。',48,'全唐诗/poet.tang.39000.json','["新鞭暗入庭，初長兩三莖。", "不是他山少，無如此地生。", "垂梢叢上出，柔葉籜間成。", "何用高唐峽，風枝埽月明。"]'),
('0fe0ed2a-1471-4cf6-a43a-d0ca5ecf6f2e','和友人送趙能卿東歸','張蠙','唐','唐诗','tang','','[]','一第時難得，歸期日已過。',48,'全唐诗/poet.tang.39000.json','["一第時難得，歸期日已過。", "相看玄鬢少，共憶白雲多。", "楚闊天垂草，吳空月上波。", "無人不有遇，之子獨狂歌。"]'),
('e43ae3ae-1cf5-4680-95fa-c9516256f0ef','送人歸南中','張蠙','唐','唐诗','tang','','[]','有家誰不別，經亂獨難尋。',48,'全唐诗/poet.tang.39000.json','["有家誰不別，經亂獨難尋。", "遠路波濤惡，窮荒雨霧深。", "燒驚山象出，雷觸海鼇沉。", "爲問南遷客，何人在瘴林。"]'),
('cdf51ded-5463-4147-b991-5c3918f3a09c','塞下曲','張蠙','唐','唐诗','tang','','[]','邊事多更變，天心亦爲憂。',48,'全唐诗/poet.tang.39000.json','["邊事多更變，天心亦爲憂。", "胡兵來作寇，漢將也封侯。", "夜燒衝星赤，寒塵翳日愁。", "無門展微畧，空上望西樓。"]'),
('a772e775-ae84-4512-98d2-cb3058761c38','邊將二首 一','張蠙','唐','唐诗','tang','','[]','歷戰燕然北，功高劒有威。',48,'全唐诗/poet.tang.39000.json','["歷戰燕然北，功高劒有威。", "聞名外國懼，輕命故人稀。", "角怨星芒動，塵愁日色微。", "從爲漢都護，未得脫征衣。"]'),
('0d9365bf-dd1c-4eb1-bf90-23ba3bf8c468','邊將二首 二','張蠙','唐','唐诗','tang','','[]','按劒立城樓，西看極海頭。',48,'全唐诗/poet.tang.39000.json','["按劒立城樓，西看極海頭。", "承家爲上將，開地得邊州。", "磧迥兵難伏，天寒馬易收。", "胡風一度獵，吹裂錦貂裘。"]'),
('09832539-f138-4c32-b7f4-76b9fca56b42','朔方書事','張蠙','唐','唐诗','tang','','[]','秋盡角聲苦，逢人唯荷戈。',48,'全唐诗/poet.tang.39000.json','["秋盡角聲苦，逢人唯荷戈。", "城池向隴少，岐路出關多。", "雁遠行垂地，烽高影入河。", "仍聞黑山寇，又覓漢家和。"]'),
('f10f8ddc-8d21-4976-b52c-b2e1ab31b942','經荒驛','張蠙','唐','唐诗','tang','','[]','古驛成幽境，雲蘿隔四隣。',48,'全唐诗/poet.tang.39000.json','["古驛成幽境，雲蘿隔四隣。", "夜燈移宿鳥，秋雨禁行人。", "廢巷荆叢合，荒庭虎迹新。", "昔年經此地，終日是紅塵。"]'),
('1e5a101e-7ad9-451b-be33-642b54b4af42','贈棲白大師','張蠙','唐','唐诗','tang','','[]','剃髮得時名，僧應別應星。',48,'全唐诗/poet.tang.39000.json','["剃髮得時名，僧應別應星。", "偶題皆有詔，閑論便成經。", "埽葉寒燒鼎，融冰曉注瓶。", "長因內齋出，多客叩禪扃。"]'),
('ae54e2a3-61fa-478a-92f9-7bc71ecdbb6a','贈聞一上人','張蠙','唐','唐诗','tang','','[]','見面雖年少，聞名似白頭。',48,'全唐诗/poet.tang.39000.json','["見面雖年少，聞名似白頭。", "玄談窮釋旨，清思掩詩流。", "果落痕生砌，松高影上樓。", "壇場在三殿，應召入焚修。"]'),
('ea1ac2f0-dec1-4698-9025-00b70a57f5cb','贈可倫上人','張蠙','唐','唐诗','tang','','[]','師教本於空，流來不自東。',48,'全唐诗/poet.tang.39000.json','["師教本於空，流來不自東。", "修從多劫後，行出衆人中。", "衲冷湖山雨，幡輕海甸風。", "遊吳累夏講，還與虎溪同。"]'),
('1f696bd7-3a60-415c-84e5-73df3619085b','寄法乾寺令諲太師','張蠙','唐','唐诗','tang','','[]','師居中禁寺，外請已無緣。',48,'全唐诗/poet.tang.39000.json','["師居中禁寺，外請已無緣。", "望幸唯修偈，承恩不亂禪。", "院多喧種藥，池有化生蓮。", "何日龍宮裏，相尋借法船。"]'),
('67b4f143-4d1c-4605-97c9-2a9ed4238d60','寄太白禪師','張蠙','唐','唐诗','tang','','[]','何年萬仞頂，獨有坐禪僧。',48,'全唐诗/poet.tang.39000.json','["何年萬仞頂，獨有坐禪僧。", "客上應無路，人傳或見燈。", "齋廚唯有橡，講石任生藤。", "遙想東林社，如師誰復能。"]'),
('ee0e65e5-92a0-43db-b646-cb4598128f5e','遇道者','張蠙','唐','唐诗','tang','','[]','數里白雲裏，身輕無履蹤。',48,'全唐诗/poet.tang.39000.json','["數里白雲裏，身輕無履蹤。", "故尋多不見，偶到即相逢。", "古井生雲水，高壇出異松。", "聊看杏花酌，便似換顏容。"]'),
('08295fd6-27a2-4eee-9f5f-aeecfbdf19db','贈道者','張蠙','唐','唐诗','tang','','[]','得道疑人識，都城獨閉關。',48,'全唐诗/poet.tang.39000.json','["得道疑人識，都城獨閉關。", "頭從白後黑，心向鬧中閑。", "飢渴唯調氣，兒孫亦駐顏。", "始知仙者隱，殊不在深山。"]'),
('6d3f0541-27ab-45ed-8205-fe52b9da752c','雨','張蠙','唐','唐诗','tang','','[]','半夜西亭雨，離人獨啓關。',48,'全唐诗/poet.tang.39000.json','["半夜西亭雨，離人獨啓關。", "桑麻荒舊國，雷電照前山。", "細滴高槐底，繁聲疊漏間。", "唯應孤鏡裏，明月長愁顏。"]'),
('61198f01-55a4-472d-b25c-87671bbb8aab','長安春望','張蠙','唐','唐诗','tang','','[]','明時不敢臥煙霞，又見秦城換物華。',64,'全唐诗/poet.tang.39000.json','["明時不敢臥煙霞，又見秦城換物華。", "殘雪未銷雙鳳闕，新春已發五侯家。", "甘貧祗擬長緘酒，忍病猶期強採花。", "故國別來桑柘盡，十年兵踐海西艖。"]'),
('3f9a704b-739f-4e6a-9824-451e53c74b6e','過黃牛峽','張蠙','唐','唐诗','tang','','[]','黃牛來勢瀉巴川，疊日孤舟逐峽前。',64,'全唐诗/poet.tang.39000.json','["黃牛來勢瀉巴川，疊日孤舟逐峽前。", "雷電夜驚猿落樹，波濤愁恐客離船。", "盤渦逆入嵌空地，斷壁高分繚繞天。", "多少人經過此去，一生魂夢怕潺湲。"]'),
('e096ee6b-9af7-4dd8-a201-7f91615f0c07','逢道者','張蠙','唐','唐诗','tang','','[]','縱意出山無遠近，還如孤鶴在空虛。',64,'全唐诗/poet.tang.39000.json','["縱意出山無遠近，還如孤鶴在空虛。", "昔年親種樹皆老，此世相逢人自疎。", "野葉細苞深洞藥，巖蘿閒束古仙書。", "秪尋隱跡歸何處，方說煙霞不定居。"]'),
('29ec173f-defa-4893-955e-cebf30541061','邊情','張蠙','唐','唐诗','tang','','[]','窮荒始得靜天驕，又說天兵擬渡遼。',64,'全唐诗/poet.tang.39000.json','["窮荒始得靜天驕，又說天兵擬渡遼。", "聖主尚嫌蕃界近，將軍莫恨漢庭遙。", "草枯朔野春難發，冰結河源夏半銷。", "惆悵臨戎皆効國，豈無人似霍嫖姚。"]'),
('b0d83adc-da70-443f-bfe0-1a0b2f8e86d8','贈李司徒','張蠙','唐','唐诗','tang','','[]','承家拓定隴關西，勳貴名應上將齊。',64,'全唐诗/poet.tang.39000.json','["承家拓定隴關西，勳貴名應上將齊。", "金庫夜開龍甲冷，玉堂秋閉鳳笙低。", "歡筵每恕嬌娥醉，閑櫪猶驚戰馬嘶。", "長怪魯儒頭枉白，不親弓劒覓丹梯。"]'),
('bc14c432-8a77-4491-9ac8-539bbdb766ca','送盧尚書赴靈武','張蠙','唐','唐诗','tang','','[]','西北正傳烽候急，靈州共喜信臣居。',64,'全唐诗/poet.tang.39000.json','["西北正傳烽候急，靈州共喜信臣居。", "從軍盡是清才去，屬郡無非大將除。", "新地進圖移漢界，古城遺碣見蕃書。", "山川不異江湖景，賓館常聞食有魚。"]'),
('bb77c11f-932d-485f-a2fa-1dd72b5e8603','投翰林張侍郎','張蠙','唐','唐诗','tang','','[]','舉家貧拾海邊樵，來認仙宗在碧霄。',64,'全唐诗/poet.tang.39000.json','["舉家貧拾海邊樵，來認仙宗在碧霄。", "丹穴雖無凡羽翼，靈椿還向細枝條。", "九衢馬識他門少，十載身辭故國遙。", "願與吾君作霖雨，且應平地活枯苗。"]'),
('2326d1b9-844e-48d8-91c4-f80d2647274b','投翰林蕭侍郎','張蠙','唐','唐诗','tang','','[]','九仞牆邊絕路岐，野才非合自求知。',64,'全唐诗/poet.tang.39000.json','["九仞牆邊絕路岐，野才非合自求知。", "靈湫豈要魚棲浪，仙桂那容鳥寄枝。", "纖草不銷春氣力，微塵還助岳形儀。", "從來爲學投文鏡，文鏡如今更有誰。"]'),
('41a67142-8cf8-4475-b5aa-b683de3e05c8','宴駙馬宅','張蠙','唐','唐诗','tang','','[]','牙香禁樂鎮相攜，日日君恩降紫泥。',64,'全唐诗/poet.tang.39000.json','["牙香禁樂鎮相攜，日日君恩降紫泥。", "紅藥院深人半醉，綠楊門掩馬頻嘶。", "座中古物多仙意，壁上新詩有御題。", "別向庭蕪寘吟石，不教宮妓踏成蹊。"]'),
('db0ba7e4-7848-4244-a940-50e015705458','邊將','張蠙','唐','唐诗','tang','','[]','上馬乘秋欲建勳，飛弧夜闕出師頻。',64,'全唐诗/poet.tang.39000.json','["上馬乘秋欲建勳，飛弧夜闕出師頻。", "若無紫塞煙塵事，誰識青樓歌舞人。", "戰骨沙中金鏃在，賀筵花畔玉蟬新。", "由來邊卒皆如此，只是君門合殺身。"]'),
('9b483f9b-d13f-495e-8577-cde296b8212a','贈水軍都將','張蠙','唐','唐诗','tang','','[]','平生爲有安邦術，便別秋曹最上階。',64,'全唐诗/poet.tang.39000.json','["平生爲有安邦術，便別秋曹最上階。", "戰艦却容儒客臥，公廳唯伴野僧齋。", "裁書榭迥冰膠筆，養藥堂深蘚惹鞋。", "直待門前見幢節，始應高愜聖君懷。"]'),
('16742e54-08cb-4c42-b3c1-c253524aeddc','贈九江太守','張蠙','唐','唐诗','tang','','[]','江頭蹔駐木蘭船，漁父來誇太守賢。',64,'全唐诗/poet.tang.39000.json','["江頭蹔駐木蘭船，漁父來誇太守賢。", "二邑旋添新戶口，四營漸廢舊戈鋋。", "笙歌不似經荒後，禮樂猶如未戰前。", "昨日西亭從游騎，信旗風裏說詩篇。"]'),
('155afb06-3a48-4437-a23b-37efc566e85c','贈信安太守','張蠙','唐','唐诗','tang','','[]','三衢正對福星時，喜得君侯玅撫綏。',64,'全唐诗/poet.tang.39000.json','["三衢正對福星時，喜得君侯玅撫綏。", "甲士散教耕壠畝，書生閑許從旌旗。", "條章最是貧家喜，禾黍仍防別郡饑。", "昨日中官說天意，即飛丹詔立新碑。"]'),
('658881a7-cd11-406e-91b2-d9e5bd6ca2bd','贈江都鄭明府','張蠙','唐','唐诗','tang','','[]','他人豈是稱才術，才術須觀力有餘。',64,'全唐诗/poet.tang.39000.json','["他人豈是稱才術，才術須觀力有餘。", "兵亂幾年臨劇邑，公清終日似閑居。", "牀頭怪石神仙畫，篋裏華牋將相書。", "更欲棲蹤近彭澤，香爐峰下結茅廬。"]'),
('07f414e9-6bca-470d-9658-564e72bf8d9d','贈南昌宰','張蠙','唐','唐诗','tang','','[]','假邑邀真邑命分，明庭元有至公存。',64,'全唐诗/poet.tang.39000.json','["假邑邀真邑命分，明庭元有至公存。", "每鋤奸弊同荆棘，唯撫孤惸似子孫。", "折獄不曾偏下筆，靈襟長是大開門。", "新銜便合兼朱紱，應待蒼生更舉論。"]'),
('950afc8e-1e50-4ec8-bea2-819479831333','贈丘衙推','張蠙','唐','唐诗','tang','','[]','仙都高處掩柴扉，人世聞名見者稀。',64,'全唐诗/poet.tang.39000.json','["仙都高處掩柴扉，人世聞名見者稀。", "詩逸不拘凡對屬，易窮皆達聖玄微。", "偶攜童穉離青嶂，便被君侯換白衣。", "任醉賓筵莫深隱，綺羅絲竹勝漁磯。"]'),
('965d4a76-a2cb-49c4-952c-eff0ba7485b2','獻所知','張蠙','唐','唐诗','tang','','[]','跡熟荀家見弟兄，九霄同與指前程。',64,'全唐诗/poet.tang.39000.json','["跡熟荀家見弟兄，九霄同與指前程。", "吹噓漸覺馨香出，夢寐長疑羽翼生。", "住僻驊騮皆識路，來頻鸚鵡亦知名。", "登龍不敢懷他願，祗望爲霖致太平。"]'),
('91f6db43-fde4-4eb9-bae9-9be001d86d84','投所知','張蠙','唐','唐诗','tang','','[]','十五年看帝里春，一枝頭白未酬身。',64,'全唐诗/poet.tang.39000.json','["十五年看帝里春，一枝頭白未酬身。", "自聞離亂開公道，漸數孤平少屈人。", "劣馬再尋商嶺路，扁舟重寄越溪濱。", "省郎門似龍門峻，應借風雷變涸鱗。"]'),
('6ac38a01-c45f-4989-8976-c5dd7ef60de3','南康夜宴東溪留別郡守陸郎中','張蠙','唐','唐诗','tang','','[]','飄然野客才無取，多謝君侯獨見知。',64,'全唐诗/poet.tang.39000.json','["飄然野客才無取，多謝君侯獨見知。", "竹葉樽前教駐樂，桃花紙上待君詩。", "香迷蛺蝶投紅燭，舞拂蒹葭倚翠帷。", "明發別愁何處去，片帆天際酒醒時。"]'),
('386a6b1b-f93c-46ed-81ef-d807f9fbf7d1','言懷','張蠙','唐','唐诗','tang','','[]','十載聲沈覺自非，賤身元合衣荷衣。',64,'全唐诗/poet.tang.39000.json','["十載聲沈覺自非，賤身元合衣荷衣。", "豈能得路陪先達，却擬還家望少微。", "戰馬到秋長淚落，傷禽無夜不魂飛。", "平生祗學穿楊箭，更向何門是見機。"]'),
('247ae2dd-b95d-4e2b-8d0a-a534186dbd82','喜友人日南迴','張蠙','唐','唐诗','tang','','[]','南遊曾去海南涯，此去遊人不易歸。',66,'全唐诗/poet.tang.39000.json','["南遊曾去海南涯，此去遊人不易歸。", "白日霧昏張夜燭，窮冬氣暖著春衣。", "溪荒毒鳥隨船啅，洞黑冤蛇出樹飛。", "重入帝城何[寂]寞，共迴遷客半輕肥。"]'),
('ac55935d-b1b5-4324-81d9-3a633ca7ab77','下第述懷','張蠙','唐','唐诗','tang','','[]','十載長安跡未安，杏花還是看人看。',64,'全唐诗/poet.tang.39000.json','["十載長安跡未安，杏花還是看人看。", "名從近事方知險，詩到窮玄更覺難。", "世薄不慚雲路晚，家貧唯怯草堂寒。", "如何直道爲身累，坐月眠霜思枉乾。"]'),
('cb277d01-8ce2-4141-bbf9-a1a3fc7b2ac3','華陽道者','張蠙','唐','唐诗','tang','','[]','華陽洞裏持真經，心嫌來客風塵腥。',64,'全唐诗/poet.tang.39000.json','["華陽洞裏持真經，心嫌來客風塵腥。", "惟餐白石過白日，擬騎青竹上青冥。", "翔螭豈作漢武駕，神娥徒降燕昭庭。", "長生不必論貴賤，却是幽人骨主靈。"]'),
('81da578d-ba4c-4c25-8b44-9596d6251225','夏日題老將林亭','張蠙','唐','唐诗','tang','','[]','百戰功成翻愛靜，侯門漸欲似仙家。',64,'全唐诗/poet.tang.39000.json','["百戰功成翻愛靜，侯門漸欲似仙家。", "牆頭雨細垂纖草，水面風回聚落花。", "井放轆轤閑侵酒，籠開鸚鵡報煎茶。", "幾人圖在凌煙閣，曾不交鋒向塞沙。"]'),
('26e9864d-194e-4ade-b786-143ca0333196','觀江南牡丹','張蠙','唐','唐诗','tang','','[]','北地花開南地風，寄根還與客心同。',64,'全唐诗/poet.tang.39000.json','["北地花開南地風，寄根還與客心同。", "羣芳盡怯千般態，幾醉能消一番紅。", "舉世秪將華勝實，真禪元喻色爲空。", "近年明主思王道，不許新栽滿六宮。"]'),
('ecbb8d15-0107-47f4-809d-595543887ab7','錢塘夜宴留別郡守','張蠙','唐','唐诗','tang','','[]','四方騷動一州安，夜列罇罍伴客懽。',64,'全唐诗/poet.tang.39000.json','["四方騷動一州安，夜列罇罍伴客懽。", "觱栗調高山閣迥，蝦蟆更促海聲寒。", "屏間佩響藏歌妓，幕外刀光立從官。", "沈醉不愁歸棹遠，晚風吹上子陵灘。"]'),
('ffe9fccb-9372-4058-9706-f3702a446a58','送薛郎中赴江州','張蠙','唐','唐诗','tang','','[]','幾州聞出刺，謠美有江民。',96,'全唐诗/poet.tang.39000.json','["幾州聞出刺，謠美有江民。", "正面傳天旨，懸心禱岳神。", "尺書先假路，紅斾旋燒塵。", "郡顯山川別，衙開將吏新。", "散招僧坐暑，閑載客行春。", "聽事棊忘着，探題酒亂巡。", "好編高隱傳，多貌上昇真。", "近日居清近，求人在此人。"]'),
('f551f55f-cdb7-46d3-b7da-bf7468a2931e','送南海僧遊蜀','張蠙','唐','唐诗','tang','','[]','真修絕故鄉，一衲度暄涼。',72,'全唐诗/poet.tang.39000.json','["真修絕故鄉，一衲度暄涼。", "此世能先覺，他生豈再忘。", "定中船過海，臘後路沿湘。", "野迥鴉隨笠，山深虎背囊。", "瀑流垂石室，蘿蔓蓋銅梁。", "却後何年會，西方有上房。"]'),
('1f9407c4-0856-4cc6-81c6-07f7cf6ebc36','和友人許裳題宣平里古藤','張蠙','唐','唐诗','tang','','[]','欲結千年茂，生來便近松。',120,'全唐诗/poet.tang.39000.json','["欲結千年茂，生來便近松。", "迸根通井潤，交葉覆庭穠。", "歷代頻更主，盤空漸變龍。", "晝風圓影亂，宵雨細聲重。", "蓋密勝丹桂，層危類遠峰。", "嫩條懸野鼠，枯節呌秋蛩。", "翠老霜難蝕，皴多蘚乍封。", "幾家遙共翫，何寺不堪容。", "客對忘離榻，僧看誤過鐘。", "頃因陪預作，終夕遶枝筇。"]'),
('12dfba16-5098-40a1-a6cb-2be66dedcaad','十五夜與友人對月','張蠙','唐','唐诗','tang','','[]','每到月圓思共醉，不宜同醉不成歡。',32,'全唐诗/poet.tang.39000.json','["每到月圓思共醉，不宜同醉不成歡。", "一千二百如輪夜，浮世誰能得盡看。"]'),
('b5d78dab-3433-4e10-ba3c-cfb5ef0017d3','青塚','張蠙','唐','唐诗','tang','','[]','傾國可能勝效國，無勞冥寞更思回。',32,'全唐诗/poet.tang.39000.json','["傾國可能勝效國，無勞冥寞更思回。", "太真雖是承恩死，祗作飛塵向馬嵬。"]'),
('2d2f6226-7718-4bd7-9561-88b8b536e8b5','古戰場','張蠙','唐','唐诗','tang','','[]','荒骨潛銷壘已平，漢家曾說此交兵。',32,'全唐诗/poet.tang.39000.json','["荒骨潛銷壘已平，漢家曾說此交兵。", "如何萬古冤魂在，風雨時聞有戰聲。"]'),
('254a21cf-e0b1-4759-8d83-7e9c0fdda393','贈段逸人','張蠙','唐','唐诗','tang','','[]','長筇自擔藥兼琴，話著名山即擬尋。',32,'全唐诗/poet.tang.39000.json','["長筇自擔藥兼琴，話著名山即擬尋。", "從聽世人權似火，不能燒得臥雲心。"]'),
('7215e05d-8d74-43b1-9d8b-c2c504f03193','贈鄭司業','張蠙','唐','唐诗','tang','','[]','晚學更求來世達，正懷非與百邪侵。',32,'全唐诗/poet.tang.39000.json','["晚學更求來世達，正懷非與百邪侵。", "古人名在今人口，不合于名不苦心。"]'),
('f552ab51-e7c1-44b5-90aa-855511ee4b82','上所知','張蠙','唐','唐诗','tang','','[]','初向衆中留姓氏，敢期言下致時名。',32,'全唐诗/poet.tang.39000.json','["初向衆中留姓氏，敢期言下致時名。", "而今馬亦知人意，每到門前不肯行。"]'),
('ac74fda7-e3ce-4efb-aeae-564a7f0bc2ba','別鄭仁表','張蠙','唐','唐诗','tang','','[]','春雷醉別鏡湖邊，官顯才狂正少年。',32,'全唐诗/poet.tang.39000.json','["春雷醉別鏡湖邊，官顯才狂正少年。", "紅燭滿汀歌舞散，美人迎上木蘭船。"]'),
('7b9faa76-5aa3-4005-bb25-c7407b50da55','言懷','張蠙','唐','唐诗','tang','','[]','不將高蓋竟煙塵，自向蓬茅認此身。',32,'全唐诗/poet.tang.39000.json','["不將高蓋竟煙塵，自向蓬茅認此身。", "唐祖本來成大業，豈非姚宋是平人。"]'),
('fae65d7c-8e6f-4ef5-8d0d-58c5ada651e4','敘懷','張蠙','唐','唐诗','tang','','[]','月裏路從何處上，江邊身合幾時歸。',32,'全唐诗/poet.tang.39000.json','["月裏路從何處上，江邊身合幾時歸。", "十年九陌寒風夜，夢掃蘆花絮客衣。"]'),
('da9e9165-dfbe-402a-8180-8c2792a901a0','抒懷','張蠙','唐','唐诗','tang','','[]','幾出東堂謝不才，便甘閒望故山迴。',32,'全唐诗/poet.tang.39000.json','["幾出東堂謝不才，便甘閒望故山迴。", "翻思未是離家久，更有人從外國來。"]'),
('f9093373-aa79-433c-976d-9a71da487bb5','自諷','張蠙','唐','唐诗','tang','','[]','鹿鳴筵上強稱賢，一送離家十四年。',32,'全唐诗/poet.tang.39000.json','["鹿鳴筵上強稱賢，一送離家十四年。", "同隱海山燒藥伴，不求丹桂却登仙。"]'),
('c9fd38fa-0e95-453a-9245-09ccdb6da64a','傷賈島','張蠙','唐','唐诗','tang','','["\u957f\u6c5f"]','生爲明代苦吟身，死作長江一逐臣。',32,'全唐诗/poet.tang.39000.json','["生爲明代苦吟身，死作長江一逐臣。", "可是當時少知己，不知知己是何人。"]'),
('fd488dd2-8d1a-4a36-9d3e-be14dcbbc5d6','再游西山贈許尊師','張蠙','唐','唐诗','tang','','[]','別後已聞師得道，不期猶在此山頭。',32,'全唐诗/poet.tang.39000.json','["別後已聞師得道，不期猶在此山頭。", "昔時霜鬢今如漆，疑是年光却倒流。"]'),
('c53aee5f-e65c-45f4-90d1-de9e1c850fd0','宮詞','張蠙','唐','唐诗','tang','','[]','日透珠簾見冕旒，六宮爭逐百花毬。',32,'全唐诗/poet.tang.39000.json','["日透珠簾見冕旒，六宮爭逐百花毬。", "迴看不覺君王去，已聽笙歌在遠樓。"]'),
('f184c1da-bc1b-4756-b7c8-e0137889d24a','經范蠡舊居','張蠙','唐','唐诗','tang','','[]','一變姓名離百越，越城猶在范家無。',32,'全唐诗/poet.tang.39000.json','["一變姓名離百越，越城猶在范家無。", "他人不見扁舟意，却笑輕生泛五湖。"]'),
('49088c37-d122-44cc-9d39-aded27724de8','題嘉陵驛','張蠙','唐','唐诗','tang','','[]','嘉陵路惡石和泥，行到長亭日已西。',32,'全唐诗/poet.tang.39000.json','["嘉陵路惡石和泥，行到長亭日已西。", "獨倚闌干正惆悵，海棠花裏鷓鴣啼。"]'),
('2e2222a7-b3b1-4312-ac5a-8bb7697cd03e','龜山寺晚望','張蠙','唐','唐诗','tang','','[]','四面湖光絕路岐，鸊鵜飛起暮鐘時。',32,'全唐诗/poet.tang.39000.json','["四面湖光絕路岐，鸊鵜飛起暮鐘時。", "漁舟不用懸帆席，歸去乘風插柳枝。"]'),
('898fffa1-deca-41a7-8f0e-a778b361cb02','華山孤松','張蠙','唐','唐诗','tang','','[]','石罅引根非土力，冒寒猶助岳蓮光。',32,'全唐诗/poet.tang.39000.json','["石罅引根非土力，冒寒猶助岳蓮光。", "綠槐生在膏腴地，何得無心拒雪霜。"]'),
('65b3a9cb-f331-44ed-a241-b0268135467c','弔萬人塚','張蠙','唐','唐诗','tang','','["\u6218\u4e89", "\u5199\u666f", "\u540c\u60c5"]','兵罷淮邊客路通，亂鴉來去噪寒空。',32,'全唐诗/poet.tang.39000.json','["兵罷淮邊客路通，亂鴉來去噪寒空。", "可憐白骨攢孤塚，盡爲將軍覓戰功。"]'),
('db3eade6-af37-4ce5-95d3-c54e16b77287','送友尉蜀中','張蠙','唐','唐诗','tang','','[]','故友漢中尉，請爲西蜀吟。',48,'全唐诗/poet.tang.39000.json','["故友漢中尉，請爲西蜀吟。", "人家多種橘，風土愛彈琴。", "水向昆明闊，山通大夏深。", "理閑無別事，時寄一登臨。"]'),
('1cf5cb88-3fc2-4a9a-a294-908e15c6d893','長安寓懷','張蠙','唐','唐诗','tang','','[]','九衢秋雨掩閑扉，不似干名似息機。',32,'全唐诗/poet.tang.39000.json','["九衢秋雨掩閑扉，不似干名似息機。", "貧病却慙牆上土，年來猶自換新衣。"]'),
('964eb1ff-4222-44e4-a9fa-97deebcc4463','費徵君舊居','張蠙','唐','唐诗','tang','','[]','浮世拋身外，棲蹤入九華。',48,'全唐诗/poet.tang.39000.json','["浮世拋身外，棲蹤入九華。", "遺篇補樂府，舊籍隸仙家。", "池靜龜昇樹，庭荒鶴隱花。", "古來天子命，還少到煙霞。"]'),
('d1ab7c0f-9874-4ff9-a228-119ee27af0e1','晨興','翁承贊','唐','唐诗','tang','','[]','晨起竹軒外，逍遙清興多。',48,'全唐诗/poet.tang.39000.json','["晨起竹軒外，逍遙清興多。", "早涼生戶牖，孤月照關河。", "旅食甘藜藿，歸心憶薜蘿。", "一尊如有地，放意且狂歌。"]'),
('46b4ff28-2a7b-4614-a7fb-0a9272402673','題莒潭安閩院','翁承贊','唐','唐诗','tang','','[]','祧宗營祀舍，幽異勝珠林。',48,'全唐诗/poet.tang.39000.json','["祧宗營祀舍，幽異勝珠林。", "名士穿雲訪，飛禽傍竹吟。", "牕含孤岫影，牧臥斷霞陰。", "景福滋閩壤，芳名亙古今。"]'),
('7748cb83-de94-4490-89e8-acf7f63891d6','華下霽後曉眺','翁承贊','唐','唐诗','tang','','[]','結茅幽寂近禪林，霽景煙光著柳陰。',64,'全唐诗/poet.tang.39000.json','["結茅幽寂近禪林，霽景煙光著柳陰。", "千嶂華山雲外秀，萬重鄉思望中深。", "老嫌白髮還偷鑷，貧對春風亦強吟。", "花畔水邊人不會，騰騰閑步一披襟。"]'),
('25e33a42-1282-46a9-86c2-452529c39459','喜弟承檢登科','翁承贊','唐','唐诗','tang','','[]','兩篇佳句敵瓊瑰，憐我三清道路開。',64,'全唐诗/poet.tang.39000.json','["兩篇佳句敵瓊瑰，憐我三清道路開。", "荆璞獻多還得售，桂堂恩在敢輕回。", "花繁不怕尋香客，榜到應傾賀喜杯。", "知爾苦心功業就，早攜長策出山來。"]'),
('a5e77a36-baf1-4a20-b89d-b7d795a2bf84','蒙閩王改賜鄉里','翁承贊','唐','唐诗','tang','','[]','鄉名文秀里光賢，別向鈞台造化權。',64,'全唐诗/poet.tang.39000.json','["鄉名文秀里光賢，別向鈞台造化權。", "閥閱便因今日貴，德音兼與後人傳。", "自從受賜身無力，向未酬恩骨肯鐫。", "歸闕路遙心更切，不嫌扶病倚旌旃。"]'),
('81cd84c7-3a4c-47fb-bdff-9036aca26854','訪建陽馬驛僧亞齊','翁承贊','唐','唐诗','tang','','[]','蕭蕭風雨建陽溪，溪畔維舟訪亞齊。',64,'全唐诗/poet.tang.39000.json','["蕭蕭風雨建陽溪，溪畔維舟訪亞齊。", "一軸新詩劒潭北，十年舊識華山西。", "吟魂惜向江村老，空性元知世路迷。", "應笑乘軺青瑣客，此時無暇聽猿啼。"]'),
('89f07435-de68-4a0b-8287-f412c3461d8a','題景祥院','翁承贊','唐','唐诗','tang','','[]','一溪拖碧遶崔嵬，瓶鉢偏宜向此隈。',64,'全唐诗/poet.tang.39000.json','["一溪拖碧遶崔嵬，瓶鉢偏宜向此隈。", "農罷樹陰黃犢臥，齋時山下白衣來。", "松多往日門人種，路是前朝釋子開。", "三卷貝多金粟語，可能心煉得成灰。"]'),
('4b8f9399-a622-464a-9e45-251df29d9c70','寄舍弟承裕員外','翁承贊','唐','唐诗','tang','','["\u957f\u6c5f"]','江花岸草晚萋萋，公子王孫思合迷。',64,'全唐诗/poet.tang.39000.json','["江花岸草晚萋萋，公子王孫思合迷。", "無主園林饒採伐，忘情鷗鳥恣高低。", "長江月上魚翻鬣，荒圃人稀獺印蹄。", "何事斜陽再回首，休愁離別峴山西。"]'),
('df228056-e03c-4fe3-bf53-21ca012797fd','文明殿受冊封閩王','翁承贊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','龍墀班聽漏聲長，竹帛昭勳撲御香。',64,'全唐诗/poet.tang.39000.json','["龍墀班聽漏聲長，竹帛昭勳撲御香。", "鳴佩洞庭辭帝主，登車故里冊閩王。", "一千年改江山瑞，十萬軍蒙雨露光。", "吟寄短篇追往事，留文功業不尋常。"]'),
('c339aada-2847-40ff-af64-38dd9418c6b0','御命歸鄉蒙賜錦衣','翁承贊','唐','唐诗','tang','','[]','九重宣旨下丹墀，面對天顏賜錦衣。',64,'全唐诗/poet.tang.39000.json','["九重宣旨下丹墀，面對天顏賜錦衣。", "中使擎來三殿曉，寶箱開處五雲飛。", "德音耳聆君恩重，金印腰懸已力微。", "更待臨軒陳鼓吹，星軺便指故鄉歸。"]'),
('14342e9b-d554-4933-bed0-bcfb5b3ffcf8','奉使封閩王歸京洛','翁承贊','唐','唐诗','tang','','[]','泥緘紫誥御恩光，信馬嘶風出洛陽。',64,'全唐诗/poet.tang.39000.json','["泥緘紫誥御恩光，信馬嘶風出洛陽。", "此去願言歸梓里，預憑魂夢展維桑。", "客程回首瞻文陛，驛路乘軺憶故鄉。", "指日還家堪自重，恩榮晝錦賀封王。"]'),
('35cb5b3d-110c-4646-99fd-391758d87d3a','奉使封王次宜春驛','翁承贊','唐','唐诗','tang','','[]','微宦淹留鬢已斑，此心長憶舊林泉。',64,'全唐诗/poet.tang.39000.json','["微宦淹留鬢已斑，此心長憶舊林泉。", "不因列土封千乘，爭得銜恩拜二天。", "雲斷自宜鄉樹出，月高猶伴客心懸。", "夜來夢到南臺上，徧看江山勝往年。"]'),
('f9e367e1-d74f-4f72-8a53-35a3054b1509','甲子歲銜命到家至榕城冊封次日閩王降旌旗於新豐市堤餞別','翁承贊','唐','唐诗','tang','','[]','登庸樓上方停樂，新市堤邊又舉杯。',64,'全唐诗/poet.tang.39000.json','["登庸樓上方停樂，新市堤邊又舉杯。", "正是離情傷遠別，忽聞台旨許重來。", "此時暫與交親好，今日還將簡冊回。", "爭得長房猶在世，縮教地近釣魚臺。"]'),
('ce166e0a-2419-4868-a743-e5c9da3f1f3e','寄示兒孫','翁承贊','唐','唐诗','tang','','[]','力學燒丹二十年，辛勤方得遇真仙。',64,'全唐诗/poet.tang.39000.json','["力學燒丹二十年，辛勤方得遇真仙。", "便隨羽客歸三島，旋聽霓裳適九天。", "得路自能酬造化，立身何必戀林泉。", "予家藥鼎分明在，好把仙方次第傳。"]'),
('a4d5c8a6-9304-4c3b-b737-f2b439d07b1b','天祐元年以右拾遺使冊閩王而作','翁承贊','唐','唐诗','tang','','[]','蓬萊宮闕曉光勻，紅案舁麻降紫宸。',64,'全唐诗/poet.tang.39000.json','["蓬萊宮闕曉光勻，紅案舁麻降紫宸。", "鸞奏八音諧律呂，鳳銜五色顯絲綸。", "蕭何相印鈞衡重，韓信齋壇雨露新。", "得侍丹墀官異寵，此身何幸沐恩頻。"]'),
('b868c3b2-605a-4bd5-93ee-e6476795e05a','漢上登舟憶閩','翁承贊','唐','唐诗','tang','','[]','漢臯亭畔起西風，半挂征帆立向東。',64,'全唐诗/poet.tang.39000.json','["漢臯亭畔起西風，半挂征帆立向東。", "久客自憐歸路近，筭程不怕酒觴空。", "參差雁陣天初碧，零落漁家蓼欲紅。", "一片歸心隨去櫂，願言指日拜文翁。"]'),
('4088b9dc-6391-463f-a3d6-957d23315974','對雨述懷示弟承檢','翁承贊','唐','唐诗','tang','','[]','淋淋霎霎結秋霖，欲使秦城歎陸沈。',64,'全唐诗/poet.tang.39000.json','["淋淋霎霎結秋霖，欲使秦城歎陸沈。", "曉勢遮回朝客馬，夜聲滴破旅人心。", "青苔重疊封顏巷，白髮蕭疎引越吟。", "不有惠連同此景，江南歸思幾般深。"]'),
('d3f44556-98a6-420e-a217-65276ff3ae60','題壺山','翁承贊','唐','唐诗','tang','','[]','井邑斜連北，蓬瀛直倚東。',24,'全唐诗/poet.tang.39000.json','["井邑斜連北，蓬瀛直倚東。", "秋高巖溜白，日上海波紅。"]'),
('2dc476f3-51a8-4f31-a740-46e33cc8ac90','題故居','翁承贊','唐','唐诗','tang','','[]','一爲鵝子二連花，三望青湖四石斜。',32,'全唐诗/poet.tang.39000.json','["一爲鵝子二連花，三望青湖四石斜。", "惟有嶺湖居第五，山前却是宰臣家。"]'),
('fe88847b-c015-4d15-a5e0-45176b085c7e','題槐','翁承贊','唐','唐诗','tang','','[]','雨中妝點望中黃，句引蟬聲送夕陽。',32,'全唐诗/poet.tang.39000.json','["雨中妝點望中黃，句引蟬聲送夕陽。", "憶昔當年隨計吏，馬蹄終日爲君忙。"]'),
('61172123-ca47-40ae-9d97-184b2c4b94c3','擢進士','翁承贊','唐','唐诗','tang','','[]','霓旌引上大羅天，別領新銜意自憐。',32,'全唐诗/poet.tang.39000.json','["霓旌引上大羅天，別領新銜意自憐。", "蝴蝶流鶯莫先去，滿城春色屬羣仙。"]'),
('05795c6a-9bbc-4d79-99d7-78ce34226791','擢探花使三首 一','翁承贊','唐','唐诗','tang','','[]','洪崖差遣探花來，檢點芳叢飲數杯。',32,'全唐诗/poet.tang.39000.json','["洪崖差遣探花來，檢點芳叢飲數杯。", "深紫濃香三百朵，明朝爲我一時開。"]'),
('ce4914a9-0b49-4ac4-8c7f-fa906a8b46a3','擢探花使三首 二','翁承贊','唐','唐诗','tang','','[]','九重煙暖折槐芽，自是升平好物華。',32,'全唐诗/poet.tang.39000.json','["九重煙暖折槐芽，自是升平好物華。", "今日始知春氣味，長安虛過四年花。"]'),
('5dd8336f-2d6c-4220-9d8d-33d26897752c','擢探花使三首 三','翁承贊','唐','唐诗','tang','','[]','探花時節日偏長，恬淡春風稱意忙。',32,'全唐诗/poet.tang.39000.json','["探花時節日偏長，恬淡春風稱意忙。", "每到黃昏醉歸去，紵衣惹得牡丹香。"]'),
('f56d6b74-fa43-449a-9f29-e0e5648f89b6','書齋謾興二首 一','翁承贊','唐','唐诗','tang','','[]','池塘四五尺深水，籬落兩三般樣花。',32,'全唐诗/poet.tang.39000.json','["池塘四五尺深水，籬落兩三般樣花。", "過客不須頻問姓，讀書聲裏是吾家。"]'),
('f5e242ee-05ee-4f01-b00c-4cf105c78db5','書齋謾興二首 二','翁承贊','唐','唐诗','tang','','[]','官事歸來衣雪埋，兒童燈火小茅齋。',32,'全唐诗/poet.tang.39000.json','["官事歸來衣雪埋，兒童燈火小茅齋。", "人家不必論貧富，惟有讀書聲最佳。"]'),
('26b38ced-e3c8-4d1a-8f19-bacb51f59ceb','辭閩王歸朝寄倪先輩','翁承贊','唐','唐诗','tang','','[]','時人莫訝再還鄉，簡冊分明劒佩光。',32,'全唐诗/poet.tang.39000.json','["時人莫訝再還鄉，簡冊分明劒佩光。", "駟馬高車太常樂，登庸門下憶賢良。"]'),
('807011ad-2028-4340-9246-8663810e249e','曉望','翁承贊','唐','唐诗','tang','','[]','清霜散漫似輕嵐，玉闕參差萬象涵。',32,'全唐诗/poet.tang.39000.json','["清霜散漫似輕嵐，玉闕參差萬象涵。", "獨上秦臺最高處，舊山依約在東南。"]'),
('2764e79a-2c59-4970-b5aa-a7a08b282657','萬壽寺牡丹','翁承贊','唐','唐诗','tang','','[]','爛熳香風引貴遊，高僧移步亦遲留。',32,'全唐诗/poet.tang.39000.json','["爛熳香風引貴遊，高僧移步亦遲留。", "可憐殿角長松色，不得王孫一舉頭。"]'),
('05dfab6f-2a9e-46b0-9dc4-4c6ccc5ff1e3','松','翁承贊','唐','唐诗','tang','','[]','倚澗臨溪自屈蟠，雪花銷盡蘚花乾。',32,'全唐诗/poet.tang.39000.json','["倚澗臨溪自屈蟠，雪花銷盡蘚花乾。", "幽枝好折爲談柄，入手方知有歲寒。"]'),
('d7c539fb-cab8-4676-b7f7-d0fa73eb3b4b','柳 一','翁承贊','唐','唐诗','tang','','[]','斜拂中橋遠映樓，翠光駘蕩曉煙收。',32,'全唐诗/poet.tang.39000.json','["斜拂中橋遠映樓，翠光駘蕩曉煙收。", "洛陽才子多情思，橫把金鞭約馬頭。"]'),
('ad975330-d999-4367-89dd-4a9bd459ee66','柳 二','翁承贊','唐','唐诗','tang','','[]','高出營門遠出墻，朱闌門閉綠成行。',32,'全唐诗/poet.tang.39000.json','["高出營門遠出墻，朱闌門閉綠成行。", "將軍宴罷東風急，閑襯旌旗簇畫堂。"]'),
('636c7781-73e8-476e-a8f6-d1038653340e','柳 三','翁承贊','唐','唐诗','tang','','[]','彭澤先生酒滿船，五株栽向九江邊。',32,'全唐诗/poet.tang.39000.json','["彭澤先生酒滿船，五株栽向九江邊。", "長條細葉無窮盡，管領春風不計年。"]'),
('7164d9aa-b510-4258-ae4e-e44ee5de9328','柳 四','翁承贊','唐','唐诗','tang','','[]','煬帝東遊意緒多，宮娃眉翠兩相和。',32,'全唐诗/poet.tang.39000.json','["煬帝東遊意緒多，宮娃眉翠兩相和。", "一聲水調春風暮，千里交陰鎖汴河。"]');
